export function localizedAgentGuidesPartC(en: Guides): Partial<Record<LandingLocaleCode, Guides>> {
  return {
    'it': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code per il design — Open Design",
        description: "Come i designer usano Claude Code per il design di UI e web, e come Open Design lo trasforma in un vero agente di design — local-first, BYOK, con una libreria curata di skill e design system.",
        breadcrumb: "Claude Code",
        label: "Agente · Claude Code",
        heading: "Claude Code per il design.",
        lead: "Claude Code è l'agente di coding da terminale di Anthropic. Le persone lo usano già per costruire UI, design system e landing page. Open Design lo collega a un vero flusso di lavoro di design — porta la tua chiave Anthropic o il tuo abbonamento Claude, mantieni ogni file in locale.",
        rich: {"heroCtaLead": "Open Design trasforma Claude Code in un agente di design open-source e local-first — la tua chiave Anthropic o il tuo abbonamento Claude, i tuoi file, una libreria curata di skill e design system tutt'intorno.", "heroCtaActions": [{"label": "Usa Claude Code dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code è ampiamente considerato l'agente di coding con il miglior gusto per il frontend — ragiona sulle interfacce con una specificità insolita, indicando valori hex esatti, spaziature e scale tipografiche, e rifattorizza la UI in un'intera grande codebase senza perdere il filo. Ma, di base, tende comunque a derivare verso un look generico a meno che non gli si forniscano un design system, delle skill e dei riferimenti reali. Questa è una guida pratica ed end-to-end all'uso di Claude Code per UI, frontend e design system, e a come integrarlo in un flusso di lavoro strutturato con Open Design.", "Copre cos'è realmente Claude Code, perché è forte nel frontend, come configurarlo da zero, il flusso di lavoro con CLAUDE.md e le Skill, il round-trip ufficiale con Figma, come si confronta con Codex e Cursor, le insidie che fanno apparire generico l'output dell'IA e come Open Design colma il divario come layer di design aperto e local-first."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Il ciclo di feedback del design con Claude Code: l'agente da terminale che prende decisioni di design specifiche, un browser che renderizza la UI e uno spazio di lavoro, con una freccia di feedback che ritorna", "caption": "Il ciclo centrale: Claude Code ragiona su decisioni di UI specifiche nel terminale, le renderizza e le verifica in un browser reale e converge rispetto ai tuoi riferimenti."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-claude-code", "label": "Cos'è realmente Claude Code"}, {"id": "why-design", "label": "Perché Claude Code è bravo nel design"}, {"id": "setup", "label": "Configurare Claude Code per il design (da zero)"}, {"id": "skills-workflow", "label": "Il flusso di lavoro con CLAUDE.md e le Skill"}, {"id": "figma", "label": "Round-trip Claude Code + Figma"}, {"id": "vs", "label": "Claude Code vs Codex vs Cursor"}, {"id": "pitfalls", "label": "Insidie e l'estetica da \"sbobba dell'IA\""}, {"id": "open-design", "label": "Progettare con Claude Code in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-claude-code", "heading": "Cos'è realmente Claude Code", "blocks": [{"kind": "p", "text": "Claude Code è lo strumento di coding agentico di Anthropic. Legge la tua codebase, modifica file, esegue comandi e si integra con i tuoi strumenti di sviluppo — pianificando, scrivendo e verificando il lavoro a partire da compiti in linguaggio naturale, anziché limitarsi a completare righe in autocompletamento."}, {"kind": "p", "text": "È disponibile su diverse superfici che condividono tutte lo stesso motore: una CLI da terminale, estensioni IDE per VS Code, Cursor e JetBrains, un'app desktop con revisione visiva delle diff e un'esperienza web per i task a lunga esecuzione. I tuoi file CLAUDE.md, le impostazioni e i server MCP ti seguono su tutte."}, {"kind": "steps", "items": [{"label": "File di istruzioni", "body": "Claude Code legge un file CLAUDE.md nella root del progetto all'inizio di ogni sessione — il posto naturale dove codificare le tue convenzioni di design, i tokens e le checklist di revisione."}, {"label": "Skill", "body": "Le Agent Skill impacchettano istruzioni, script e risorse riutilizzabili che Claude carica su richiesta, inclusa la skill ufficiale Frontend Design di Anthropic per il gusto estetico."}, {"label": "Pianificazione e subagenti", "body": "Può pianificare prima di agire e generare subagenti che lavorano in parallelo su parti diverse di un task, il che mantiene coerenti i grandi refactoring di UI."}]}, {"kind": "ul", "items": ["Fornitore: Anthropic", "Credenziale: chiave API Anthropic (BYOK, tramite la Console) o un abbonamento Claude (Pro / Max)", "Superfici: CLI da terminale, estensioni VS Code / Cursor / JetBrains, app desktop, web"]}]}, {"id": "why-design", "heading": "Perché Claude Code è bravo nel design", "blocks": [{"kind": "p", "text": "Tra gli agenti di coding, Claude Code ha la reputazione di avere gusto nel lavoro frontend. Alcune cose lo spiegano."}, {"kind": "steps", "items": [{"label": "Decisioni specifiche, non vaghe", "body": "Claude Code tende a impegnarsi su scelte concrete — valori hex esatti, scale di spaziatura, ramp tipografici e gerarchia dei componenti — invece di tergiversare, ed è proprio questo che distingue una vera interfaccia da un segnaposto."}, {"label": "Ragionamento consapevole della codebase", "body": "Con un ampio contesto di lavoro rifattorizza la UI su molti file contemporaneamente, riutilizzando i tuoi componenti e tokens esistenti invece di reinventare stili improvvisati."}, {"label": "Una skill frontend ufficiale", "body": "Anthropic include una skill Frontend Design che fa scrivere a Claude prima una direzione di design e lo allontana deliberatamente da font di sistema generici e prevedibili gradienti viola."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto nasce da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali."}, {"kind": "p", "text": "La lezione è la stessa che Anthropic ripete sui propri modelli: Claude non ha gusto di default — lasciato a sé converge verso il centro statistico del web design (Inter, gradienti viola, ombre soft). Produce buon design quando gli dai dei vincoli. Open Design impacchetta esattamente quegli input, ed è per questo che i due si combinano bene (più sotto)."}]}, {"id": "setup", "heading": "Configurare Claude Code per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo, da una macchina pulita a un Claude Code in grado di costruire e verificare la UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passi: installa, autentica, configura CLAUDE.md, aggiungi la skill, verifica", "caption": "La sequenza di configurazione: installa → autentica → configura CLAUDE.md → aggiungi la skill Frontend Design → abilita la verifica nel browser."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Inserisci i tuoi tokens, le primitive e le convenzioni in CLAUDE.md e indirizza Claude verso di essi, così l'output rispetta un brand invece di ripiegare su un look generico."}, {"label": "Aggiungi la verifica nel browser", "body": "Collega un MCP Playwright o Chrome così Claude renderizza in un browser reale e controlla il proprio output sui vari breakpoint, invece di confermare solo che la build passa."}]}]}, {"id": "skills-workflow", "heading": "Il flusso di lavoro con CLAUDE.md e le Skill", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggior leva con Claude Code consiste nel fornirgli riferimenti reali più il tuo contesto di design, e poi iterare finché la UI non corrisponde — con CLAUDE.md e le Skill a portare i vincoli, così da non doverli rispiegare a ogni prompt."}, {"kind": "ol", "items": ["Parti dai riferimenti visivi più chiari di cui disponi — e includi più stati (desktop e mobile, hover, vuoto, caricamento), non solo un'unica immagine hero.", "Sii specifico nel prompt; prompt vaghi producono UI generiche anche con un agente forte.", "Tieni il tuo design system e le tue convenzioni in CLAUDE.md, e indica a Claude dove si trovano i tokens e le primitive canoniche.", "Aggiungi la skill Frontend Design così Claude si impegna su una vera direzione estetica prima di scrivere codice.", "Collega la verifica nel browser così Claude renderizza, ridimensiona ai breakpoint e confronta con i riferimenti — non si limita a confermare che la build funziona."]}, {"kind": "p", "text": "Inserisci un'immagine di riferimento nella sessione e formula il prompt con vincoli concreti:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Tieni in esecuzione un dev server a fianco, mantieni i prompt piccoli e mirati e fai commit delle buone iterazioni / revert di quelle cattive (avvisando Claude quando fai revert) così ogni passaggio si costruisce su una base pulita. Usa la modalità plan per i refactoring più grandi così da poter rivedere l'approccio prima di qualsiasi modifica ai file."}]}, {"id": "figma", "heading": "Claude Code + Figma: round-trip design ↔ codice", "blocks": [{"kind": "p", "text": "Nel febbraio 2026 Anthropic e Figma hanno rilasciato un'integrazione bidirezionale di prima classe tramite il server Figma MCP. Funziona in entrambe le direzioni."}, {"kind": "steps", "items": [{"label": "Design → Codice", "body": "Seleziona un frame in Figma o incolla un link in Claude Code, recupera il contesto di design e chiedigli di implementarlo usando la tua libreria di componenti esistente. Code Connect mantiene l'output allineato ai tuoi componenti reali."}, {"label": "Codice → Design", "body": "Costruisci e visualizza in anteprima una funzionalità nel browser, poi di' \"Send this to Figma\" per catturare la UI in esecuzione come layer Figma modificabili — l'intera schermata o un elemento selezionato."}]}, {"kind": "p", "text": "Installalo una volta con claude plugin install figma@claude-plugins-official (la modalità Dev Mode MCP richiede un piano Figma a pagamento). Lo stesso Figma MCP è disponibile per Claude Code, Codex, Cursor e VS Code — esattamente il tipo di capacità portabile e multi-agente che Open Design è costruito per orchestrare."}]}, {"id": "vs", "heading": "Claude Code vs Codex vs Cursor per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso e i team esperti li combinano. Un riassunto equo:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e ragionamento UX consapevole della codebase", "Ragionamento frontend e refactoring a grande contesto"], ["Codex", "Forte rifinitura visiva e comprensione delle immagini; build asincrone in sandbox", "Build asincrone delegate e regole AGENTS.md portabili"], ["Cursor", "Ciclo visivo costruisci-e-osserva con anteprima live e modifiche inline", "Lavoro di UI iterativo e a vista all'interno di un IDE"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dagli esseri umani: tutti e tre, senza skill, riferimenti e vincoli, ripiegano su un'estetica generica. È questo il vero problema da risolvere — ed è di forma da strumento di design, non da modello."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'estetica da \"sbobba dell'IA\"", "blocks": [{"kind": "p", "text": "Anche con la reputazione di gusto di Claude Code, la lamentela più comune sul design generato dall'IA è che appare generico — font Inter, gradienti viola su bianco, ombre soft, angoli arrotondati esagerati, un'estetica che \"urla che l'ha fatto un'IA\". Anthropic stessa lo attribuisce alla convergenza distributiva: le scelte sicure dominano i dati di addestramento del web. Altri problemi segnalati includono layout mobile rotti e istruzioni che trapelano nel testo della UI."}, {"kind": "steps", "items": [{"label": "Installa la skill Frontend Design", "body": "Costringe Claude a impegnarsi su una vera direzione ed evita esplicitamente font e gradienti abusati dall'IA."}, {"label": "Abilita la verifica nel browser", "body": "Fai renderizzare Claude e auto-controllare sui vari breakpoint così i layout non si rompono in silenzio su mobile."}, {"label": "Fornisci tokens e riferimenti", "body": "Tokens di design reali e screenshot di riferimento sono la singola leva più grande sulla qualità dell'output."}, {"label": "Codifica le regole in CLAUDE.md", "body": "Metti regole in stile \"niente hero card, al massimo due caratteri, gerarchia brand-first\" dove l'agente le legge a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione consiste nel dare all'agente un contesto di design curato. Mantenere quel contesto a mano, progetto per progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con Claude Code dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il layer di design open-source che il flusso di lavoro qui sopra continua a richiedere. Tratta Claude Code come un adattatore di prima parte e lo avvolge in una libreria curata di skill e design system, una pipeline di rendering strutturata e una UI desktop locale — così il contesto di design che rende bravo Claude Code è presente fin dalla prima esecuzione, non assemblato a mano ogni volta."}, {"kind": "ol", "items": ["Installa Open Design e seleziona Claude Code come tuo agente.", "Autenticati con la tua chiave API Anthropic (BYOK) o il tuo abbonamento Claude — le credenziali restano sulla tua macchina e non vengono mai instradate tramite noi.", "Scegli un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e file DESIGN.md vive nella tua repo, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente Claude Code, stessa chiave — più un vero flusso di lavoro di design portabile e open-source tutt'intorno. È local-first e Apache-2.0, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "Claude Code è adatto al lavoro di design?", "text": "Sì — è ampiamente considerato l'agente di coding con il miglior gusto per il frontend, capace di decisioni specifiche e consapevoli della codebase su valori hex, spaziatura e scale tipografiche. Con la skill Frontend Design, un design system e immagini di riferimento reali nel contesto produce UI responsive di qualità da produzione e può verificarla in un browser. Senza quel contesto tende a ripiegare su un look generico, ed è il divario che Open Design colma."}, {"name": "Mi serve un abbonamento Claude per progettare con Claude Code?", "text": "Puoi usare sia una chiave API Anthropic (BYOK, tramite la Console) sia un abbonamento Claude (Pro / Max). In ogni caso Open Design non instrada mai le tue credenziali — vengono usate direttamente dal tuo agente sulla tua macchina."}, {"name": "Claude Code o Codex per il design frontend?", "text": "Entrambi sono forti. Claude Code è noto per decisioni di design specifiche e consapevoli della codebase e per il ragionamento frontend; Codex ha una forte rifinitura visiva ed eccelle nelle build delegate e in sandbox. Molti team usano entrambi — Open Design ti permette di cambiare agente senza modificare il tuo flusso di lavoro di design."}, {"name": "Come collego Claude Code a Figma?", "text": "Installa il plugin Figma ufficiale con claude plugin install figma@claude-plugins-official. Potrai poi implementare i frame di Figma in codice usando il contesto di design, e riportare una UI in esecuzione verso frame Figma modificabili con \"Send this to Figma\". La modalità Dev Mode MCP richiede un piano Figma a pagamento."}, {"name": "Cosa sono le Skill e CLAUDE.md?", "text": "CLAUDE.md è un file markdown nella root del tuo progetto che Claude Code legge all'inizio di ogni sessione — il posto dove codificare le tue convenzioni di design. Le Skill impacchettano istruzioni e risorse riutilizzabili che Claude carica su richiesta, inclusa la skill ufficiale Frontend Design di Anthropic. Open Design include una libreria curata di entrambe, così salti la configurazione progetto per progetto."}, {"name": "Come evito l'estetica generica da \"sbobba dell'IA\"?", "text": "Installa la skill Frontend Design, fornisci tokens di design reali e screenshot di riferimento, codifica le regole del brand in CLAUDE.md e abilita la verifica nel browser. Open Design li include come libreria curata, così salti la configurazione progetto per progetto."}, {"name": "Open Design è affiliato ad Anthropic?", "text": "No. Claude Code è un prodotto di Anthropic; Open Design è un progetto open-source indipendente che lo supporta come adattatore di prima parte. Claude e Claude Code sono marchi di Anthropic."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first e Apache-2.0. I tuoi file, gli artefatti e DESIGN.md restano nella tua repo, e le tue credenziali Anthropic vengono usate direttamente dal tuo agente, mai instradate attraverso i server di Open Design."}], "ctaTitle": "Progetta con Claude Code, in modo aperto.", "ctaBody": "Porta la tua chiave Anthropic o il tuo abbonamento Claude, mantieni ogni file in locale e ottieni una libreria di design curata intorno all'agente che già usi.", "ctaActions": [{"label": "Usa Claude Code dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex per il design — Open Design",
        description: "Come le persone usano OpenAI Codex per il design di UI e web — il plugin Product Design, l'integrazione con Figma, le skill frontend — e come Open Design trasforma Codex in un agente di design open-source e local-first.",
        breadcrumb: "Codex",
        label: "Agente · Codex",
        heading: "Codex per il design.",
        lead: "Codex è l'agente di coding di OpenAI. Con il suo plugin Product Design e l'integrazione con Figma è diventato un serio strumento di design. Open Design collega Codex a un flusso di lavoro di design open-source — la tua chiave OpenAI o il tuo abbonamento ChatGPT, i tuoi file, local-first.",
        rich: {"heroCtaLead": "Open Design trasforma Codex in un agente di design open-source e local-first — la tua chiave OpenAI, i tuoi file, una libreria curata di skill e design system tutt'intorno.", "heroCtaActions": [{"label": "Usa Codex dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex è nato come generatore di codice, ma nel 2026 è diventato uno strumento credibile per progettare interfacce reali — una volta che gli fornisci i riferimenti giusti, le skill e un ciclo di verifica. Questa è una guida pratica ed end-to-end all'uso di Codex per UI, frontend e design system, e a come integrarlo in un flusso di lavoro di design strutturato con Open Design.", "Copre cos'è Codex oggi, perché è improvvisamente bravo nel frontend, come configurarlo da zero, il ciclo screenshot-to-UI, il round-trip ufficiale con Figma, come si confronta con Cursor e Claude Code, le insidie che fanno apparire generico l'output dell'IA e come Open Design colma il divario come layer di design aperto e local-first."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Il ciclo di feedback del design con Codex: l'agente da terminale, il browser che renderizza la UI e uno spazio di lavoro, con una freccia di feedback che ritorna", "caption": "Il ciclo centrale: Codex costruisce la UI nel terminale, la renderizza e la verifica in un browser reale e itera rispetto ai tuoi riferimenti."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-codex", "label": "Cos'è realmente OpenAI Codex"}, {"id": "why-design", "label": "Perché ora Codex è bravo nel design"}, {"id": "setup", "label": "Configurare Codex per il design (da zero)"}, {"id": "screenshot-workflow", "label": "Il flusso di lavoro screenshot-to-UI"}, {"id": "figma", "label": "Round-trip Codex + Figma"}, {"id": "vs", "label": "Codex vs Cursor vs Claude Code"}, {"id": "pitfalls", "label": "Insidie e l'estetica da \"sbobba dell'IA\""}, {"id": "open-design", "label": "Progettare con Codex in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-codex", "heading": "Cos'è realmente OpenAI Codex (e cosa non è)", "blocks": [{"kind": "p", "text": "Prima, una disambiguazione che inganna quasi tutti quelli che cercano \"Codex\". L'originale OpenAI Codex era un modello di completamento del codice del 2021 che alimentava i primi GitHub Copilot ed è stato deprecato nel 2023. Non è di questo che parla questa pagina. Il Codex di oggi è lo strumento di coding agentico di OpenAI — pianifica, scrive, esegue e verifica codice a partire da compiti in linguaggio naturale."}, {"kind": "p", "text": "Il Codex moderno è disponibile su quattro superfici: una CLI da terminale (riscritta in Rust, con licenza Apache-2.0), un'estensione IDE per VS Code, Cursor e Windsurf, un'esperienza cloud/web per task asincroni delegati e un'app desktop con un browser integrato e Computer Use."}, {"kind": "steps", "items": [{"label": "Modello predefinito", "body": "A metà 2026 il modello raccomandato è gpt-5.5, con gpt-5.4 come modello che OpenAI ha addestrato esplicitamente per il frontend e il computer use."}, {"label": "File di istruzioni", "body": "Codex legge un file AGENTS.md nel tuo progetto (uno standard cross-tool) per le regole di progetto — il posto naturale dove codificare le tue convenzioni di design."}, {"label": "Sandbox", "body": "Gira in una sandbox a livello kernel (workspace-write di default), così un agente che modifica la tua UI non può vagare al di fuori del progetto."}]}, {"kind": "ul", "items": ["Fornitore: OpenAI", "Credenziale: chiave API OpenAI (BYOK) o abbonamento ChatGPT (Free / Go / Plus / Pro / Business / Enterprise)", "Licenza della CLI: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Perché ora Codex è bravo nel design", "blocks": [{"kind": "p", "text": "Tre cose sono convergute all'inizio del 2026 per rendere Codex un vero strumento di design anziché un generatore di codice generico."}, {"kind": "steps", "items": [{"label": "Un modello addestrato per il frontend", "body": "OpenAI ha rilasciato GPT-5.4, il suo primo modello mainline addestrato per il frontend e il computer use, con una comprensione delle immagini molto migliore lungo tutto il flusso di design e un'auto-verifica più solida. Può persino generare mood board e opzioni visive prima di impegnarsi sugli asset finali."}, {"label": "Una skill frontend ufficiale", "body": "Il catalogo openai/skills include una skill frontend curata che impone vero gusto: layout senza card, hero a tutto schermo, gerarchia brand-first, movimento contenuto, al massimo due caratteri e un colore d'accento — e fa scrivere a Codex una tesi visiva prima di costruire."}, {"label": "Verifica nel browser", "body": "Con la skill Playwright Codex apre un browser reale, ridimensiona ai breakpoint e confronta il proprio output con il riferimento invece di limitarsi a controllare che la build passi."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto nasce da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali."}, {"kind": "p", "text": "La lezione dietro tutte e tre: Codex non ha gusto di default. Produce buon design quando gli dai dei vincoli — un design system, una skill estetica e riferimenti concreti. Open Design impacchetta esattamente quegli input, ed è per questo che i due si combinano bene (più sotto)."}]}, {"id": "setup", "heading": "Configurare Codex per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo, da una macchina pulita a un Codex in grado di costruire e verificare la UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passi: installa, autentica, configura, installa la skill, verifica", "caption": "La sequenza di configurazione: installa → autentica → configura AGENTS.md → installa la skill frontend → abilita la verifica nel browser."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Inserisci i tuoi tokens, le primitive e le convenzioni in AGENTS.md o in un DESIGN.md e indirizza Codex verso di essi, così l'output rispetta un brand invece di ripiegare su un look generico."}, {"label": "Scegli il giusto livello di ragionamento", "body": "OpenAI osserva che livelli di ragionamento da basso a medio spesso producono risultati frontend migliori rispetto all'impostazione più alta."}]}]}, {"id": "screenshot-workflow", "heading": "Il flusso di lavoro screenshot-to-UI", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggior leva con Codex consiste nel trasformare un'immagine di riferimento in una UI funzionante e responsive e iterare finché non corrisponde. Le linee guida di OpenAI si distillano in cinque passi."}, {"kind": "ol", "items": ["Parti dai riferimenti visivi più chiari di cui disponi — e includi più stati (desktop e mobile, hover, vuoto, caricamento), non solo un'unica immagine hero.", "Sii specifico nel prompt; prompt vaghi producono UI generiche.", "Prepara un design system e indica a Codex dove si trovano i tokens e le primitive canoniche.", "Abilita la skill interattiva Playwright così Codex renderizza in un browser reale e ridimensiona ai breakpoint.", "Itera facendo confrontare a Codex la propria implementazione con gli screenshot — non limitarti a confermare che la build funziona."]}, {"kind": "p", "text": "Fornisci le immagini trascinando uno screenshot nel terminale o con il flag image, poi formula il prompt con vincoli concreti:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Esegui un dev server in un secondo terminale, mantieni i prompt piccoli e mirati e fai commit delle buone iterazioni / revert di quelle cattive (avvisando Codex quando fai revert) così ogni passaggio si costruisce su una base pulita."}]}, {"id": "figma", "heading": "Codex + Figma: round-trip design ↔ codice", "blocks": [{"kind": "p", "text": "Nel febbraio 2026 OpenAI e Figma hanno annunciato una partnership ufficiale, trasformando la precedente beta del Figma MCP in un'integrazione bidirezionale di prima classe. Funziona in entrambe le direzioni."}, {"kind": "steps", "items": [{"label": "Design → Codice", "body": "Copia il \"link to selection\" di un frame in Figma, incollalo in Codex con get_design_context e chiedigli di implementare il design usando la tua libreria di componenti esistente."}, {"label": "Codice → Design", "body": "Lo strumento generate_figma_design (\"Code to Canvas\") trasforma una UI live, in esecuzione, in frame Figma modificabili — l'intera schermata, un elemento selezionato o un intero file."}]}, {"kind": "p", "text": "Il Figma MCP gira come server remoto ed è esente dai rate limit. Aggiungilo una volta ed è disponibile per Codex, Claude Code, Cursor, VS Code e altri — esattamente il tipo di capacità portabile e multi-agente che Open Design è costruito per orchestrare."}]}, {"id": "vs", "heading": "Codex vs Cursor vs Claude Code per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso e i team esperti li combinano. Un riassunto equo:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["Codex", "Forte rifinitura visiva dopo GPT-5.4 + skill frontend; comprensione delle immagini", "Build asincrone delegate, esecuzioni in sandbox, regole AGENTS.md portabili"], ["Cursor", "Ciclo visivo costruisci-e-osserva con anteprima live e modifiche inline", "Lavoro di UI iterativo e a vista all'interno di un IDE"], ["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e UX consapevole della codebase", "Ragionamento frontend e refactoring a grande contesto"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dagli esseri umani: tutti e tre, senza skill, riferimenti e vincoli, ripiegano su un'estetica generica. È questo il vero problema da risolvere — ed è di forma da strumento di design, non da modello."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'estetica da \"sbobba dell'IA\"", "blocks": [{"kind": "p", "text": "La lamentela più comune sul design generato da Codex è che appare generico — gradienti soft, pannelli fluttuanti, angoli arrotondati esagerati, ombre drammatiche, un'aria da Inter-e-viola che \"urla che l'ha fatto un'IA\". Altri problemi segnalati includono layout mobile rotti, istruzioni che trapelano nel testo della UI e il raggiungimento rapido dei limiti d'uso."}, {"kind": "steps", "items": [{"label": "Installa una skill frontend", "body": "Una skill estetica curata costringe Codex a impegnarsi su una vera direzione invece del look predefinito."}, {"label": "Abilita la verifica con Playwright", "body": "Fai renderizzare Codex e auto-controllare sui vari breakpoint così i layout non si rompono in silenzio su mobile."}, {"label": "Fornisci tokens e riferimenti", "body": "Tokens di design reali e screenshot di riferimento sono la singola leva più grande sulla qualità dell'output."}, {"label": "Codifica le regole in AGENTS.md", "body": "Metti regole in stile \"niente hero card, al massimo due caratteri, gerarchia brand-first\" dove l'agente le legge a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione consiste nel dare all'agente un contesto di design curato. Mantenere quel contesto a mano, progetto per progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con Codex dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il layer di design open-source che il flusso di lavoro qui sopra continua a richiedere. Tratta Codex come un adattatore di prima parte e lo avvolge in una libreria curata di skill e design system, una pipeline di rendering strutturata e una UI desktop locale — così il contesto di design che rende bravo Codex è presente fin dalla prima esecuzione, non assemblato a mano ogni volta."}, {"kind": "ol", "items": ["Installa Open Design e seleziona Codex come tuo agente.", "Autenticati con la tua chiave API OpenAI (BYOK) o il tuo abbonamento ChatGPT — le credenziali restano sulla tua macchina e non vengono mai instradate tramite noi.", "Scegli un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e file DESIGN.md vive nella tua repo, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente Codex, stessa chiave — più un vero flusso di lavoro di design portabile e open-source tutt'intorno. È local-first e Apache-2.0, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "OpenAI Codex può davvero fare lavoro di design?", "text": "Sì — con una skill frontend, un design system e immagini di riferimento reali nel contesto, Codex (specialmente su GPT-5.4) produce UI responsive di qualità da produzione e può verificarla in un browser. Senza quel contesto tende a ripiegare su un look generico, ed è il divario che Open Design colma."}, {"name": "Questo è il plugin Product Design di OpenAI Codex?", "text": "No. Open Design è un progetto open-source indipendente che integra Codex come agente. Completa gli strumenti di OpenAI con una libreria di skill e design system aperta e local-first."}, {"name": "Mi serve un abbonamento ChatGPT per progettare con Codex?", "text": "Puoi usare sia una chiave API OpenAI (BYOK) sia il tuo abbonamento ChatGPT. L'accesso con ChatGPT in genere offre limiti più generosi; in ogni caso Open Design non instrada mai le tue credenziali."}, {"name": "Codex o Claude Code per il design frontend?", "text": "Entrambi sono forti. Claude Code è noto per decisioni di design specifiche e consapevoli della codebase; Codex ha una forte rifinitura visiva dopo GPT-5.4 ed eccelle nelle build delegate e in sandbox. Molti team usano entrambi — Open Design ti permette di cambiare agente senza modificare il tuo flusso di lavoro di design."}, {"name": "Come collego Codex a Figma?", "text": "Aggiungi il server Figma MCP ufficiale (codex mcp add figma --url https://mcp.figma.com/mcp). Potrai poi implementare i frame di Figma in codice con get_design_context e riportare una UI in esecuzione verso frame Figma modificabili con generate_figma_design."}, {"name": "Come evito l'estetica generica da \"sbobba dell'IA\"?", "text": "Installa una skill frontend, fornisci tokens di design reali e screenshot di riferimento, codifica le regole del brand in AGENTS.md e abilita la verifica con Playwright. Open Design li include come libreria curata, così salti la configurazione progetto per progetto."}, {"name": "Open Design è affiliato a OpenAI?", "text": "No. Codex è un prodotto di OpenAI; Open Design è un progetto open-source indipendente che lo supporta come adattatore di prima parte. OpenAI e Codex sono marchi di OpenAI."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first. I tuoi file, gli artefatti e DESIGN.md restano nella tua repo, e le tue credenziali OpenAI vengono usate direttamente dal tuo agente, mai instradate attraverso i server di Open Design."}], "ctaTitle": "Progetta con Codex, in modo aperto.", "ctaBody": "Porta la tua chiave OpenAI, mantieni ogni file in locale e ottieni una libreria di design curata intorno all'agente che già usi.", "ctaActions": [{"label": "Usa Codex dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor per i designer — Open Design",
        description: "Come i designer usano Cursor per il design di UI e web — Design Mode, da Figma a codice, il Figma MCP — e come Open Design trasforma Cursor in un agente di design open-source e local-first.",
        breadcrumb: "Cursor",
        label: "Agente · Cursor",
        heading: "Cursor per i designer.",
        lead: "Cursor è l'editor di codice IA, ora con una Design Mode visiva. I designer lo usano per modificare la UI puntando e disegnando, e per trasformare Figma in codice. Open Design collega Cursor Agent a un flusso di lavoro di design open-source che mantiene i tuoi file in locale.",
        rich: {"heroCtaLead": "Open Design trasforma Cursor in un agente di design open-source e local-first — il tuo account Cursor o le tue chiavi di modello, i tuoi file, una libreria curata di skill e design system tutt'intorno.", "heroCtaActions": [{"label": "Usa Cursor dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor è l'editor di codice AI-first che ha reso \"costruiscilo e guardalo renderizzare\" il modo predefinito di rilasciare UI. Con la modalità Agent, le modifiche inline, un'anteprima nell'editor e Figma tramite MCP, è diventato un vero strumento di design — una volta che gli fornisci i riferimenti giusti, le regole e un ciclo di verifica. Questa è una guida pratica ed end-to-end all'uso di Cursor per UI, frontend e design system, e a come integrarlo in un flusso di lavoro di design strutturato con Open Design.", "Copre cos'è realmente Cursor, perché il suo stretto ciclo itera-e-osserva è adatto al design, come configurarlo da zero, il ciclo screenshot-e-anteprima-to-UI, il round-trip con Figma tramite MCP, come si confronta con Codex e Claude Code, le insidie che fanno apparire generico l'output dell'IA e come Open Design colma il divario come layer di design aperto e local-first."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "La convergenza del design con Cursor: l'editor a sinistra, un hub curato di skill e design system al centro con il marchio Cursor al centro, e una UI renderizzata a destra", "caption": "L'idea centrale: Cursor modifica e renderizza la UI nell'editor, mentre un hub di design curato gli fornisce il sistema, le skill e i riferimenti che fanno apparire intenzionale l'output."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-cursor", "label": "Cos'è realmente Cursor"}, {"id": "why-design", "label": "Perché Cursor è bravo nel design"}, {"id": "setup", "label": "Configurare Cursor per il design (da zero)"}, {"id": "preview-workflow", "label": "Il flusso di lavoro anteprima-to-UI"}, {"id": "figma", "label": "Cursor + Figma tramite MCP"}, {"id": "vs", "label": "Cursor vs Codex vs Claude Code"}, {"id": "pitfalls", "label": "Insidie e l'estetica da \"sbobba dell'IA\""}, {"id": "open-design", "label": "Progettare con Cursor in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-cursor", "heading": "Cos'è realmente Cursor", "blocks": [{"kind": "p", "text": "Cursor è un editor di codice AI-first costruito da Anysphere. È un fork di VS Code, quindi conserva l'editor, le estensioni e le scorciatoie da tastiera familiari, ma ricostruisce il flusso di lavoro attorno a un agente IA capace di leggere l'intero progetto, modificare più file, eseguire comandi e iterare con te nel ciclo."}, {"kind": "p", "text": "Per il lavoro di design le superfici importanti sono la modalità Agent (descrivi un risultato e Cursor pianifica e modifica attraverso i file), le modifiche inline e i completamenti Tab per aggiustamenti rapidi, un'anteprima / browser nell'editor così puoi vedere la UI in esecuzione senza lasciare la finestra, e il supporto MCP che gli permette di attingere a contesto esterno come un file Figma live."}, {"kind": "steps", "items": [{"label": "Regole di progetto", "body": "Cursor legge file di istruzioni di progetto — regole `.mdc` versionate sotto `.cursor/rules`, e un semplice `AGENTS.md` — così puoi codificare le tue convenzioni di design dove l'agente le legge a ogni esecuzione."}, {"label": "Modelli", "body": "Cursor è flessibile sui modelli: include modelli di frontiera tramite il tuo abbonamento e supporta anche l'uso delle tue chiavi di modello, così scegli il motore dietro lo stesso flusso di lavoro dell'editor."}, {"label": "MCP", "body": "Parla il Model Context Protocol, così i server esterni — il più rilevante è il server Figma MCP — diventano contesto di prima classe per l'agente."}]}, {"kind": "ul", "items": ["Fornitore: Anysphere", "Credenziale: account / abbonamento Cursor (Hobby / Pro / Business) o le tue chiavi di modello (BYOK)", "Forma: editor di codice AI-first (fork di VS Code) con agente e anteprima nell'editor"]}]}, {"id": "why-design", "heading": "Perché Cursor è bravo nel design", "blocks": [{"kind": "p", "text": "Il vantaggio di Cursor nel design non è una singola funzionalità — è la strettezza del ciclo costruisci-e-osserva. Tre cose lo fanno sembrare uno strumento di design anziché un generatore di codice generico."}, {"kind": "steps", "items": [{"label": "Uno stretto ciclo itera-e-osserva", "body": "Tu dai il prompt, Cursor modifica attraverso i file e l'anteprima nell'editor renderizza il risultato immediatamente — così aggiusti spaziatura, gerarchia e movimento in secondi invece di fare avanti e indietro tra un terminale e un browser separati."}, {"label": "Editing visivo diretto", "body": "Oltre alla chat, Cursor ti permette di selezionare elementi nell'anteprima e ritoccare gli stili, così le piccole correzioni visive sembrano modifiche di design piuttosto che archeologia del codice."}, {"label": "Regole di progetto e contesto MCP", "body": "Con `.cursor/rules` (o `AGENTS.md`) e il server Figma MCP, l'agente lavora rispetto ai tuoi tokens, componenti e specifiche di design reali invece di tirare a indovinare."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto nasce da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali."}, {"kind": "p", "text": "La lezione è la stessa che insegna ogni agente: Cursor non ha gusto di default. Produce buon design quando gli dai dei vincoli — un design system, una skill estetica e riferimenti concreti. Open Design impacchetta esattamente quegli input, ed è per questo che i due si combinano bene (più sotto)."}]}, {"id": "setup", "heading": "Configurare Cursor per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo, da una macchina pulita a un Cursor in grado di costruire, visualizzare in anteprima e verificare la UI rispetto al tuo design system."}, {"kind": "ol", "items": ["Installa Cursor da cursor.com e accedi con il tuo account Cursor, oppure configura le tue chiavi di modello (BYOK) nelle Impostazioni.", "Apri il tuo progetto e scegli un modello nel pannello chat / Agent.", "Aggiungi regole di progetto: crea `.cursor/rules/*.mdc` per convenzioni strutturate e con ambito glob, oppure un semplice `AGENTS.md` per istruzioni semplici e leggibili.", "Connetti il server Figma MCP (opzionale) così l'agente può leggere il contesto di design live.", "Esegui il tuo dev server e usa l'anteprima nell'editor per vedere e verificare la UI mentre iteri."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passi: installa, autentica, configura le regole, aggiungi la skill, verifica", "caption": "La sequenza di configurazione: installa → autentica → configura le regole di progetto → aggiungi una skill → abilita la verifica in anteprima."}, {"kind": "p", "text": "Un file di regole di progetto minimale fa progettare l'agente verso un brand invece di ripiegare su un look generico. Mettilo dove Cursor lo legge a ogni esecuzione:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Inserisci i tuoi tokens, le primitive e le convenzioni in `.cursor/rules` o `AGENTS.md` e indirizza Cursor verso di essi, così l'output rispetta un brand invece di ripiegare su un look generico."}, {"label": "Mantieni i prompt piccoli", "body": "Lo stretto ciclo di Cursor premia le richieste mirate — itera un componente o uno stato alla volta e osserva l'anteprima tra un passaggio e l'altro."}]}]}, {"id": "preview-workflow", "heading": "Il flusso di lavoro anteprima-to-UI", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggior leva con Cursor consiste nel trasformare un riferimento in una UI funzionante e responsive e iterare nell'editor finché non corrisponde — guardando l'anteprima live per tutto il tempo invece di tirare a indovinare."}, {"kind": "ol", "items": ["Parti dai riferimenti visivi più chiari di cui disponi — e includi più stati (desktop e mobile, hover, vuoto, caricamento), non solo un'unica immagine hero.", "Sii specifico nel prompt; prompt vaghi producono UI generiche.", "Prepara un design system e indica a Cursor dove si trovano i tokens e le primitive canoniche.", "Tieni aperta l'anteprima nell'editor e in esecuzione il tuo dev server così ogni modifica renderizza immediatamente ai breakpoint che ti interessano.", "Itera confrontando la UI renderizzata con i riferimenti — e usa la selezione diretta degli elementi nell'anteprima per piccole correzioni visive."]}, {"kind": "p", "text": "Fornisci i riferimenti allegando un'immagine alla chat, poi formula il prompt con vincoli concreti:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Fai commit delle buone iterazioni e revert di quelle cattive (avvisando Cursor quando fai revert) così ogni passaggio si costruisce su una base pulita — la stessa disciplina che impedisce a qualsiasi ciclo di agente di andare alla deriva."}]}, {"id": "figma", "heading": "Cursor + Figma: design ↔ codice tramite MCP", "blocks": [{"kind": "p", "text": "Cursor si connette a Figma attraverso il server Figma MCP ufficiale, che dà all'agente accesso strutturato a un file Figma live invece di uno screenshot piatto. Questo elimina le congetture dall'handoff."}, {"kind": "steps", "items": [{"label": "Design → Codice", "body": "Copia il link di un frame in Figma, incollalo in Cursor e chiedigli di implementare il design. Il server MCP espone contesto di design reale — componenti, variabili, dati di layout, tokens — così il codice generato corrisponde alla sorgente invece di approssimarla."}, {"label": "Resta allineato", "body": "Con tokens di design, stili e componenti usati in modo coerente in Figma (e Code Connect dove disponibile), l'output di Cursor resta mappato sul tuo design system reale anziché reinventare le primitive."}]}, {"kind": "p", "text": "Configura il server Figma MCP remoto una volta ed è disponibile per Cursor come contesto di prima classe. Poiché MCP è uno standard aperto, lo stesso server è riutilizzabile su Cursor, Claude Code, Codex e VS Code — esattamente il tipo di capacità portabile e multi-agente che Open Design è costruito per orchestrare."}]}, {"id": "vs", "heading": "Cursor vs Codex vs Claude Code per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso e i team esperti li combinano. Un riassunto equo:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["Cursor", "Ciclo visivo costruisci-e-osserva con anteprima live nell'editor e editing diretto degli elementi", "Lavoro di UI iterativo e a vista all'interno di un IDE"], ["Codex", "Forte rifinitura visiva con una skill frontend; comprensione delle immagini ed esecuzioni in sandbox", "Build asincrone delegate e regole AGENTS.md portabili"], ["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e UX consapevole della codebase", "Ragionamento frontend e refactoring a grande contesto"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dagli esseri umani: tutti e tre, senza skill, riferimenti e vincoli, ripiegano su un'estetica generica. È questo il vero problema da risolvere — ed è di forma da strumento di design, non da modello."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'estetica da \"sbobba dell'IA\"", "blocks": [{"kind": "p", "text": "La lamentela più comune sul design generato da Cursor è che appare generico — gradienti soft, pannelli fluttuanti, angoli arrotondati esagerati, ombre drammatiche, un'aria da Inter-e-viola che \"urla che l'ha fatto un'IA\". Altri problemi segnalati includono layout che si rompono su mobile e istruzioni che trapelano nel testo della UI."}, {"kind": "steps", "items": [{"label": "Aggiungi una skill di design", "body": "Una skill estetica curata costringe Cursor a impegnarsi su una vera direzione invece del look predefinito."}, {"label": "Usa l'anteprima per verificare", "body": "Renderizza e auto-controlla sui vari breakpoint nell'anteprima nell'editor così i layout non si rompono in silenzio su mobile."}, {"label": "Fornisci tokens e riferimenti", "body": "Tokens di design reali e screenshot di riferimento sono la singola leva più grande sulla qualità dell'output."}, {"label": "Codifica le regole in `.cursor/rules`", "body": "Metti regole in stile \"niente hero card, al massimo due caratteri, gerarchia brand-first\" dove l'agente le legge a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione consiste nel dare all'agente un contesto di design curato. Mantenere quel contesto a mano, progetto per progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con Cursor dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il layer di design open-source che il flusso di lavoro qui sopra continua a richiedere. Tratta Cursor come un adattatore di prima parte e lo avvolge in una libreria curata di skill e design system, una pipeline di rendering strutturata e una UI desktop locale — così il contesto di design che rende bravo Cursor è presente fin dalla prima esecuzione, non assemblato a mano ogni volta."}, {"kind": "ol", "items": ["Installa Open Design e seleziona Cursor come tuo agente.", "Autenticati con il tuo account Cursor o le tue chiavi di modello (BYOK) — le credenziali restano sulla tua macchina e non vengono mai instradate tramite noi.", "Scegli un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e file DESIGN.md vive nella tua repo, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente Cursor, stessa chiave — più un vero flusso di lavoro di design portabile e open-source tutt'intorno. È local-first e Apache-2.0, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "Cursor può davvero fare lavoro di design?", "text": "Sì — con una skill di design, un design system e immagini di riferimento reali nel contesto, Cursor produce UI responsive di qualità da produzione, e la sua anteprima nell'editor ti permette di verificarla e rifinirla visivamente. Senza quel contesto tende a ripiegare su un look generico, ed è il divario che Open Design colma."}, {"name": "Questo è un prodotto Cursor ufficiale?", "text": "No. Open Design è un progetto open-source indipendente che integra Cursor come agente. Completa Cursor con una libreria di skill e design system aperta e local-first."}, {"name": "Mi serve un abbonamento Cursor per progettare con Cursor?", "text": "Puoi usare un account / abbonamento Cursor oppure portare le tue chiavi di modello (BYOK). In ogni caso Open Design non instrada mai le tue credenziali — vengono usate direttamente dal tuo agente."}, {"name": "Cursor o Claude Code per il design frontend?", "text": "Entrambi sono forti. Claude Code è noto per decisioni di design specifiche e consapevoli della codebase; il vantaggio di Cursor è il suo stretto ciclo costruisci-e-osserva con un'anteprima live dentro l'editor. Molti team usano entrambi — Open Design ti permette di cambiare agente senza modificare il tuo flusso di lavoro di design."}, {"name": "Come collego Cursor a Figma?", "text": "Aggiungi il server Figma MCP ufficiale in Cursor, poi incolla il link di un frame Figma nella chat e chiedi a Cursor di implementarlo. Il server espone componenti, variabili e dati di layout reali così il codice generato corrisponde al design sorgente."}, {"name": "Come evito l'estetica generica da \"sbobba dell'IA\"?", "text": "Aggiungi una skill di design, fornisci tokens di design reali e screenshot di riferimento, codifica le regole del brand in `.cursor/rules` o `AGENTS.md`, e verifica sui vari breakpoint nell'anteprima. Open Design li include come libreria curata, così salti la configurazione progetto per progetto."}, {"name": "Open Design è affiliato a Cursor o Anysphere?", "text": "No. Cursor è un prodotto di Anysphere; Open Design è un progetto open-source indipendente che lo supporta come adattatore di prima parte. Cursor e Anysphere sono marchi di Anysphere, Inc."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first. I tuoi file, gli artefatti e DESIGN.md restano nella tua repo, e le tue credenziali Cursor o di modello vengono usate direttamente dal tuo agente, mai instradate attraverso i server di Open Design."}], "ctaTitle": "Progetta con Cursor, in modo aperto.", "ctaBody": "Porta il tuo account Cursor o le tue chiavi di modello, mantieni ogni file in locale e ottieni una libreria di design curata intorno all'agente che già usi.", "ctaActions": [{"label": "Usa Cursor dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode per il design — Open Design",
        description: "Come le persone usano OpenCode per il design di UI e web — file design.md, skill UI/UX, Figma MCP — e come Open Design trasforma OpenCode in un agente di design open-source e local-first.",
        breadcrumb: "OpenCode",
        label: "Agente · OpenCode",
        heading: "OpenCode per il design.",
        lead: "OpenCode è l'agente di coding IA da terminale open-source. I designer vi aggiungono skill di design e file DESIGN.md per generare UI reali. Open Design ne fa un flusso di lavoro strutturato e open-source — porta le chiavi dei tuoi provider, mantieni tutto in locale.",
        rich: {"heroCtaLead": "Open Design trasforma OpenCode in un agente di design open-source e local-first — qualsiasi modello tu scelga con la tua chiave di provider, i tuoi file, una libreria curata di skill e design system tutt'intorno.", "heroCtaActions": [{"label": "Usa OpenCode dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode è un agente di coding IA open-source e terminal-first deliberatamente agnostico rispetto al modello: porti la tua chiave di provider ed esegui qualunque modello vuoi dietro lo stesso flusso di lavoro. Questa apertura ne fa una base naturale per il lavoro di design — ma, come ogni agente, produce buona UI solo quando gli fornisci i riferimenti giusti, le skill e un ciclo di verifica. Questa è una guida pratica ed end-to-end all'uso di OpenCode per UI, frontend e design system, e a come integrarlo in un flusso di lavoro di design strutturato con Open Design.", "Copre cos'è realmente OpenCode, perché un agente aperto e agnostico rispetto al modello è adatto al design, come configurarlo da zero, il ciclo screenshot-to-UI, come AGENTS.md e MCP lo estendono, come si confronta con Codex, Claude Code e Cursor, le insidie che fanno apparire generico l'output dell'IA e come Open Design colma il divario come layer di design aperto e local-first — un abbinamento naturale, dato che entrambi i progetti sono open-source e girano sulla tua macchina."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "Il ciclo di feedback del design con OpenCode: un agente TUI da terminale, un browser che renderizza la UI e uno spazio di lavoro, con una freccia di feedback che ritorna", "caption": "Il ciclo centrale: OpenCode costruisce la UI nel terminale, la renderizza e la verifica in un browser reale e itera rispetto ai tuoi riferimenti — su qualsiasi modello tu scelga."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-opencode", "label": "Cos'è realmente OpenCode"}, {"id": "why-design", "label": "Perché un agente aperto e con qualsiasi modello è adatto al design"}, {"id": "setup", "label": "Configurare OpenCode per il design (da zero)"}, {"id": "screenshot-workflow", "label": "Il flusso di lavoro screenshot-to-UI"}, {"id": "extend", "label": "AGENTS.md, MCP e sessioni condivisibili"}, {"id": "vs", "label": "OpenCode vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "Insidie e l'estetica da \"sbobba dell'IA\""}, {"id": "open-design", "label": "Progettare con OpenCode in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-opencode", "heading": "Cos'è realmente OpenCode", "blocks": [{"kind": "p", "text": "OpenCode è un agente di coding IA open-source costruito per il terminale, mantenuto dal team dietro SST (Anomaly Innovations). Legge la tua repository, esegue comandi, modifica file e parla con un modello linguistico di grandi dimensioni — ma, a differenza degli agenti legati a un fornitore, non include un proprio modello. Lo punti verso qualunque provider e modello vuoi e porti la tua chiave."}, {"kind": "p", "text": "Gira come UI da terminale (TUI), con un'app desktop ed estensioni IDE sopra lo stesso motore. Sotto il cofano usa un'architettura client/server, così l'agente che fa il lavoro è disaccoppiato dalla superficie da cui lo guidi. Due agenti integrati — build e plan — si alternano con il tasto Tab."}, {"kind": "steps", "items": [{"label": "Agnostico rispetto al modello", "body": "Modelli e provider provengono da models.dev, un catalogo aperto. Li configuri in opencode.json con una stringa provider/model-id e puoi disabilitare i provider che non vuoi caricare — così lo stesso flusso di lavoro di design gira su Anthropic, OpenAI, Google, OpenRouter, modelli locali e altro."}, {"label": "File di istruzioni", "body": "OpenCode legge un file AGENTS.md nel tuo progetto (lo standard cross-tool, compatibile anche con CLAUDE.md) per le regole di progetto — il posto naturale dove codificare le tue convenzioni di design. Esegui /init per generarne uno."}, {"label": "Estendibile", "body": "Supporta l'integrazione LSP, i server MCP, i temi, le scorciatoie da tastiera e i comandi personalizzati, oltre a link di sessione condivisibili per la collaborazione."}]}, {"kind": "ul", "items": ["Manutentore: SST / Anomaly Innovations (progetto open-source)", "Credenziale: la/le tua/e chiave/i API di provider di modello — BYOK, senza vincoli di fornitore", "Licenza: MIT, open source"]}]}, {"id": "why-design", "heading": "Perché un agente aperto e con qualsiasi modello è adatto al lavoro di design", "blocks": [{"kind": "p", "text": "OpenCode non ha un singolo \"modello di design\" come ce l'ha un agente di fornitore — ed è proprio il punto. Poiché è agnostico rispetto al modello e aperto, puoi eseguire lo stesso flusso di lavoro di design su qualsiasi modello sia attualmente il migliore nel frontend, cambiarlo in seguito o ripiegare su un modello locale, tutto senza modificare la tua configurazione."}, {"kind": "p", "text": "Ma la scelta del modello da sola non compra il gusto. Come ogni agente di coding, OpenCode produce UI generiche a meno che non gli dia dei vincoli. Un buon output di design nasce da tre input che fornisci tu."}, {"kind": "steps", "items": [{"label": "Un design system", "body": "Tokens, primitive e convenzioni reali che l'agente riutilizza, così l'output rispetta un brand invece di ripiegare su un look generico."}, {"label": "Una skill estetica", "body": "Una skill curata che impone vero gusto — movimento contenuto, gerarchia brand-first, al massimo due caratteri e un colore d'accento — e fa impegnare l'agente su una direzione prima di costruire."}, {"label": "Riferimenti concreti", "body": "Immagini di riferimento reali e più stati (desktop e mobile, hover, vuoto, caricamento), non una singola immagine hero."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto nasce da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali — indipendentemente da quale modello esegui."}, {"kind": "p", "text": "La lezione: OpenCode ti dà libertà di modello, ma il gusto continua a nascere da un contesto di design curato. Open Design impacchetta esattamente quegli input, ed è per questo che i due si combinano bene — entrambi sono open-source e local-first (più sotto)."}]}, {"id": "setup", "heading": "Configurare OpenCode per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo, da una macchina pulita a un OpenCode in grado di costruire e verificare la UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passi: installa, autentica con la tua chiave di provider, configura AGENTS.md, aggiungi una skill, verifica", "caption": "La sequenza di configurazione: installa → autentica (la tua chiave di provider) → configura AGENTS.md → aggiungi una skill → verifica in un browser reale."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Inserisci i tuoi tokens, le primitive e le convenzioni in AGENTS.md (o in un DESIGN.md richiamato da esso) così l'output rispetta un brand invece di ripiegare su un look generico. L'opzione instructions in opencode.json può puntare a file di regole aggiuntivi tramite glob."}, {"label": "Scegli un modello capace", "body": "Poiché OpenCode è agnostico rispetto al modello, scegli quale provider/modello sia attualmente il più forte nel frontend per il passaggio di design — e mantieni invariato il resto del tuo flusso di lavoro."}]}]}, {"id": "screenshot-workflow", "heading": "Il flusso di lavoro screenshot-to-UI", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggior leva con qualsiasi agente consiste nel trasformare un'immagine di riferimento in una UI funzionante e responsive e iterare finché non corrisponde. La stessa struttura in cinque passi vale in OpenCode."}, {"kind": "ol", "items": ["Parti dai riferimenti visivi più chiari di cui disponi — e includi più stati (desktop e mobile, hover, vuoto, caricamento), non solo un'unica immagine hero.", "Sii specifico nel prompt; prompt vaghi producono UI generiche.", "Prepara un design system e indica a OpenCode dove si trovano i tokens e le primitive canoniche (in AGENTS.md).", "Esegui un dev server e fai renderizzare l'agente in un browser reale, ridimensionando ai breakpoint per controllare il risultato.", "Itera facendo confrontare a OpenCode la propria implementazione con gli screenshot — non limitarti a confermare che la build funziona."]}, {"kind": "p", "text": "Richiama i file con @ nella TUI per una ricerca fuzzy della tua directory di lavoro, esegui comandi shell inline con un ! iniziale e guida le azioni con i comandi /. Poi formula il prompt con vincoli concreti:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Mantieni i prompt piccoli e mirati, fai commit delle buone iterazioni e revert di quelle cattive (avvisando OpenCode quando fai revert), così ogni passaggio si costruisce su una base pulita."}]}, {"id": "extend", "heading": "AGENTS.md, MCP e sessioni condivisibili", "blocks": [{"kind": "p", "text": "Tre punti di estensione rendono OpenCode pratico per il lavoro di design prolungato, e tutti e tre si mappano in modo pulito su un flusso di lavoro di design aperto."}, {"kind": "steps", "items": [{"label": "Regole AGENTS.md", "body": "Le regole di progetto vivono in un AGENTS.md nella root della repo (o regole globali in ~/.config/opencode/AGENTS.md). È la casa duratura per le tue convenzioni di design, letta a ogni esecuzione, ed è compatibile con i file CLAUDE.md usati da altri agenti."}, {"label": "Server MCP", "body": "OpenCode supporta server MCP sia locali (command) sia remoti (URL), configurati sotto la chiave mcp — il modo portabile per portare contesto di design e strumenti esterni che funzionano su più agenti, non solo OpenCode."}, {"label": "Sessioni condivisibili", "body": "Il comando /share crea un link pubblico a una conversazione per collaborazione o revisione, e /unshare lo revoca — utile per ottenere feedback su un passaggio di design."}]}, {"kind": "p", "text": "Queste sono capacità portabili e multi-agente — esattamente il tipo di cosa che Open Design è costruito per orchestrare, invece di ricrearla progetto per progetto."}]}, {"id": "vs", "heading": "OpenCode vs Codex vs Claude Code vs Cursor per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso e i team esperti li combinano. Un riassunto equo:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["OpenCode", "Open-source e agnostico rispetto al modello; esegui qualsiasi provider dietro un unico flusso di lavoro da terminale", "Libertà BYOK, cambio di modello, configurazioni completamente aperte e local-first"], ["Codex", "Forte rifinitura visiva con una skill frontend; comprensione delle immagini", "Asincrono delegato, build in sandbox, regole AGENTS.md portabili"], ["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e UX consapevole della codebase", "Ragionamento frontend e refactoring a grande contesto"], ["Cursor", "Ciclo visivo costruisci-e-osserva con anteprima live e modifiche inline", "Lavoro di UI iterativo e a vista all'interno di un IDE"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dagli esseri umani: tutti, senza skill, riferimenti e vincoli, ripiegano su un'estetica generica. È questo il vero problema da risolvere — ed è di forma da strumento di design, non da modello, ed è precisamente per questo che un agente aperto come OpenCode si abbina così bene a un layer di design aperto."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'estetica da \"sbobba dell'IA\"", "blocks": [{"kind": "p", "text": "La lamentela più comune sul design generato dall'IA è che appare generico — gradienti soft, pannelli fluttuanti, angoli arrotondati esagerati, ombre drammatiche, un'aria da Inter-e-viola che \"urla che l'ha fatto un'IA\". Altri problemi segnalati includono layout mobile rotti e istruzioni che trapelano nel testo della UI. Nessuno di questi è esclusivo di OpenCode; sono ciò che accade quando qualsiasi agente gira senza un contesto di design curato."}, {"kind": "steps", "items": [{"label": "Aggiungi una skill estetica", "body": "Una skill di design curata costringe l'agente a impegnarsi su una vera direzione invece del look predefinito."}, {"label": "Verifica in un browser reale", "body": "Renderizza e auto-controlla sui vari breakpoint così i layout non si rompono in silenzio su mobile."}, {"label": "Fornisci tokens e riferimenti", "body": "Tokens di design reali e screenshot di riferimento sono la singola leva più grande sulla qualità dell'output."}, {"label": "Codifica le regole in AGENTS.md", "body": "Metti regole in stile \"niente hero card, al massimo due caratteri, gerarchia brand-first\" dove l'agente le legge a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione consiste nel dare all'agente un contesto di design curato — indipendentemente da quale modello esegui. Mantenere quel contesto a mano, progetto per progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con OpenCode dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il layer di design open-source che il flusso di lavoro qui sopra continua a richiedere. Tratta OpenCode come un adattatore di prima parte e lo avvolge in una libreria curata di skill e design system, una pipeline di rendering strutturata e una UI desktop locale — così il contesto di design che rende bravo qualsiasi agente è presente fin dalla prima esecuzione, non assemblato a mano ogni volta. Entrambi i progetti sono open-source e local-first, il che rende l'abbinamento un'unione naturale."}, {"kind": "ol", "items": ["Installa Open Design e seleziona OpenCode come tuo agente.", "Autenticati con la tua chiave API di provider di modello (BYOK) — le credenziali restano sulla tua macchina e non vengono mai instradate tramite noi.", "Scegli qualsiasi provider e modello, più un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e file DESIGN.md vive nella tua repo, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente OpenCode, stessa libertà di modello — più un vero flusso di lavoro di design portabile e open-source tutt'intorno. È local-first e Apache-2.0, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "OpenCode può davvero fare lavoro di design?", "text": "Sì — con una skill estetica, un design system e immagini di riferimento reali nel contesto, OpenCode produce UI responsive di qualità da produzione e può verificarla in un browser. Poiché è agnostico rispetto al modello, esegui qualsiasi modello sia attualmente il migliore nel frontend. Senza quel contesto curato tende a ripiegare su un look generico, ed è il divario che Open Design colma."}, {"name": "Quale modello dovrei usare con OpenCode per il design?", "text": "Quello che preferisci — OpenCode è agnostico rispetto al provider tramite models.dev, così puoi eseguire Anthropic, OpenAI, Google, OpenRouter o modelli locali dietro lo stesso flusso di lavoro e cambiarli in qualsiasi momento. La qualità dell'output di design dipende molto più dalla tua skill, dal tuo design system e dai tuoi riferimenti che dal modello da solo."}, {"name": "Open Design è realizzato dal team di OpenCode (SST)?", "text": "No. Open Design è un progetto open-source indipendente che integra OpenCode come agente. Completa OpenCode con una libreria di skill e design system aperta e local-first."}, {"name": "Mi serve un abbonamento speciale per progettare con OpenCode?", "text": "No — OpenCode è BYOK. Porti la tua chiave API di provider di modello, e Open Design non instrada mai le tue credenziali. Non c'è alcun vincolo di fornitore."}, {"name": "OpenCode o Codex o Claude Code per il design frontend?", "text": "Sono tutti forti, e molti team li combinano. Il vantaggio di OpenCode è essere completamente open-source e agnostico rispetto al modello; Codex eccelle nelle build delegate e in sandbox; Claude Code è noto per decisioni di design specifiche e consapevoli della codebase. Open Design ti permette di cambiare agente senza modificare il tuo flusso di lavoro di design."}, {"name": "Come estendo OpenCode per il contesto di design?", "text": "Codifica le regole in AGENTS.md, aggiungi server MCP sotto la chiave mcp per strumenti e contesto di design portabili, e usa le sessioni condivisibili per la revisione. Open Design include una libreria curata di skill e design system, così salti la configurazione progetto per progetto."}, {"name": "Open Design è affiliato a OpenCode o SST?", "text": "No. OpenCode è un progetto open-source mantenuto da SST (Anomaly Innovations); Open Design è un progetto open-source indipendente che lo supporta come adattatore di prima parte."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first. I tuoi file, gli artefatti e DESIGN.md restano nella tua repo, e le tue credenziali di provider di modello vengono usate direttamente dal tuo agente, mai instradate attraverso i server di Open Design."}], "ctaTitle": "Progetta con OpenCode, in modo aperto.", "ctaBody": "Porta la tua chiave di provider di modello, mantieni ogni file in locale e ottieni una libreria di design curata intorno all'agente aperto che già usi.", "ctaActions": [{"label": "Usa OpenCode dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
    },
    'vi': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code cho thiết kế — Open Design",
        description: "Cách các nhà thiết kế dùng Claude Code cho thiết kế UI và web, và cách Open Design biến nó thành một agent thiết kế thực thụ — local-first, BYOK, kèm thư viện skill và design-system được tuyển chọn.",
        breadcrumb: "Claude Code",
        label: "Agent · Claude Code",
        heading: "Claude Code cho thiết kế.",
        lead: "Claude Code là agent lập trình chạy trên terminal của Anthropic. Người ta đã dùng nó để dựng UI, design system và landing page. Open Design cắm nó vào một quy trình thiết kế thực thụ — mang theo khóa Anthropic hoặc gói đăng ký Claude của bạn, giữ mọi tệp tin ở máy bạn.",
        rich: {"heroCtaLead": "Open Design biến Claude Code thành một agent thiết kế local-first, mã nguồn mở — khóa Anthropic hoặc gói đăng ký Claude của bạn, tệp tin của bạn, kèm thư viện skill và design-system được tuyển chọn bao quanh nó.", "heroCtaActions": [{"label": "Dùng Claude Code trong Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gắn sao trên GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Tải ứng dụng desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code được nhiều người xem là agent lập trình có gu thẩm mỹ frontend tốt nhất — nó lập luận về giao diện với độ cụ thể khác thường, gọi đúng giá trị hex, khoảng cách và type scale, đồng thời tái cấu trúc UI xuyên suốt một codebase lớn mà không lạc mạch. Nhưng ngay khi mới dùng, nó vẫn có xu hướng trôi về một diện mạo chung chung trừ khi bạn trao cho nó một design system, các skill và những tham chiếu thực. Đây là hướng dẫn thực hành, đầu-cuối về cách dùng Claude Code cho công việc UI, frontend và design-system, cũng như cách nối nó vào một quy trình có cấu trúc với Open Design.", "Bài viết bao quát Claude Code thực chất là gì, vì sao nó mạnh ở frontend, cách thiết lập nó từ con số không, quy trình CLAUDE.md và Skills, vòng đi-về Figma chính thức, so sánh với Codex và Cursor, những cạm bẫy khiến đầu ra AI trông chung chung, và cách Open Design lấp khoảng cách đó như một lớp thiết kế mở, local-first."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Vòng phản hồi thiết kế của Claude Code: agent terminal đưa ra các quyết định thiết kế cụ thể, trình duyệt render UI, và một không gian làm việc, với mũi tên phản hồi quay vòng trở lại", "caption": "Vòng lặp cốt lõi: Claude Code lập luận ra các quyết định UI cụ thể trong terminal, render và kiểm chứng chúng trong một trình duyệt thực, rồi hội tụ theo các tham chiếu của bạn."}, "tocLabel": "Trên trang này", "toc": [{"id": "what-is-claude-code", "label": "Claude Code thực chất là gì"}, {"id": "why-design", "label": "Vì sao Claude Code giỏi thiết kế"}, {"id": "setup", "label": "Thiết lập Claude Code cho thiết kế (từ con số không)"}, {"id": "skills-workflow", "label": "Quy trình CLAUDE.md và Skills"}, {"id": "figma", "label": "Vòng đi-về Claude Code + Figma"}, {"id": "vs", "label": "Claude Code so với Codex so với Cursor"}, {"id": "pitfalls", "label": "Cạm bẫy và diện mạo “AI slop”"}, {"id": "open-design", "label": "Thiết kế với Claude Code trong Open Design"}, {"id": "faq", "label": "Câu hỏi thường gặp"}], "sections": [{"id": "what-is-claude-code", "heading": "Claude Code thực chất là gì", "blocks": [{"kind": "p", "text": "Claude Code là công cụ lập trình theo dạng agent của Anthropic. Nó đọc codebase của bạn, chỉnh sửa tệp tin, chạy lệnh và tích hợp với các công cụ phát triển của bạn — lập kế hoạch, viết và kiểm chứng công việc từ các tác vụ bằng ngôn ngữ tự nhiên, thay vì chỉ tự động hoàn thành từng dòng."}, {"kind": "p", "text": "Nó hiện diện trên nhiều bề mặt cùng chung một engine: một CLI trên terminal, các tiện ích mở rộng IDE cho VS Code, Cursor và JetBrains, một ứng dụng desktop có tính năng xem diff trực quan, và một trải nghiệm web cho các tác vụ chạy dài. Các tệp CLAUDE.md, thiết lập và máy chủ MCP của bạn theo cùng bạn trên tất cả chúng."}, {"kind": "steps", "items": [{"label": "Tệp chỉ dẫn", "body": "Claude Code đọc tệp CLAUDE.md ở thư mục gốc dự án vào đầu mỗi phiên — nơi tự nhiên để mã hóa các quy ước thiết kế, tokens và danh mục kiểm tra review của bạn."}, {"label": "Skills", "body": "Agent Skills đóng gói các chỉ dẫn, script và tài nguyên lặp lại được mà Claude nạp theo nhu cầu, bao gồm skill Frontend Design chính thức của Anthropic dành cho gu thẩm mỹ."}, {"label": "Kế hoạch và subagent", "body": "Nó có thể lập kế hoạch trước khi hành động và sinh ra các subagent làm việc song song trên những phần khác nhau của một tác vụ, giúp giữ cho các đợt tái cấu trúc UI lớn được nhất quán."}]}, {"kind": "ul", "items": ["Nhà cung cấp: Anthropic", "Thông tin xác thực: Khóa API Anthropic (BYOK, qua Console) hoặc gói đăng ký Claude (Pro / Max)", "Bề mặt: CLI terminal, tiện ích VS Code / Cursor / JetBrains, ứng dụng desktop, web"]}]}, {"id": "why-design", "heading": "Vì sao Claude Code giỏi thiết kế", "blocks": [{"kind": "p", "text": "Trong số các agent lập trình, Claude Code nổi tiếng về gu thẩm mỹ trong công việc frontend. Có vài điều giải thích cho điều đó."}, {"kind": "steps", "items": [{"label": "Quyết định cụ thể, không mơ hồ", "body": "Claude Code có xu hướng cam kết với những lựa chọn cụ thể — giá trị hex chính xác, các thang khoảng cách, type ramp và phân cấp component — thay vì nói chung chung, và đó chính là điều phân biệt một giao diện thực với một bản giữ chỗ."}, {"label": "Lập luận hiểu codebase", "body": "Với ngữ cảnh làm việc lớn, nó tái cấu trúc UI trên nhiều tệp cùng lúc, tái dùng các component và tokens sẵn có của bạn thay vì sáng chế lại các style dùng một lần."}, {"label": "Một skill frontend chính thức", "body": "Anthropic cung cấp skill Frontend Design khiến Claude viết ra một định hướng thiết kế trước, và chủ động tránh xa các font hệ thống chung chung cùng những gradient tím dễ đoán."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Sơ đồ thể hiện design system, skill và ảnh tham chiếu hội tụ thành đầu ra thiết kế tốt", "caption": "Gu thẩm mỹ đến từ ba đầu vào mà bạn cung cấp: một design system, một skill và những ảnh tham chiếu thực."}, {"kind": "p", "text": "Bài học cũng chính là điều Anthropic nói về các mô hình của họ: Claude không có gu thẩm mỹ mặc định — để mặc kệ, nó hội tụ về trung tâm thống kê của thiết kế web (Inter, gradient tím, đổ bóng mềm). Nó tạo ra thiết kế tốt khi bạn trao cho nó các ràng buộc. Open Design đóng gói đúng những đầu vào ấy, và đó là lý do hai thứ ăn khớp với nhau (chi tiết bên dưới)."}]}, {"id": "setup", "heading": "Thiết lập Claude Code cho công việc thiết kế, từ con số không", "blocks": [{"kind": "p", "text": "Đây là toàn bộ lộ trình từ một máy sạch đến một Claude Code có thể dựng và kiểm chứng UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Quy trình thiết lập năm bước: cài đặt, xác thực, cấu hình CLAUDE.md, thêm skill, kiểm chứng", "caption": "Trình tự thiết lập: cài đặt → xác thực → cấu hình CLAUDE.md → thêm skill Frontend Design → bật kiểm chứng trên trình duyệt."}, {"kind": "steps", "items": [{"label": "Mã hóa các quy tắc thiết kế của bạn", "body": "Đặt tokens, primitive và quy ước của bạn vào CLAUDE.md rồi trỏ Claude tới đó, để đầu ra khớp với một thương hiệu thay vì mặc định về một diện mạo chung chung."}, {"label": "Thêm kiểm chứng trên trình duyệt", "body": "Nối một MCP Playwright hoặc Chrome để Claude render trong trình duyệt thực và kiểm tra đầu ra trên các breakpoint thay vì chỉ xác nhận build thành công."}]}]}, {"id": "skills-workflow", "heading": "Quy trình CLAUDE.md và Skills", "blocks": [{"kind": "p", "text": "Vòng thiết kế đòn bẩy cao nhất với Claude Code là cấp cho nó các tham chiếu thực cộng với ngữ cảnh thiết kế của bạn, rồi lặp đi lặp lại cho đến khi UI khớp — với CLAUDE.md và Skills mang theo các ràng buộc để bạn không phải giải thích lại chúng ở mỗi prompt."}, {"kind": "ol", "items": ["Bắt đầu từ những tham chiếu hình ảnh rõ ràng nhất bạn có — và đưa vào nhiều trạng thái (desktop và mobile, hover, rỗng, đang tải), không chỉ một ảnh hero.", "Hãy cụ thể trong prompt; prompt mơ hồ tạo ra UI chung chung ngay cả với một agent mạnh.", "Giữ design system và các quy ước của bạn trong CLAUDE.md, và cho Claude biết tokens cùng các primitive chuẩn nằm ở đâu.", "Thêm skill Frontend Design để Claude cam kết với một định hướng thẩm mỹ thực sự trước khi viết code.", "Nối kiểm chứng trên trình duyệt để Claude render, đổi kích thước theo breakpoint và đối chiếu lại với các tham chiếu — không chỉ xác nhận nó build được."]}, {"kind": "p", "text": "Thả một ảnh tham chiếu vào phiên và prompt bằng các ràng buộc cụ thể:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Chạy một dev server song song, giữ prompt nhỏ và tập trung, commit các vòng lặp tốt / hoàn tác các vòng tệ (báo cho Claude biết khi bạn hoàn tác) để mỗi lượt dựng trên một nền sạch. Dùng chế độ plan cho các đợt tái cấu trúc lớn hơn để bạn xem xét cách tiếp cận trước khi bất kỳ tệp nào thay đổi."}]}, {"id": "figma", "heading": "Claude Code + Figma: vòng đi-về thiết kế ↔ code", "blocks": [{"kind": "p", "text": "Vào tháng 2 năm 2026, Anthropic và Figma ra mắt một tích hợp hai chiều hạng nhất qua máy chủ Figma MCP. Nó hoạt động theo cả hai chiều."}, {"kind": "steps", "items": [{"label": "Thiết kế → Code", "body": "Chọn một frame trong Figma hoặc dán một liên kết vào Claude Code, kéo ngữ cảnh thiết kế về, và yêu cầu nó hiện thực thiết kế bằng thư viện component sẵn có của bạn. Code Connect giữ cho đầu ra ăn khớp với các component thực của bạn."}, {"label": "Code → Thiết kế", "body": "Dựng và xem trước một tính năng trong trình duyệt, rồi nói “Send this to Figma” để chụp lại UI đang chạy thành các layer Figma chỉnh sửa được — toàn bộ màn hình hoặc một phần tử được chọn."}]}, {"kind": "p", "text": "Cài đặt một lần với claude plugin install figma@claude-plugins-official (Dev Mode MCP yêu cầu gói Figma trả phí). Cùng một Figma MCP có sẵn cho Claude Code, Codex, Cursor và VS Code — đúng kiểu năng lực di động, đa-agent mà Open Design được tạo ra để điều phối."}]}, {"id": "vs", "heading": "Claude Code so với Codex so với Cursor cho thiết kế", "blocks": [{"kind": "p", "text": "Không có người thắng cuộc duy nhất cho công việc thiết kế — mỗi agent có một thế mạnh khác nhau, và các đội ngũ giàu kinh nghiệm xếp chồng chúng. Một bản tóm tắt công bằng:"}, {"kind": "table", "columns": ["Agent", "Thế mạnh thiết kế", "Phù hợp nhất cho"], "rows": [["Claude Code", "Quyết định thiết kế cụ thể (hex, khoảng cách, kiểu chữ) và lập luận UX hiểu codebase", "Lập luận frontend và tái cấu trúc ngữ cảnh lớn"], ["Codex", "Độ tinh chỉnh thị giác mạnh và khả năng hiểu hình ảnh; build bất đồng bộ trong sandbox", "Build bất đồng bộ được ủy thác và quy tắc AGENTS.md di động"], ["Cursor", "Vòng dựng-và-thấy trực quan với xem trước trực tiếp và chỉnh sửa inline", "Công việc UI lặp-và-quan-sát chặt chẽ bên trong một IDE"]]}, {"kind": "p", "text": "Kết luận lặp đi lặp lại của cộng đồng là gu thẩm mỹ đến từ con người: cả ba đều mặc định về một thẩm mỹ chung chung nếu thiếu skill, tham chiếu và ràng buộc. Đó mới là vấn đề thực cần giải — và nó mang hình hài công cụ thiết kế, chứ không phải hình hài mô hình."}]}, {"id": "pitfalls", "heading": "Cạm bẫy, và cách tránh diện mạo “AI slop”", "blocks": [{"kind": "p", "text": "Ngay cả với danh tiếng về gu thẩm mỹ của Claude Code, phàn nàn phổ biến nhất về thiết kế do AI tạo ra là nó trông chung chung — font Inter, gradient tím trên nền trắng, đổ bóng mềm, bo góc quá khổ, một thẩm mỹ “gào lên rằng AI làm cái này.” Chính Anthropic quy điều này cho sự hội tụ phân phối: các lựa chọn an toàn áp đảo dữ liệu huấn luyện web. Những vấn đề khác được báo cáo gồm bố cục mobile vỡ và phần chỉ dẫn rò rỉ vào nội dung UI."}, {"kind": "steps", "items": [{"label": "Cài skill Frontend Design", "body": "Nó buộc Claude cam kết với một định hướng thực và chủ động tránh các font cùng gradient bị AI lạm dụng."}, {"label": "Bật kiểm chứng trên trình duyệt", "body": "Bắt Claude render và tự kiểm tra trên các breakpoint để bố cục không âm thầm vỡ trên mobile."}, {"label": "Cung cấp tokens và tham chiếu", "body": "Tokens thiết kế thực và ảnh chụp tham chiếu là đòn bẩy lớn nhất duy nhất lên chất lượng đầu ra."}, {"label": "Mã hóa quy tắc trong CLAUDE.md", "body": "Đặt những quy tắc kiểu “không thẻ hero, tối đa hai kiểu chữ, phân cấp ưu tiên thương hiệu” ở nơi agent đọc mỗi lần chạy."}]}, {"kind": "p", "text": "Hãy để ý rằng mọi biện pháp giảm thiểu đều xoay quanh việc trao cho agent một ngữ cảnh thiết kế được tuyển chọn. Duy trì ngữ cảnh đó bằng tay, theo từng dự án, chính là sự cực nhọc mà Open Design loại bỏ."}]}, {"id": "open-design", "heading": "Thiết kế với Claude Code bên trong Open Design", "blocks": [{"kind": "p", "text": "Open Design là lớp thiết kế mã nguồn mở mà quy trình ở trên cứ liên tục đòi hỏi. Nó coi Claude Code như một adapter hạng nhất và bao bọc nó trong một thư viện skill và design-system được tuyển chọn, một render pipeline có cấu trúc và một giao diện desktop cục bộ — để ngữ cảnh thiết kế giúp Claude Code trở nên giỏi đã có sẵn ngay từ lần chạy đầu tiên, chứ không phải ghép lại bằng tay mỗi lần."}, {"kind": "ol", "items": ["Cài đặt Open Design và chọn Claude Code làm agent của bạn.", "Xác thực bằng khóa API Anthropic (BYOK) hoặc gói đăng ký Claude của bạn — thông tin xác thực ở lại trên máy bạn và không bao giờ được trung chuyển qua chúng tôi.", "Chọn một design system và một skill, rồi tạo ra deck, prototype và landing page với gu thẩm mỹ nhất quán.", "Mọi sản phẩm và tệp DESIGN.md đều nằm trong repo của riêng bạn, không phải một đám mây được lưu trữ ở nơi khác."]}, {"kind": "p", "text": "Cùng một agent Claude Code, cùng một khóa — cộng thêm một quy trình thiết kế thực, di động, mã nguồn mở bao quanh nó. Nó local-first và Apache-2.0, nên không gì về công việc hay thông tin xác thực của bạn rời khỏi máy bạn."}]}], "faqTitle": "Câu hỏi thường gặp", "faq": [{"name": "Claude Code có tốt cho công việc thiết kế không?", "text": "Có — nó được nhiều người xem là agent lập trình có gu thẩm mỹ frontend tốt nhất, đưa ra các quyết định cụ thể và hiểu codebase về giá trị hex, khoảng cách và type scale. Với skill Frontend Design, một design system và những ảnh tham chiếu thực trong ngữ cảnh, nó tạo ra UI responsive chất lượng sản xuất và có thể kiểm chứng trong trình duyệt. Thiếu ngữ cảnh đó, nó có xu hướng mặc định về một diện mạo chung chung, và đó chính là khoảng cách mà Open Design lấp đầy."}, {"name": "Tôi có cần gói đăng ký Claude để thiết kế với Claude Code không?", "text": "Bạn có thể dùng hoặc khóa API Anthropic (BYOK, qua Console) hoặc gói đăng ký Claude (Pro / Max). Dù theo cách nào, Open Design cũng không bao giờ trung chuyển thông tin xác thực của bạn — chúng được agent của bạn dùng trực tiếp trên máy bạn."}, {"name": "Claude Code hay Codex cho thiết kế frontend?", "text": "Cả hai đều mạnh. Claude Code nổi tiếng với các quyết định thiết kế cụ thể, hiểu codebase và lập luận frontend; Codex có độ tinh chỉnh thị giác mạnh và xuất sắc ở các bản build được ủy thác, chạy trong sandbox. Nhiều đội dùng cả hai — Open Design cho phép bạn đổi agent mà không thay đổi quy trình thiết kế của mình."}, {"name": "Làm sao kết nối Claude Code với Figma?", "text": "Cài plugin Figma chính thức bằng claude plugin install figma@claude-plugins-official. Sau đó bạn có thể hiện thực các frame Figma thành code bằng ngữ cảnh thiết kế, và đẩy một UI đang chạy ngược lại thành các frame Figma chỉnh sửa được với “Send this to Figma.” Dev Mode MCP yêu cầu một gói Figma trả phí."}, {"name": "Skills và CLAUDE.md là gì?", "text": "CLAUDE.md là một tệp markdown ở thư mục gốc dự án mà Claude Code đọc vào đầu mỗi phiên — nơi để mã hóa các quy ước thiết kế của bạn. Skills đóng gói các chỉ dẫn và tài nguyên lặp lại được mà Claude nạp theo nhu cầu, bao gồm skill Frontend Design chính thức của Anthropic. Open Design cung cấp một thư viện tuyển chọn cả hai để bạn bỏ qua phần thiết lập theo từng dự án."}, {"name": "Làm sao tránh thẩm mỹ “AI slop” chung chung?", "text": "Cài skill Frontend Design, cung cấp tokens thiết kế thực và ảnh chụp tham chiếu, mã hóa quy tắc thương hiệu trong CLAUDE.md, và bật kiểm chứng trên trình duyệt. Open Design cung cấp những thứ này dưới dạng một thư viện tuyển chọn để bạn bỏ qua phần thiết lập theo từng dự án."}, {"name": "Open Design có liên kết với Anthropic không?", "text": "Không. Claude Code là sản phẩm của Anthropic; Open Design là một dự án mã nguồn mở độc lập hỗ trợ nó như một adapter hạng nhất. Claude và Claude Code là thương hiệu của Anthropic."}, {"name": "Tệp tin và thông tin xác thực của tôi có an toàn không?", "text": "Có — Open Design là local-first và Apache-2.0. Tệp tin, sản phẩm và DESIGN.md của bạn ở lại trong repo của riêng bạn, còn thông tin xác thực Anthropic của bạn được agent của bạn dùng trực tiếp, không bao giờ định tuyến qua máy chủ Open Design."}], "ctaTitle": "Thiết kế với Claude Code, theo cách mở.", "ctaBody": "Mang theo khóa Anthropic hoặc gói đăng ký Claude của riêng bạn, giữ mọi tệp tin ở máy, và có một thư viện thiết kế được tuyển chọn bao quanh agent bạn đã dùng.", "ctaActions": [{"label": "Dùng Claude Code trong Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gắn sao trên GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Tải ứng dụng desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Xem tất cả agent được hỗ trợ"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex cho thiết kế — Open Design",
        description: "Cách người ta dùng OpenAI Codex cho thiết kế UI và web — plugin Product Design, tích hợp Figma, các skill frontend — và cách Open Design biến Codex thành một agent thiết kế local-first, mã nguồn mở.",
        breadcrumb: "Codex",
        label: "Agent · Codex",
        heading: "Codex cho thiết kế.",
        lead: "Codex là agent lập trình của OpenAI. Với plugin Product Design và tích hợp Figma, nó đã trở thành một công cụ thiết kế nghiêm túc. Open Design nối Codex vào một quy trình thiết kế mã nguồn mở — khóa OpenAI hoặc gói đăng ký ChatGPT của bạn, tệp tin của bạn, local-first.",
        rich: {"heroCtaLead": "Open Design biến Codex thành một agent thiết kế local-first, mã nguồn mở — khóa OpenAI của bạn, tệp tin của bạn, kèm thư viện skill và design-system được tuyển chọn bao quanh nó.", "heroCtaActions": [{"label": "Dùng Codex trong Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gắn sao trên GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Tải ứng dụng desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex khởi đầu là một bộ sinh code, nhưng trong năm 2026 nó đã trở thành một công cụ đáng tin cậy để thiết kế các giao diện thực — một khi bạn trao cho nó đúng tham chiếu, skill và vòng kiểm chứng. Đây là hướng dẫn thực hành, đầu-cuối về cách dùng Codex cho công việc UI, frontend và design-system, cũng như cách nối nó vào một quy trình thiết kế có cấu trúc với Open Design.", "Bài viết bao quát Codex hôm nay là gì, vì sao nó đột nhiên giỏi frontend, cách thiết lập nó từ con số không, vòng ảnh-chụp-thành-UI, vòng đi-về Figma chính thức, so sánh với Cursor và Claude Code, những cạm bẫy khiến đầu ra AI trông chung chung, và cách Open Design lấp khoảng cách đó như một lớp thiết kế mở, local-first."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Vòng phản hồi thiết kế của Codex: agent terminal, trình duyệt render UI, và một không gian làm việc, với mũi tên phản hồi quay vòng trở lại", "caption": "Vòng lặp cốt lõi: Codex dựng UI trong terminal, render và kiểm chứng nó trong một trình duyệt thực, rồi lặp lại theo các tham chiếu của bạn."}, "tocLabel": "Trên trang này", "toc": [{"id": "what-is-codex", "label": "OpenAI Codex thực chất là gì"}, {"id": "why-design", "label": "Vì sao Codex giờ đây giỏi thiết kế"}, {"id": "setup", "label": "Thiết lập Codex cho thiết kế (từ con số không)"}, {"id": "screenshot-workflow", "label": "Quy trình ảnh-chụp-thành-UI"}, {"id": "figma", "label": "Vòng đi-về Codex + Figma"}, {"id": "vs", "label": "Codex so với Cursor so với Claude Code"}, {"id": "pitfalls", "label": "Cạm bẫy và diện mạo “AI slop”"}, {"id": "open-design", "label": "Thiết kế với Codex trong Open Design"}, {"id": "faq", "label": "Câu hỏi thường gặp"}], "sections": [{"id": "what-is-codex", "heading": "OpenAI Codex thực chất là gì (và không phải là gì)", "blocks": [{"kind": "p", "text": "Trước hết, một sự phân biệt làm vấp ngã gần như tất cả những ai tìm kiếm “Codex.” OpenAI Codex nguyên gốc là một mô hình hoàn thành code năm 2021 từng vận hành GitHub Copilot thời đầu và bị ngừng hỗ trợ năm 2023. Đó không phải điều trang này nói tới. Codex ngày nay là công cụ lập trình theo dạng agent của OpenAI — nó lập kế hoạch, viết, chạy và kiểm chứng code từ các tác vụ bằng ngôn ngữ tự nhiên."}, {"kind": "p", "text": "Codex hiện đại hiện diện trên bốn bề mặt: một CLI terminal (được viết lại bằng Rust, cấp phép Apache-2.0), một tiện ích IDE cho VS Code, Cursor và Windsurf, một trải nghiệm cloud/web cho các tác vụ bất đồng bộ được ủy thác, và một ứng dụng desktop có trình duyệt trong ứng dụng và Computer Use."}, {"kind": "steps", "items": [{"label": "Mô hình mặc định", "body": "Tính đến giữa năm 2026, mô hình được khuyến nghị là gpt-5.5, với gpt-5.4 là mô hình mà OpenAI huấn luyện rõ ràng cho frontend và computer use."}, {"label": "Tệp chỉ dẫn", "body": "Codex đọc một tệp AGENTS.md trong dự án của bạn (một chuẩn liên-công-cụ) để lấy các quy tắc dự án — nơi tự nhiên để mã hóa các quy ước thiết kế của bạn."}, {"label": "Sandbox", "body": "Nó chạy trong một sandbox ở cấp kernel (mặc định workspace-write), nên một agent đang chỉnh sửa UI của bạn không thể lang thang ra ngoài dự án."}]}, {"kind": "ul", "items": ["Nhà cung cấp: OpenAI", "Thông tin xác thực: Khóa API OpenAI (BYOK) hoặc gói đăng ký ChatGPT (Free / Go / Plus / Pro / Business / Enterprise)", "Giấy phép của CLI: Apache-2.0, mã nguồn mở"]}]}, {"id": "why-design", "heading": "Vì sao Codex giờ đây giỏi thiết kế", "blocks": [{"kind": "p", "text": "Ba điều hội tụ vào đầu năm 2026 khiến Codex trở thành một công cụ thiết kế thực thụ thay vì một bộ sinh code chung chung."}, {"kind": "steps", "items": [{"label": "Một mô hình được huấn luyện cho frontend", "body": "OpenAI ra mắt GPT-5.4, mô hình dòng chính đầu tiên của họ được huấn luyện cho frontend và computer use, với khả năng hiểu hình ảnh tốt hơn nhiều xuyên suốt quy trình thiết kế và tự-kiểm-chứng mạnh hơn. Nó thậm chí có thể tạo mood board và các phương án thị giác trước khi cam kết với tài sản cuối cùng."}, {"label": "Một skill frontend chính thức", "body": "Danh mục openai/skills cung cấp một frontend-skill được tuyển chọn nhằm thực thi gu thẩm mỹ thực: bố cục không thẻ, hero tràn viền, phân cấp ưu tiên thương hiệu, chuyển động tiết chế, tối đa hai kiểu chữ và một màu nhấn — và khiến Codex viết ra một luận đề thị giác trước khi dựng."}, {"label": "Kiểm chứng trên trình duyệt", "body": "Với skill Playwright, Codex mở một trình duyệt thực, đổi kích thước theo breakpoint, và đối chiếu đầu ra của mình với tham chiếu thay vì chỉ kiểm tra rằng build thành công."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Sơ đồ thể hiện design system, skill và ảnh tham chiếu hội tụ thành đầu ra thiết kế tốt", "caption": "Gu thẩm mỹ đến từ ba đầu vào mà bạn cung cấp: một design system, một skill và những ảnh tham chiếu thực."}, {"kind": "p", "text": "Bài học đằng sau cả ba: Codex không có gu thẩm mỹ mặc định. Nó tạo ra thiết kế tốt khi bạn trao cho nó các ràng buộc — một design system, một skill thẩm mỹ và những tham chiếu cụ thể. Open Design đóng gói đúng những đầu vào ấy, và đó là lý do hai thứ ăn khớp với nhau (chi tiết bên dưới)."}]}, {"id": "setup", "heading": "Thiết lập Codex cho công việc thiết kế, từ con số không", "blocks": [{"kind": "p", "text": "Đây là toàn bộ lộ trình từ một máy sạch đến một Codex có thể dựng và kiểm chứng UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Quy trình thiết lập năm bước: cài đặt, xác thực, cấu hình, cài skill, kiểm chứng", "caption": "Trình tự thiết lập: cài đặt → xác thực → cấu hình AGENTS.md → cài skill frontend → bật kiểm chứng trên trình duyệt."}, {"kind": "steps", "items": [{"label": "Mã hóa các quy tắc thiết kế của bạn", "body": "Đặt tokens, primitive và quy ước của bạn vào AGENTS.md hoặc một DESIGN.md rồi trỏ Codex tới đó, để đầu ra khớp với một thương hiệu thay vì mặc định về một diện mạo chung chung."}, {"label": "Chọn đúng mức reasoning", "body": "OpenAI lưu ý rằng các mức reasoning thấp-đến-trung bình thường tạo ra kết quả frontend mạnh hơn so với mức cao nhất."}]}]}, {"id": "screenshot-workflow", "heading": "Quy trình ảnh-chụp-thành-UI", "blocks": [{"kind": "p", "text": "Vòng thiết kế đòn bẩy cao nhất với Codex là biến một ảnh tham chiếu thành UI hoạt động được, responsive và lặp đi lặp lại cho đến khi nó khớp. Chính hướng dẫn của OpenAI cô đọng thành năm bước."}, {"kind": "ol", "items": ["Bắt đầu từ những tham chiếu hình ảnh rõ ràng nhất bạn có — và đưa vào nhiều trạng thái (desktop và mobile, hover, rỗng, đang tải), không chỉ một ảnh hero.", "Hãy cụ thể trong prompt; prompt mơ hồ tạo ra UI chung chung.", "Chuẩn bị một design system và cho Codex biết tokens cùng các primitive chuẩn nằm ở đâu.", "Bật skill tương tác Playwright để Codex render trong một trình duyệt thực và đổi kích thước theo breakpoint.", "Lặp lại bằng cách cho Codex đối chiếu phần hiện thực của nó với các ảnh chụp — không chỉ xác nhận nó build được."]}, {"kind": "p", "text": "Cấp ảnh bằng cách kéo một ảnh chụp vào terminal hoặc bằng cờ image, rồi prompt với các ràng buộc cụ thể:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Chạy một dev server ở terminal thứ hai, giữ prompt nhỏ và tập trung, commit các vòng lặp tốt / hoàn tác các vòng tệ (báo cho Codex biết khi bạn hoàn tác) để mỗi lượt dựng trên một nền sạch."}]}, {"id": "figma", "heading": "Codex + Figma: vòng đi-về thiết kế ↔ code", "blocks": [{"kind": "p", "text": "Vào tháng 2 năm 2026, OpenAI và Figma công bố một quan hệ đối tác chính thức, biến bản beta Figma MCP trước đó thành một tích hợp hai chiều hạng nhất. Nó hoạt động theo cả hai chiều."}, {"kind": "steps", "items": [{"label": "Thiết kế → Code", "body": "Sao chép “link to selection” của một frame trong Figma, dán nó vào Codex với get_design_context, và yêu cầu nó hiện thực thiết kế bằng thư viện component sẵn có của bạn."}, {"label": "Code → Thiết kế", "body": "Công cụ generate_figma_design (“Code to Canvas”) biến một UI sống động, đang chạy ngược lại thành các frame Figma chỉnh sửa được — toàn bộ màn hình, một phần tử được chọn, hoặc cả một tệp."}]}, {"kind": "p", "text": "Figma MCP chạy như một máy chủ từ xa và được miễn khỏi giới hạn tần suất. Thêm nó một lần và nó có sẵn cho Codex, Claude Code, Cursor, VS Code và nhiều hơn nữa — đúng kiểu năng lực di động, đa-agent mà Open Design được tạo ra để điều phối."}]}, {"id": "vs", "heading": "Codex so với Cursor so với Claude Code cho thiết kế", "blocks": [{"kind": "p", "text": "Không có người thắng cuộc duy nhất cho công việc thiết kế — mỗi agent có một thế mạnh khác nhau, và các đội ngũ giàu kinh nghiệm xếp chồng chúng. Một bản tóm tắt công bằng:"}, {"kind": "table", "columns": ["Agent", "Thế mạnh thiết kế", "Phù hợp nhất cho"], "rows": [["Codex", "Độ tinh chỉnh thị giác mạnh sau GPT-5.4 + frontend-skill; khả năng hiểu hình ảnh", "Build bất đồng bộ được ủy thác, chạy trong sandbox, quy tắc AGENTS.md di động"], ["Cursor", "Vòng dựng-và-thấy trực quan với xem trước trực tiếp và chỉnh sửa inline", "Công việc UI lặp-và-quan-sát chặt chẽ bên trong một IDE"], ["Claude Code", "Quyết định thiết kế cụ thể (hex, khoảng cách, kiểu chữ) và UX hiểu codebase", "Lập luận frontend và tái cấu trúc ngữ cảnh lớn"]]}, {"kind": "p", "text": "Kết luận lặp đi lặp lại của cộng đồng là gu thẩm mỹ đến từ con người: cả ba đều mặc định về một thẩm mỹ chung chung nếu thiếu skill, tham chiếu và ràng buộc. Đó mới là vấn đề thực cần giải — và nó mang hình hài công cụ thiết kế, chứ không phải hình hài mô hình."}]}, {"id": "pitfalls", "heading": "Cạm bẫy, và cách tránh diện mạo “AI slop”", "blocks": [{"kind": "p", "text": "Phàn nàn phổ biến nhất về thiết kế do Codex tạo ra là nó trông chung chung — gradient mềm, panel lơ lửng, bo góc quá khổ, đổ bóng kịch tính, một cảm giác Inter-và-tím “gào lên rằng AI làm cái này.” Những vấn đề khác được báo cáo gồm bố cục mobile vỡ, phần chỉ dẫn rò rỉ vào nội dung UI, và chạm giới hạn sử dụng nhanh chóng."}, {"kind": "steps", "items": [{"label": "Cài một skill frontend", "body": "Một skill thẩm mỹ được tuyển chọn buộc Codex cam kết với một định hướng thực thay vì diện mạo mặc định."}, {"label": "Bật kiểm chứng Playwright", "body": "Bắt Codex render và tự kiểm tra trên các breakpoint để bố cục không âm thầm vỡ trên mobile."}, {"label": "Cung cấp tokens và tham chiếu", "body": "Tokens thiết kế thực và ảnh chụp tham chiếu là đòn bẩy lớn nhất duy nhất lên chất lượng đầu ra."}, {"label": "Mã hóa quy tắc trong AGENTS.md", "body": "Đặt những quy tắc kiểu “không thẻ hero, tối đa hai kiểu chữ, phân cấp ưu tiên thương hiệu” ở nơi agent đọc mỗi lần chạy."}]}, {"kind": "p", "text": "Hãy để ý rằng mọi biện pháp giảm thiểu đều xoay quanh việc trao cho agent một ngữ cảnh thiết kế được tuyển chọn. Duy trì ngữ cảnh đó bằng tay, theo từng dự án, chính là sự cực nhọc mà Open Design loại bỏ."}]}, {"id": "open-design", "heading": "Thiết kế với Codex bên trong Open Design", "blocks": [{"kind": "p", "text": "Open Design là lớp thiết kế mã nguồn mở mà quy trình ở trên cứ liên tục đòi hỏi. Nó coi Codex như một adapter hạng nhất và bao bọc nó trong một thư viện skill và design-system được tuyển chọn, một render pipeline có cấu trúc và một giao diện desktop cục bộ — để ngữ cảnh thiết kế giúp Codex trở nên giỏi đã có sẵn ngay từ lần chạy đầu tiên, chứ không phải ghép lại bằng tay mỗi lần."}, {"kind": "ol", "items": ["Cài đặt Open Design và chọn Codex làm agent của bạn.", "Xác thực bằng khóa API OpenAI (BYOK) hoặc gói đăng ký ChatGPT của bạn — thông tin xác thực ở lại trên máy bạn và không bao giờ được trung chuyển qua chúng tôi.", "Chọn một design system và một skill, rồi tạo ra deck, prototype và landing page với gu thẩm mỹ nhất quán.", "Mọi sản phẩm và tệp DESIGN.md đều nằm trong repo của riêng bạn, không phải một đám mây được lưu trữ ở nơi khác."]}, {"kind": "p", "text": "Cùng một agent Codex, cùng một khóa — cộng thêm một quy trình thiết kế thực, di động, mã nguồn mở bao quanh nó. Nó local-first và Apache-2.0, nên không gì về công việc hay thông tin xác thực của bạn rời khỏi máy bạn."}]}], "faqTitle": "Câu hỏi thường gặp", "faq": [{"name": "OpenAI Codex có thực sự làm được công việc thiết kế không?", "text": "Có — với một skill frontend, một design system và những ảnh tham chiếu thực trong ngữ cảnh, Codex (đặc biệt trên GPT-5.4) tạo ra UI responsive chất lượng sản xuất và có thể kiểm chứng trong trình duyệt. Thiếu ngữ cảnh đó, nó có xu hướng mặc định về một diện mạo chung chung, và đó chính là khoảng cách mà Open Design lấp đầy."}, {"name": "Đây có phải plugin Product Design của OpenAI Codex không?", "text": "Không. Open Design là một dự án mã nguồn mở độc lập tích hợp Codex như một agent. Nó bổ sung cho bộ công cụ riêng của OpenAI bằng một thư viện skill và design-system mở, local-first."}, {"name": "Tôi có cần gói đăng ký ChatGPT để thiết kế với Codex không?", "text": "Bạn có thể dùng hoặc khóa API OpenAI (BYOK) hoặc gói đăng ký ChatGPT của bạn. Đăng nhập ChatGPT thường cho giới hạn hào phóng hơn; dù theo cách nào, Open Design cũng không bao giờ trung chuyển thông tin xác thực của bạn."}, {"name": "Codex hay Claude Code cho thiết kế frontend?", "text": "Cả hai đều mạnh. Claude Code nổi tiếng với các quyết định thiết kế cụ thể, hiểu codebase; Codex có độ tinh chỉnh thị giác mạnh sau GPT-5.4 và xuất sắc ở các bản build được ủy thác, chạy trong sandbox. Nhiều đội dùng cả hai — Open Design cho phép bạn đổi agent mà không thay đổi quy trình thiết kế của mình."}, {"name": "Làm sao kết nối Codex với Figma?", "text": "Thêm máy chủ Figma MCP chính thức (codex mcp add figma --url https://mcp.figma.com/mcp). Sau đó bạn có thể hiện thực các frame Figma thành code với get_design_context và đẩy một UI đang chạy ngược lại thành các frame Figma chỉnh sửa được với generate_figma_design."}, {"name": "Làm sao tránh thẩm mỹ “AI slop” chung chung?", "text": "Cài một skill frontend, cung cấp tokens thiết kế thực và ảnh chụp tham chiếu, mã hóa quy tắc thương hiệu trong AGENTS.md, và bật kiểm chứng Playwright. Open Design cung cấp những thứ này dưới dạng một thư viện tuyển chọn để bạn bỏ qua phần thiết lập theo từng dự án."}, {"name": "Open Design có liên kết với OpenAI không?", "text": "Không. Codex là sản phẩm của OpenAI; Open Design là một dự án mã nguồn mở độc lập hỗ trợ nó như một adapter hạng nhất. OpenAI và Codex là thương hiệu của OpenAI."}, {"name": "Tệp tin và thông tin xác thực của tôi có an toàn không?", "text": "Có — Open Design là local-first. Tệp tin, sản phẩm và DESIGN.md của bạn ở lại trong repo của riêng bạn, còn thông tin xác thực OpenAI của bạn được agent của bạn dùng trực tiếp, không bao giờ định tuyến qua máy chủ Open Design."}], "ctaTitle": "Thiết kế với Codex, theo cách mở.", "ctaBody": "Mang theo khóa OpenAI của riêng bạn, giữ mọi tệp tin ở máy, và có một thư viện thiết kế được tuyển chọn bao quanh agent bạn đã dùng.", "ctaActions": [{"label": "Dùng Codex trong Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gắn sao trên GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Tải ứng dụng desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Xem tất cả agent được hỗ trợ"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor cho nhà thiết kế — Open Design",
        description: "Cách các nhà thiết kế dùng Cursor cho thiết kế UI và web — Design Mode, Figma-to-code, Figma MCP — và cách Open Design biến Cursor thành một agent thiết kế local-first, mã nguồn mở.",
        breadcrumb: "Cursor",
        label: "Agent · Cursor",
        heading: "Cursor cho nhà thiết kế.",
        lead: "Cursor là trình soạn code AI, giờ đây có Design Mode trực quan. Các nhà thiết kế dùng nó để chỉnh sửa UI bằng cách trỏ và vẽ, và để biến Figma thành code. Open Design cắm Cursor Agent vào một quy trình thiết kế mã nguồn mở giữ tệp tin của bạn ở máy.",
        rich: {"heroCtaLead": "Open Design biến Cursor thành một agent thiết kế local-first, mã nguồn mở — tài khoản Cursor hoặc khóa mô hình của bạn, tệp tin của bạn, kèm thư viện skill và design-system được tuyển chọn bao quanh nó.", "heroCtaActions": [{"label": "Dùng Cursor trong Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gắn sao trên GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Tải ứng dụng desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor là trình soạn code lấy AI làm trọng tâm, đã biến “dựng nó và xem nó render” thành cách mặc định để ship UI. Với chế độ Agent, chỉnh sửa inline, xem trước trong trình soạn và Figma qua MCP, nó đã trở thành một công cụ thiết kế đích thực — một khi bạn trao cho nó đúng tham chiếu, quy tắc và một vòng kiểm chứng. Đây là hướng dẫn thực hành, đầu-cuối về cách dùng Cursor cho công việc UI, frontend và design-system, cũng như cách nối nó vào một quy trình thiết kế có cấu trúc với Open Design.", "Bài viết bao quát Cursor thực chất là gì, vì sao vòng lặp-và-quan-sát chặt chẽ của nó tốt cho thiết kế, cách thiết lập nó từ con số không, vòng ảnh-chụp-và-xem-trước-thành-UI, vòng đi-về Figma qua MCP, so sánh với Codex và Claude Code, những cạm bẫy khiến đầu ra AI trông chung chung, và cách Open Design lấp khoảng cách đó như một lớp thiết kế mở, local-first."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Sự hội tụ thiết kế của Cursor: trình soạn ở bên trái, một hub skill và design-system được tuyển chọn ở giữa với biểu tượng Cursor ở trung tâm, và một UI đã render ở bên phải", "caption": "Ý tưởng cốt lõi: Cursor chỉnh sửa và render UI trong trình soạn, trong khi một hub thiết kế được tuyển chọn cấp cho nó hệ thống, skill và tham chiếu khiến đầu ra trông có chủ đích."}, "tocLabel": "Trên trang này", "toc": [{"id": "what-is-cursor", "label": "Cursor thực chất là gì"}, {"id": "why-design", "label": "Vì sao Cursor giỏi thiết kế"}, {"id": "setup", "label": "Thiết lập Cursor cho thiết kế (từ con số không)"}, {"id": "preview-workflow", "label": "Quy trình xem-trước-thành-UI"}, {"id": "figma", "label": "Cursor + Figma qua MCP"}, {"id": "vs", "label": "Cursor so với Codex so với Claude Code"}, {"id": "pitfalls", "label": "Cạm bẫy và diện mạo “AI slop”"}, {"id": "open-design", "label": "Thiết kế với Cursor trong Open Design"}, {"id": "faq", "label": "Câu hỏi thường gặp"}], "sections": [{"id": "what-is-cursor", "heading": "Cursor thực chất là gì", "blocks": [{"kind": "p", "text": "Cursor là một trình soạn code lấy AI làm trọng tâm do Anysphere xây dựng. Nó là một bản fork của VS Code, nên giữ lại trình soạn, các tiện ích mở rộng và phím tắt quen thuộc, nhưng dựng lại quy trình quanh một agent AI có thể đọc toàn bộ dự án, chỉnh sửa nhiều tệp, chạy lệnh và lặp đi lặp lại cùng bạn trong vòng lặp."}, {"kind": "p", "text": "Với công việc thiết kế, các bề mặt quan trọng là chế độ Agent (bạn mô tả một kết quả và Cursor lập kế hoạch cùng chỉnh sửa xuyên các tệp), chỉnh sửa inline và hoàn thành bằng Tab cho các tinh chỉnh nhanh, một xem trước / trình duyệt trong trình soạn để bạn thấy UI đang chạy mà không rời cửa sổ, và hỗ trợ MCP cho phép nó kéo về ngữ cảnh bên ngoài như một tệp Figma sống động."}, {"kind": "steps", "items": [{"label": "Quy tắc dự án", "body": "Cursor đọc các tệp chỉ dẫn dự án — các quy tắc `.mdc` được phiên bản hóa dưới `.cursor/rules`, và một `AGENTS.md` đơn giản — nên bạn có thể mã hóa các quy ước thiết kế ở nơi agent đọc mỗi lần chạy."}, {"label": "Mô hình", "body": "Cursor linh hoạt về mô hình: nó đi kèm các mô hình tiên phong qua gói đăng ký của bạn và cũng hỗ trợ mang theo khóa mô hình của riêng bạn, nên bạn chọn engine đứng sau cùng một quy trình trình soạn."}, {"label": "MCP", "body": "Nó nói được Model Context Protocol, nên các máy chủ bên ngoài — liên quan nhất là máy chủ Figma MCP — trở thành ngữ cảnh hạng nhất cho agent."}]}, {"kind": "ul", "items": ["Nhà cung cấp: Anysphere", "Thông tin xác thực: Tài khoản / gói đăng ký Cursor (Hobby / Pro / Business) hoặc khóa mô hình của riêng bạn (BYOK)", "Hình thức: Trình soạn code lấy AI làm trọng tâm (bản fork VS Code) với một agent và xem trước trong trình soạn"]}]}, {"id": "why-design", "heading": "Vì sao Cursor giỏi thiết kế", "blocks": [{"kind": "p", "text": "Lợi thế thiết kế của Cursor không phải một tính năng đơn lẻ — đó là độ chặt chẽ của vòng dựng-và-thấy. Ba điều khiến nó cảm giác như một công cụ thiết kế thay vì một bộ sinh code chung chung."}, {"kind": "steps", "items": [{"label": "Một vòng lặp-và-quan-sát chặt chẽ", "body": "Bạn prompt, Cursor chỉnh sửa xuyên các tệp, và xem trước trong trình soạn render kết quả ngay lập tức — nên bạn điều chỉnh khoảng cách, phân cấp và chuyển động trong vài giây thay vì đi-về qua một terminal và trình duyệt riêng."}, {"label": "Chỉnh sửa thị giác trực tiếp", "body": "Ngoài chat, Cursor cho phép bạn chọn phần tử trong xem trước và nhích các style, nên những chỉnh sửa thị giác nhỏ giống như sửa thiết kế hơn là khảo cổ code."}, {"label": "Quy tắc dự án và ngữ cảnh MCP", "body": "Với `.cursor/rules` (hoặc `AGENTS.md`) và máy chủ Figma MCP, agent làm việc dựa trên tokens, component và đặc tả thiết kế thực của bạn thay vì đoán mò."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Sơ đồ thể hiện design system, skill và ảnh tham chiếu hội tụ thành đầu ra thiết kế tốt", "caption": "Gu thẩm mỹ đến từ ba đầu vào mà bạn cung cấp: một design system, một skill và những ảnh tham chiếu thực."}, {"kind": "p", "text": "Bài học cũng chính là điều mọi agent đều dạy: Cursor không có gu thẩm mỹ mặc định. Nó tạo ra thiết kế tốt khi bạn trao cho nó các ràng buộc — một design system, một skill thẩm mỹ và những tham chiếu cụ thể. Open Design đóng gói đúng những đầu vào ấy, và đó là lý do hai thứ ăn khớp với nhau (chi tiết bên dưới)."}]}, {"id": "setup", "heading": "Thiết lập Cursor cho công việc thiết kế, từ con số không", "blocks": [{"kind": "p", "text": "Đây là toàn bộ lộ trình từ một máy sạch đến một Cursor có thể dựng, xem trước và kiểm chứng UI theo design system của bạn."}, {"kind": "ol", "items": ["Cài Cursor từ cursor.com và đăng nhập bằng tài khoản Cursor của bạn, hoặc cấu hình khóa mô hình của riêng bạn (BYOK) trong Settings.", "Mở dự án của bạn và chọn một mô hình trong panel chat / Agent.", "Thêm quy tắc dự án: tạo `.cursor/rules/*.mdc` cho các quy ước có cấu trúc, được giới hạn theo glob, hoặc một `AGENTS.md` đơn giản cho các chỉ dẫn dễ đọc.", "Kết nối máy chủ Figma MCP (tùy chọn) để agent có thể đọc ngữ cảnh thiết kế sống động.", "Chạy dev server của bạn và dùng xem trước trong trình soạn để thấy và kiểm chứng UI khi bạn lặp đi lặp lại."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Quy trình thiết lập năm bước: cài đặt, xác thực, cấu hình quy tắc, thêm skill, kiểm chứng", "caption": "Trình tự thiết lập: cài đặt → xác thực → cấu hình quy tắc dự án → thêm một skill → bật kiểm chứng bằng xem trước."}, {"kind": "p", "text": "Một tệp quy tắc dự án tối giản khiến agent thiết kế theo một thương hiệu thay vì mặc định về một diện mạo chung chung. Đặt nó ở nơi Cursor đọc mỗi lần chạy:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Mã hóa các quy tắc thiết kế của bạn", "body": "Đặt tokens, primitive và quy ước của bạn vào `.cursor/rules` hoặc `AGENTS.md` rồi trỏ Cursor tới đó, để đầu ra khớp với một thương hiệu thay vì mặc định về một diện mạo chung chung."}, {"label": "Giữ prompt nhỏ", "body": "Vòng lặp chặt chẽ của Cursor thưởng cho những yêu cầu tập trung — lặp từng component hoặc trạng thái một và quan sát xem trước giữa các lượt."}]}]}, {"id": "preview-workflow", "heading": "Quy trình xem-trước-thành-UI", "blocks": [{"kind": "p", "text": "Vòng thiết kế đòn bẩy cao nhất với Cursor là biến một tham chiếu thành UI hoạt động được, responsive và lặp đi lặp lại trong trình soạn cho đến khi nó khớp — quan sát xem trước trực tiếp suốt quá trình thay vì đoán mò."}, {"kind": "ol", "items": ["Bắt đầu từ những tham chiếu hình ảnh rõ ràng nhất bạn có — và đưa vào nhiều trạng thái (desktop và mobile, hover, rỗng, đang tải), không chỉ một ảnh hero.", "Hãy cụ thể trong prompt; prompt mơ hồ tạo ra UI chung chung.", "Chuẩn bị một design system và cho Cursor biết tokens cùng các primitive chuẩn nằm ở đâu.", "Giữ xem trước trong trình soạn luôn mở và dev server của bạn luôn chạy để mỗi chỉnh sửa render ngay lập tức ở các breakpoint bạn quan tâm.", "Lặp lại bằng cách đối chiếu UI đã render với các tham chiếu — và dùng chọn phần tử trực tiếp trong xem trước cho các chỉnh sửa thị giác nhỏ."]}, {"kind": "p", "text": "Cấp tham chiếu bằng cách đính một ảnh vào chat, rồi prompt với các ràng buộc cụ thể:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Commit các vòng lặp tốt và hoàn tác các vòng tệ (báo cho Cursor biết khi bạn hoàn tác) để mỗi lượt dựng trên một nền sạch — chính kỷ luật giữ cho bất kỳ vòng lặp agent nào khỏi trôi dạt."}]}, {"id": "figma", "heading": "Cursor + Figma: thiết kế ↔ code qua MCP", "blocks": [{"kind": "p", "text": "Cursor kết nối với Figma qua máy chủ Figma MCP chính thức, thứ cấp cho agent quyền truy cập có cấu trúc vào một tệp Figma sống động thay vì một ảnh chụp phẳng. Điều đó loại bỏ sự đoán mò khỏi quá trình bàn giao."}, {"kind": "steps", "items": [{"label": "Thiết kế → Code", "body": "Sao chép liên kết của một frame trong Figma, dán nó vào Cursor, và yêu cầu nó hiện thực thiết kế. Máy chủ MCP phơi bày ngữ cảnh thiết kế thực — component, biến, dữ liệu bố cục, tokens — nên code sinh ra khớp với nguồn thay vì xấp xỉ nó."}, {"label": "Giữ sự ăn khớp", "body": "Với design tokens, style và component được dùng nhất quán trong Figma (và Code Connect ở nơi có sẵn), đầu ra của Cursor vẫn ánh xạ tới design system thực của bạn thay vì sáng chế lại các primitive."}]}, {"kind": "p", "text": "Thiết lập máy chủ Figma MCP từ xa một lần và nó có sẵn cho Cursor như ngữ cảnh hạng nhất. Vì MCP là một chuẩn mở, cùng một máy chủ có thể tái dùng trên Cursor, Claude Code, Codex và VS Code — đúng kiểu năng lực di động, đa-agent mà Open Design được tạo ra để điều phối."}]}, {"id": "vs", "heading": "Cursor so với Codex so với Claude Code cho thiết kế", "blocks": [{"kind": "p", "text": "Không có người thắng cuộc duy nhất cho công việc thiết kế — mỗi agent có một thế mạnh khác nhau, và các đội ngũ giàu kinh nghiệm xếp chồng chúng. Một bản tóm tắt công bằng:"}, {"kind": "table", "columns": ["Agent", "Thế mạnh thiết kế", "Phù hợp nhất cho"], "rows": [["Cursor", "Vòng dựng-và-thấy trực quan với xem trước trực tiếp trong trình soạn và chỉnh sửa phần tử trực tiếp", "Công việc UI lặp-và-quan-sát chặt chẽ bên trong một IDE"], ["Codex", "Độ tinh chỉnh thị giác mạnh với một skill frontend; khả năng hiểu hình ảnh và chạy trong sandbox", "Build bất đồng bộ được ủy thác và quy tắc AGENTS.md di động"], ["Claude Code", "Quyết định thiết kế cụ thể (hex, khoảng cách, kiểu chữ) và UX hiểu codebase", "Lập luận frontend và tái cấu trúc ngữ cảnh lớn"]]}, {"kind": "p", "text": "Kết luận lặp đi lặp lại của cộng đồng là gu thẩm mỹ đến từ con người: cả ba đều mặc định về một thẩm mỹ chung chung nếu thiếu skill, tham chiếu và ràng buộc. Đó mới là vấn đề thực cần giải — và nó mang hình hài công cụ thiết kế, chứ không phải hình hài mô hình."}]}, {"id": "pitfalls", "heading": "Cạm bẫy, và cách tránh diện mạo “AI slop”", "blocks": [{"kind": "p", "text": "Phàn nàn phổ biến nhất về thiết kế do Cursor tạo ra là nó trông chung chung — gradient mềm, panel lơ lửng, bo góc quá khổ, đổ bóng kịch tính, một cảm giác Inter-và-tím “gào lên rằng AI làm cái này.” Những vấn đề khác được báo cáo gồm bố cục vỡ trên mobile và phần chỉ dẫn rò rỉ vào nội dung UI."}, {"kind": "steps", "items": [{"label": "Thêm một skill thiết kế", "body": "Một skill thẩm mỹ được tuyển chọn buộc Cursor cam kết với một định hướng thực thay vì diện mạo mặc định."}, {"label": "Dùng xem trước để kiểm chứng", "body": "Render và tự kiểm tra trên các breakpoint trong xem trước trong trình soạn để bố cục không âm thầm vỡ trên mobile."}, {"label": "Cung cấp tokens và tham chiếu", "body": "Tokens thiết kế thực và ảnh chụp tham chiếu là đòn bẩy lớn nhất duy nhất lên chất lượng đầu ra."}, {"label": "Mã hóa quy tắc trong `.cursor/rules`", "body": "Đặt những quy tắc kiểu “không thẻ hero, tối đa hai kiểu chữ, phân cấp ưu tiên thương hiệu” ở nơi agent đọc mỗi lần chạy."}]}, {"kind": "p", "text": "Hãy để ý rằng mọi biện pháp giảm thiểu đều xoay quanh việc trao cho agent một ngữ cảnh thiết kế được tuyển chọn. Duy trì ngữ cảnh đó bằng tay, theo từng dự án, chính là sự cực nhọc mà Open Design loại bỏ."}]}, {"id": "open-design", "heading": "Thiết kế với Cursor bên trong Open Design", "blocks": [{"kind": "p", "text": "Open Design là lớp thiết kế mã nguồn mở mà quy trình ở trên cứ liên tục đòi hỏi. Nó coi Cursor như một adapter hạng nhất và bao bọc nó trong một thư viện skill và design-system được tuyển chọn, một render pipeline có cấu trúc và một giao diện desktop cục bộ — để ngữ cảnh thiết kế giúp Cursor trở nên giỏi đã có sẵn ngay từ lần chạy đầu tiên, chứ không phải ghép lại bằng tay mỗi lần."}, {"kind": "ol", "items": ["Cài đặt Open Design và chọn Cursor làm agent của bạn.", "Xác thực bằng tài khoản Cursor hoặc khóa mô hình của riêng bạn (BYOK) — thông tin xác thực ở lại trên máy bạn và không bao giờ được trung chuyển qua chúng tôi.", "Chọn một design system và một skill, rồi tạo ra deck, prototype và landing page với gu thẩm mỹ nhất quán.", "Mọi sản phẩm và tệp DESIGN.md đều nằm trong repo của riêng bạn, không phải một đám mây được lưu trữ ở nơi khác."]}, {"kind": "p", "text": "Cùng một agent Cursor, cùng một khóa — cộng thêm một quy trình thiết kế thực, di động, mã nguồn mở bao quanh nó. Nó local-first và Apache-2.0, nên không gì về công việc hay thông tin xác thực của bạn rời khỏi máy bạn."}]}], "faqTitle": "Câu hỏi thường gặp", "faq": [{"name": "Cursor có thực sự làm được công việc thiết kế không?", "text": "Có — với một skill thiết kế, một design system và những ảnh tham chiếu thực trong ngữ cảnh, Cursor tạo ra UI responsive chất lượng sản xuất, và xem trước trong trình soạn của nó cho phép bạn kiểm chứng và tinh chỉnh nó một cách trực quan. Thiếu ngữ cảnh đó, nó có xu hướng mặc định về một diện mạo chung chung, và đó chính là khoảng cách mà Open Design lấp đầy."}, {"name": "Đây có phải sản phẩm Cursor chính thức không?", "text": "Không. Open Design là một dự án mã nguồn mở độc lập tích hợp Cursor như một agent. Nó bổ sung cho Cursor bằng một thư viện skill và design-system mở, local-first."}, {"name": "Tôi có cần gói đăng ký Cursor để thiết kế với Cursor không?", "text": "Bạn có thể dùng một tài khoản / gói đăng ký Cursor hoặc mang theo khóa mô hình của riêng bạn (BYOK). Dù theo cách nào, Open Design cũng không bao giờ trung chuyển thông tin xác thực của bạn — chúng được agent của bạn dùng trực tiếp."}, {"name": "Cursor hay Claude Code cho thiết kế frontend?", "text": "Cả hai đều mạnh. Claude Code nổi tiếng với các quyết định thiết kế cụ thể, hiểu codebase; lợi thế của Cursor là vòng dựng-và-thấy chặt chẽ với một xem trước trực tiếp bên trong trình soạn. Nhiều đội dùng cả hai — Open Design cho phép bạn đổi agent mà không thay đổi quy trình thiết kế của mình."}, {"name": "Làm sao kết nối Cursor với Figma?", "text": "Thêm máy chủ Figma MCP chính thức trong Cursor, rồi dán một liên kết frame Figma vào chat và yêu cầu Cursor hiện thực nó. Máy chủ phơi bày các component, biến và dữ liệu bố cục thực nên code sinh ra khớp với thiết kế nguồn."}, {"name": "Làm sao tránh thẩm mỹ “AI slop” chung chung?", "text": "Thêm một skill thiết kế, cung cấp tokens thiết kế thực và ảnh chụp tham chiếu, mã hóa quy tắc thương hiệu trong `.cursor/rules` hoặc `AGENTS.md`, và kiểm chứng trên các breakpoint trong xem trước. Open Design cung cấp những thứ này dưới dạng một thư viện tuyển chọn để bạn bỏ qua phần thiết lập theo từng dự án."}, {"name": "Open Design có liên kết với Cursor hay Anysphere không?", "text": "Không. Cursor là sản phẩm của Anysphere; Open Design là một dự án mã nguồn mở độc lập hỗ trợ nó như một adapter hạng nhất. Cursor và Anysphere là thương hiệu của Anysphere, Inc."}, {"name": "Tệp tin và thông tin xác thực của tôi có an toàn không?", "text": "Có — Open Design là local-first. Tệp tin, sản phẩm và DESIGN.md của bạn ở lại trong repo của riêng bạn, còn thông tin xác thực Cursor hoặc mô hình của bạn được agent của bạn dùng trực tiếp, không bao giờ định tuyến qua máy chủ Open Design."}], "ctaTitle": "Thiết kế với Cursor, theo cách mở.", "ctaBody": "Mang theo tài khoản Cursor hoặc khóa mô hình của riêng bạn, giữ mọi tệp tin ở máy, và có một thư viện thiết kế được tuyển chọn bao quanh agent bạn đã dùng.", "ctaActions": [{"label": "Dùng Cursor trong Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gắn sao trên GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Tải ứng dụng desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Xem tất cả agent được hỗ trợ"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode cho thiết kế — Open Design",
        description: "Cách người ta dùng OpenCode cho thiết kế UI và web — tệp design.md, các skill UI/UX, Figma MCP — và cách Open Design biến OpenCode thành một agent thiết kế local-first, mã nguồn mở.",
        breadcrumb: "OpenCode",
        label: "Agent · OpenCode",
        heading: "OpenCode cho thiết kế.",
        lead: "OpenCode là agent lập trình AI chạy trên terminal mã nguồn mở. Các nhà thiết kế gắn các skill thiết kế và tệp DESIGN.md lên nó để tạo ra UI thực. Open Design biến điều đó thành một quy trình có cấu trúc, mã nguồn mở — mang theo khóa nhà cung cấp của bạn, giữ mọi thứ ở máy.",
        rich: {"heroCtaLead": "Open Design biến OpenCode thành một agent thiết kế local-first, mã nguồn mở — bất kỳ mô hình nào bạn chọn với khóa nhà cung cấp của riêng bạn, tệp tin của bạn, kèm thư viện skill và design-system được tuyển chọn bao quanh nó.", "heroCtaActions": [{"label": "Dùng OpenCode trong Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gắn sao trên GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Tải ứng dụng desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode là một agent lập trình AI mã nguồn mở, lấy terminal làm trọng tâm, được thiết kế có chủ đích để không phụ thuộc mô hình: bạn mang theo khóa nhà cung cấp của riêng mình và chạy bất kỳ mô hình nào bạn muốn đứng sau cùng một quy trình. Sự cởi mở đó khiến nó là một nền tảng tự nhiên cho công việc thiết kế — nhưng như mọi agent, nó chỉ tạo ra UI tốt khi bạn trao cho nó đúng tham chiếu, skill và một vòng kiểm chứng. Đây là hướng dẫn thực hành, đầu-cuối về cách dùng OpenCode cho công việc UI, frontend và design-system, cũng như cách nối nó vào một quy trình thiết kế có cấu trúc với Open Design.", "Bài viết bao quát OpenCode thực chất là gì, vì sao một agent mở không phụ thuộc mô hình phù hợp với thiết kế, cách thiết lập nó từ con số không, vòng ảnh-chụp-thành-UI, cách AGENTS.md và MCP mở rộng nó, so sánh với Codex, Claude Code và Cursor, những cạm bẫy khiến đầu ra AI trông chung chung, và cách Open Design lấp khoảng cách đó như một lớp thiết kế mở, local-first — một sự ghép đôi tự nhiên, vì cả hai dự án đều mã nguồn mở và chạy trên máy của riêng bạn."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "Vòng phản hồi thiết kế của OpenCode: một agent TUI terminal, một trình duyệt render UI, và một không gian làm việc, với mũi tên phản hồi quay vòng trở lại", "caption": "Vòng lặp cốt lõi: OpenCode dựng UI trong terminal, render và kiểm chứng nó trong một trình duyệt thực, rồi lặp lại theo các tham chiếu của bạn — trên bất kỳ mô hình nào bạn chọn."}, "tocLabel": "Trên trang này", "toc": [{"id": "what-is-opencode", "label": "OpenCode thực chất là gì"}, {"id": "why-design", "label": "Vì sao một agent mở, bất-kỳ-mô-hình hợp với thiết kế"}, {"id": "setup", "label": "Thiết lập OpenCode cho thiết kế (từ con số không)"}, {"id": "screenshot-workflow", "label": "Quy trình ảnh-chụp-thành-UI"}, {"id": "extend", "label": "AGENTS.md, MCP và các phiên chia sẻ được"}, {"id": "vs", "label": "OpenCode so với Codex so với Claude Code so với Cursor"}, {"id": "pitfalls", "label": "Cạm bẫy và diện mạo “AI slop”"}, {"id": "open-design", "label": "Thiết kế với OpenCode trong Open Design"}, {"id": "faq", "label": "Câu hỏi thường gặp"}], "sections": [{"id": "what-is-opencode", "heading": "OpenCode thực chất là gì", "blocks": [{"kind": "p", "text": "OpenCode là một agent lập trình AI mã nguồn mở được xây dựng cho terminal, do đội ngũ đứng sau SST (Anomaly Innovations) duy trì. Nó đọc kho mã của bạn, chạy lệnh, chỉnh sửa tệp và trò chuyện với một mô hình ngôn ngữ lớn — nhưng khác với các agent buộc chặt vào nhà cung cấp, nó không đi kèm mô hình riêng. Bạn trỏ nó tới bất kỳ nhà cung cấp và mô hình nào bạn muốn và mang theo khóa của riêng mình."}, {"kind": "p", "text": "Nó chạy như một giao diện terminal (TUI), với một ứng dụng desktop và các tiện ích IDE đặt trên cùng một engine. Bên dưới, nó dùng kiến trúc client/server, nên agent thực hiện công việc được tách rời khỏi bề mặt mà bạn điều khiển nó. Hai agent dựng sẵn — build và plan — chuyển đổi bằng phím Tab."}, {"kind": "steps", "items": [{"label": "Không phụ thuộc mô hình", "body": "Mô hình và nhà cung cấp đến từ models.dev, một danh mục mở. Bạn cấu hình chúng trong opencode.json bằng một chuỗi provider/model-id và có thể tắt các nhà cung cấp bạn không muốn nạp — nên cùng một quy trình thiết kế chạy trên Anthropic, OpenAI, Google, OpenRouter, các mô hình cục bộ và nhiều hơn nữa."}, {"label": "Tệp chỉ dẫn", "body": "OpenCode đọc một tệp AGENTS.md trong dự án của bạn (chuẩn liên-công-cụ, cũng tương thích với CLAUDE.md) để lấy các quy tắc dự án — nơi tự nhiên để mã hóa các quy ước thiết kế của bạn. Chạy /init để tạo một tệp."}, {"label": "Mở rộng được", "body": "Nó hỗ trợ tích hợp LSP, máy chủ MCP, theme, phím tắt và lệnh tùy chỉnh, cùng các liên kết phiên chia sẻ được cho việc cộng tác."}]}, {"kind": "ul", "items": ["Người duy trì: SST / Anomaly Innovations (dự án mã nguồn mở)", "Thông tin xác thực: (các) khóa API nhà cung cấp mô hình của riêng bạn — BYOK, không khóa chặt vào nhà cung cấp", "Giấy phép: MIT, mã nguồn mở"]}]}, {"id": "why-design", "heading": "Vì sao một agent mở, bất-kỳ-mô-hình hợp với công việc thiết kế", "blocks": [{"kind": "p", "text": "OpenCode không có một “mô hình thiết kế” đơn lẻ như cách một agent gắn nhà cung cấp có — và đó chính là điểm mấu chốt. Vì nó không phụ thuộc mô hình và mở, bạn có thể chạy cùng một quy trình thiết kế trên mô hình nào đang giỏi frontend nhất hiện tại, đổi nó về sau, hoặc lùi về một mô hình cục bộ, tất cả mà không thay đổi thiết lập của bạn."}, {"kind": "p", "text": "Nhưng riêng việc chọn mô hình không mua được gu thẩm mỹ. Như mọi agent lập trình, OpenCode tạo ra UI chung chung trừ khi bạn trao cho nó các ràng buộc. Đầu ra thiết kế tốt đến từ ba đầu vào mà bạn cung cấp."}, {"kind": "steps", "items": [{"label": "Một design system", "body": "Tokens, primitive và quy ước thực mà agent tái dùng, để đầu ra khớp với một thương hiệu thay vì mặc định về một diện mạo chung chung."}, {"label": "Một skill thẩm mỹ", "body": "Một skill được tuyển chọn thực thi gu thẩm mỹ thực — chuyển động tiết chế, phân cấp ưu tiên thương hiệu, tối đa hai kiểu chữ và một màu nhấn — và khiến agent cam kết với một định hướng trước khi dựng."}, {"label": "Tham chiếu cụ thể", "body": "Những ảnh tham chiếu thực và nhiều trạng thái (desktop và mobile, hover, rỗng, đang tải), không chỉ một ảnh hero."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Sơ đồ thể hiện design system, skill và ảnh tham chiếu hội tụ thành đầu ra thiết kế tốt", "caption": "Gu thẩm mỹ đến từ ba đầu vào mà bạn cung cấp: một design system, một skill và những ảnh tham chiếu thực — bất kể bạn chạy mô hình nào."}, {"kind": "p", "text": "Bài học: OpenCode cho bạn tự do về mô hình, nhưng gu thẩm mỹ vẫn đến từ một ngữ cảnh thiết kế được tuyển chọn. Open Design đóng gói đúng những đầu vào ấy, và đó là lý do hai thứ ăn khớp với nhau — cả hai đều mã nguồn mở và local-first (chi tiết bên dưới)."}]}, {"id": "setup", "heading": "Thiết lập OpenCode cho công việc thiết kế, từ con số không", "blocks": [{"kind": "p", "text": "Đây là toàn bộ lộ trình từ một máy sạch đến một OpenCode có thể dựng và kiểm chứng UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Quy trình thiết lập năm bước: cài đặt, xác thực bằng khóa nhà cung cấp của bạn, cấu hình AGENTS.md, thêm một skill, kiểm chứng", "caption": "Trình tự thiết lập: cài đặt → xác thực (khóa nhà cung cấp của bạn) → cấu hình AGENTS.md → thêm một skill → kiểm chứng trong một trình duyệt thực."}, {"kind": "steps", "items": [{"label": "Mã hóa các quy tắc thiết kế của bạn", "body": "Đặt tokens, primitive và quy ước của bạn vào AGENTS.md (hoặc một DESIGN.md được tham chiếu từ đó) để đầu ra khớp với một thương hiệu thay vì mặc định về một diện mạo chung chung. Tùy chọn instructions trong opencode.json có thể trỏ tới các tệp quy tắc bổ sung qua glob."}, {"label": "Chọn một mô hình có năng lực", "body": "Vì OpenCode không phụ thuộc mô hình, hãy chọn provider/model nào đang mạnh nhất ở frontend hiện tại cho lượt thiết kế — và giữ phần còn lại của quy trình không đổi."}]}]}, {"id": "screenshot-workflow", "heading": "Quy trình ảnh-chụp-thành-UI", "blocks": [{"kind": "p", "text": "Vòng thiết kế đòn bẩy cao nhất với bất kỳ agent nào là biến một ảnh tham chiếu thành UI hoạt động được, responsive và lặp đi lặp lại cho đến khi nó khớp. Cùng dạng năm bước ấy áp dụng trong OpenCode."}, {"kind": "ol", "items": ["Bắt đầu từ những tham chiếu hình ảnh rõ ràng nhất bạn có — và đưa vào nhiều trạng thái (desktop và mobile, hover, rỗng, đang tải), không chỉ một ảnh hero.", "Hãy cụ thể trong prompt; prompt mơ hồ tạo ra UI chung chung.", "Chuẩn bị một design system và cho OpenCode biết tokens cùng các primitive chuẩn nằm ở đâu (trong AGENTS.md).", "Chạy một dev server và để agent render trong một trình duyệt thực, đổi kích thước theo breakpoint để kiểm tra kết quả.", "Lặp lại bằng cách cho OpenCode đối chiếu phần hiện thực của nó với các ảnh chụp — không chỉ xác nhận nó build được."]}, {"kind": "p", "text": "Tham chiếu tệp bằng @ trong TUI để tìm kiếm mờ trong thư mục làm việc của bạn, chạy lệnh shell trực tiếp với một dấu ! ở đầu, và điều khiển hành động bằng các lệnh /. Rồi prompt với các ràng buộc cụ thể:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Giữ prompt nhỏ và tập trung, commit các vòng lặp tốt và hoàn tác các vòng tệ (báo cho OpenCode biết khi bạn hoàn tác), để mỗi lượt dựng trên một nền sạch."}]}, {"id": "extend", "heading": "AGENTS.md, MCP và các phiên chia sẻ được", "blocks": [{"kind": "p", "text": "Ba điểm mở rộng khiến OpenCode thực dụng cho công việc thiết kế bền bỉ, và cả ba đều ánh xạ gọn gàng lên một quy trình thiết kế mở."}, {"kind": "steps", "items": [{"label": "Quy tắc AGENTS.md", "body": "Các quy tắc dự án nằm trong một AGENTS.md ở thư mục gốc repo (hoặc các quy tắc toàn cục trong ~/.config/opencode/AGENTS.md). Đó là nơi trú ngụ bền lâu cho các quy ước thiết kế của bạn, được đọc ở mỗi lần chạy, và nó tương thích với các tệp CLAUDE.md mà các agent khác dùng."}, {"label": "Máy chủ MCP", "body": "OpenCode hỗ trợ cả máy chủ MCP cục bộ (command) lẫn từ xa (URL), được cấu hình dưới khóa mcp — cách di động để mang vào ngữ cảnh thiết kế và các công cụ bên ngoài hoạt động xuyên các agent, không chỉ OpenCode."}, {"label": "Các phiên chia sẻ được", "body": "Lệnh /share tạo một liên kết công khai tới một cuộc hội thoại để cộng tác hoặc review, và /unshare thu hồi nó — hữu ích để lấy phản hồi về một lượt thiết kế."}]}, {"kind": "p", "text": "Đây là những năng lực di động, đa-agent — đúng kiểu thứ mà Open Design được tạo ra để điều phối, thay vì tạo lại theo từng dự án."}]}, {"id": "vs", "heading": "OpenCode so với Codex so với Claude Code so với Cursor cho thiết kế", "blocks": [{"kind": "p", "text": "Không có người thắng cuộc duy nhất cho công việc thiết kế — mỗi agent có một thế mạnh khác nhau, và các đội ngũ giàu kinh nghiệm xếp chồng chúng. Một bản tóm tắt công bằng:"}, {"kind": "table", "columns": ["Agent", "Thế mạnh thiết kế", "Phù hợp nhất cho"], "rows": [["OpenCode", "Mã nguồn mở và không phụ thuộc mô hình; chạy bất kỳ nhà cung cấp nào đứng sau một quy trình terminal", "Tự do BYOK, đổi mô hình, các thiết lập hoàn toàn mở và local-first"], ["Codex", "Độ tinh chỉnh thị giác mạnh với một skill frontend; khả năng hiểu hình ảnh", "Bất đồng bộ được ủy thác, build trong sandbox, quy tắc AGENTS.md di động"], ["Claude Code", "Quyết định thiết kế cụ thể (hex, khoảng cách, kiểu chữ) và UX hiểu codebase", "Lập luận frontend và tái cấu trúc ngữ cảnh lớn"], ["Cursor", "Vòng dựng-và-thấy trực quan với xem trước trực tiếp và chỉnh sửa inline", "Công việc UI lặp-và-quan-sát chặt chẽ bên trong một IDE"]]}, {"kind": "p", "text": "Kết luận lặp đi lặp lại của cộng đồng là gu thẩm mỹ đến từ con người: tất cả chúng đều mặc định về một thẩm mỹ chung chung nếu thiếu skill, tham chiếu và ràng buộc. Đó mới là vấn đề thực cần giải — và nó mang hình hài công cụ thiết kế, chứ không phải hình hài mô hình, đó chính là lý do một agent mở như OpenCode ghép đôi rất hợp với một lớp thiết kế mở."}]}, {"id": "pitfalls", "heading": "Cạm bẫy, và cách tránh diện mạo “AI slop”", "blocks": [{"kind": "p", "text": "Phàn nàn phổ biến nhất về thiết kế do AI tạo ra là nó trông chung chung — gradient mềm, panel lơ lửng, bo góc quá khổ, đổ bóng kịch tính, một cảm giác Inter-và-tím “gào lên rằng AI làm cái này.” Những vấn đề khác được báo cáo gồm bố cục mobile vỡ và phần chỉ dẫn rò rỉ vào nội dung UI. Không điều nào trong số này là riêng có ở OpenCode; chúng là điều xảy ra khi bất kỳ agent nào chạy mà không có một ngữ cảnh thiết kế được tuyển chọn."}, {"kind": "steps", "items": [{"label": "Thêm một skill thẩm mỹ", "body": "Một skill thiết kế được tuyển chọn buộc agent cam kết với một định hướng thực thay vì diện mạo mặc định."}, {"label": "Kiểm chứng trong một trình duyệt thực", "body": "Render và tự kiểm tra trên các breakpoint để bố cục không âm thầm vỡ trên mobile."}, {"label": "Cung cấp tokens và tham chiếu", "body": "Tokens thiết kế thực và ảnh chụp tham chiếu là đòn bẩy lớn nhất duy nhất lên chất lượng đầu ra."}, {"label": "Mã hóa quy tắc trong AGENTS.md", "body": "Đặt những quy tắc kiểu “không thẻ hero, tối đa hai kiểu chữ, phân cấp ưu tiên thương hiệu” ở nơi agent đọc mỗi lần chạy."}]}, {"kind": "p", "text": "Hãy để ý rằng mọi biện pháp giảm thiểu đều xoay quanh việc trao cho agent một ngữ cảnh thiết kế được tuyển chọn — bất kể bạn chạy mô hình nào. Duy trì ngữ cảnh đó bằng tay, theo từng dự án, chính là sự cực nhọc mà Open Design loại bỏ."}]}, {"id": "open-design", "heading": "Thiết kế với OpenCode bên trong Open Design", "blocks": [{"kind": "p", "text": "Open Design là lớp thiết kế mã nguồn mở mà quy trình ở trên cứ liên tục đòi hỏi. Nó coi OpenCode như một adapter hạng nhất và bao bọc nó trong một thư viện skill và design-system được tuyển chọn, một render pipeline có cấu trúc và một giao diện desktop cục bộ — để ngữ cảnh thiết kế giúp bất kỳ agent nào trở nên giỏi đã có sẵn ngay từ lần chạy đầu tiên, chứ không phải ghép lại bằng tay mỗi lần. Cả hai dự án đều mã nguồn mở và local-first, điều khiến sự ghép đôi này là một sự phù hợp tự nhiên."}, {"kind": "ol", "items": ["Cài đặt Open Design và chọn OpenCode làm agent của bạn.", "Xác thực bằng khóa API nhà cung cấp mô hình của riêng bạn (BYOK) — thông tin xác thực ở lại trên máy bạn và không bao giờ được trung chuyển qua chúng tôi.", "Chọn bất kỳ nhà cung cấp và mô hình nào, cùng một design system và một skill, rồi tạo ra deck, prototype và landing page với gu thẩm mỹ nhất quán.", "Mọi sản phẩm và tệp DESIGN.md đều nằm trong repo của riêng bạn, không phải một đám mây được lưu trữ ở nơi khác."]}, {"kind": "p", "text": "Cùng một agent OpenCode, cùng một sự tự do về mô hình — cộng thêm một quy trình thiết kế thực, di động, mã nguồn mở bao quanh nó. Nó local-first và Apache-2.0, nên không gì về công việc hay thông tin xác thực của bạn rời khỏi máy bạn."}]}], "faqTitle": "Câu hỏi thường gặp", "faq": [{"name": "OpenCode có thực sự làm được công việc thiết kế không?", "text": "Có — với một skill thẩm mỹ, một design system và những ảnh tham chiếu thực trong ngữ cảnh, OpenCode tạo ra UI responsive chất lượng sản xuất và có thể kiểm chứng trong trình duyệt. Vì nó không phụ thuộc mô hình, bạn chạy mô hình nào đang giỏi frontend nhất hiện tại. Thiếu ngữ cảnh được tuyển chọn đó, nó có xu hướng mặc định về một diện mạo chung chung, và đó chính là khoảng cách mà Open Design lấp đầy."}, {"name": "Tôi nên dùng mô hình nào với OpenCode cho thiết kế?", "text": "Mô hình nào bạn thích — OpenCode không phụ thuộc nhà cung cấp qua models.dev, nên bạn có thể chạy Anthropic, OpenAI, Google, OpenRouter, hoặc các mô hình cục bộ đứng sau cùng một quy trình và đổi bất cứ lúc nào. Chất lượng đầu ra thiết kế phụ thuộc vào skill, design system và tham chiếu của bạn nhiều hơn nhiều so với riêng mô hình."}, {"name": "Open Design có do đội ngũ OpenCode (SST) làm không?", "text": "Không. Open Design là một dự án mã nguồn mở độc lập tích hợp OpenCode như một agent. Nó bổ sung cho OpenCode bằng một thư viện skill và design-system mở, local-first."}, {"name": "Tôi có cần một gói đăng ký đặc biệt để thiết kế với OpenCode không?", "text": "Không — OpenCode là BYOK. Bạn mang theo khóa API nhà cung cấp mô hình của riêng mình, và Open Design không bao giờ trung chuyển thông tin xác thực của bạn. Không có khóa chặt vào nhà cung cấp."}, {"name": "OpenCode hay Codex hay Claude Code cho thiết kế frontend?", "text": "Tất cả đều mạnh, và nhiều đội xếp chồng chúng. Lợi thế của OpenCode là hoàn toàn mã nguồn mở và không phụ thuộc mô hình; Codex xuất sắc ở các bản build được ủy thác, chạy trong sandbox; Claude Code nổi tiếng với các quyết định thiết kế cụ thể, hiểu codebase. Open Design cho phép bạn đổi agent mà không thay đổi quy trình thiết kế của mình."}, {"name": "Làm sao mở rộng OpenCode cho ngữ cảnh thiết kế?", "text": "Mã hóa quy tắc trong AGENTS.md, thêm các máy chủ MCP dưới khóa mcp cho các công cụ di động và ngữ cảnh thiết kế, và dùng các phiên chia sẻ được để review. Open Design cung cấp một thư viện skill và design-system được tuyển chọn để bạn bỏ qua phần thiết lập theo từng dự án."}, {"name": "Open Design có liên kết với OpenCode hay SST không?", "text": "Không. OpenCode là một dự án mã nguồn mở được SST (Anomaly Innovations) duy trì; Open Design là một dự án mã nguồn mở độc lập hỗ trợ nó như một adapter hạng nhất."}, {"name": "Tệp tin và thông tin xác thực của tôi có an toàn không?", "text": "Có — Open Design là local-first. Tệp tin, sản phẩm và DESIGN.md của bạn ở lại trong repo của riêng bạn, còn thông tin xác thực nhà cung cấp mô hình của bạn được agent của bạn dùng trực tiếp, không bao giờ định tuyến qua máy chủ Open Design."}], "ctaTitle": "Thiết kế với OpenCode, theo cách mở.", "ctaBody": "Mang theo khóa nhà cung cấp mô hình của riêng bạn, giữ mọi tệp tin ở máy, và có một thư viện thiết kế được tuyển chọn bao quanh agent mở bạn đã dùng.", "ctaActions": [{"label": "Dùng OpenCode trong Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gắn sao trên GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Tải ứng dụng desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Xem tất cả agent được hỗ trợ"},
      },
    },
    'pl': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code dla projektowania — Open Design",
        description: "Jak projektanci wykorzystują Claude Code do projektowania UI i stron internetowych oraz jak Open Design zamienia go w prawdziwego agenta projektowego — local-first, BYOK, z wyselekcjonowaną biblioteką skills i systemów projektowych.",
        breadcrumb: "Claude Code",
        label: "Agent · Claude Code",
        heading: "Claude Code dla projektowania.",
        lead: "Claude Code to terminalowy agent kodujący od Anthropic. Ludzie już używają go do budowania interfejsów, systemów projektowych i stron docelowych. Open Design wpina go w prawdziwy proces projektowy — przynieś swój klucz Anthropic lub subskrypcję Claude i zachowaj każdy plik lokalnie.",
        rich: {"heroCtaLead": "Open Design zamienia Claude Code w local-first, open-source'owego agenta projektowego — twój klucz Anthropic lub subskrypcja Claude, twoje pliki, a wokół nich wyselekcjonowana biblioteka skills i systemów projektowych.", "heroCtaActions": [{"label": "Użyj Claude Code w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Zostaw gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code jest powszechnie uważany za agenta kodującego o najlepszym wyczuciu frontendu — rozumuje o interfejsach z niezwykłą precyzją, podając dokładne wartości hex, odstępy i skale typograficzne, oraz refaktoryzuje UI w dużej bazie kodu, nie gubiąc wątku. Ale prosto z pudełka i tak skłania się ku generycznemu wyglądowi, dopóki nie podasz mu systemu projektowego, skills i prawdziwych referencji. To praktyczny, kompleksowy przewodnik po wykorzystaniu Claude Code do pracy nad UI, frontendem i systemami projektowymi oraz po wpięciu go w ustrukturyzowany proces z Open Design.", "Obejmuje on to, czym właściwie jest Claude Code, dlaczego jest mocny we frontendzie, jak skonfigurować go od zera, proces pracy z CLAUDE.md i Skills, oficjalny obieg dwukierunkowy z Figmą, jak wypada na tle Codeksa i Cursora, pułapki, przez które wynik AI wygląda generycznie, oraz jak Open Design zasypuje tę lukę jako otwarta, local-first warstwa projektowa."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Pętla informacji zwrotnej w projektowaniu z Claude Code: terminalowy agent podejmujący konkretne decyzje projektowe, przeglądarka renderująca UI oraz przestrzeń robocza, ze strzałką sprzężenia zwrotnego zawracającą do początku", "caption": "Główna pętla: Claude Code wyrozumowuje konkretne decyzje dotyczące UI w terminalu, renderuje je i weryfikuje w prawdziwej przeglądarce oraz zbiega się ku twoim referencjom."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-claude-code", "label": "Czym właściwie jest Claude Code"}, {"id": "why-design", "label": "Dlaczego Claude Code jest dobry w projektowaniu"}, {"id": "setup", "label": "Skonfiguruj Claude Code do projektowania (od zera)"}, {"id": "skills-workflow", "label": "Proces pracy z CLAUDE.md i Skills"}, {"id": "figma", "label": "Claude Code + dwukierunkowy obieg z Figmą"}, {"id": "vs", "label": "Claude Code kontra Codex kontra Cursor"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop”"}, {"id": "open-design", "label": "Projektowanie z Claude Code w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-claude-code", "heading": "Czym właściwie jest Claude Code", "blocks": [{"kind": "p", "text": "Claude Code to agentowe narzędzie do kodowania od Anthropic. Czyta twoją bazę kodu, edytuje pliki, uruchamia polecenia i integruje się z twoimi narzędziami deweloperskimi — planuje, pisze i weryfikuje pracę na podstawie zadań w języku naturalnym, zamiast tylko uzupełniać linijki."}, {"kind": "p", "text": "Dostarczany jest na kilku powierzchniach, które dzielą ten sam silnik: terminalowy CLI, rozszerzenia IDE dla VS Code, Cursora i JetBrains, aplikacja desktopowa z wizualnym przeglądem diffów oraz wersja webowa do długotrwałych zadań. Twoje pliki CLAUDE.md, ustawienia i serwery MCP przenoszą się między nimi wszystkimi."}, {"kind": "steps", "items": [{"label": "Plik instrukcji", "body": "Claude Code czyta plik CLAUDE.md w korzeniu projektu na początku każdej sesji — to naturalne miejsce, by zakodować swoje konwencje projektowe, tokens i listy kontrolne przeglądu."}, {"label": "Skills", "body": "Agent Skills pakują powtarzalne instrukcje, skrypty i zasoby, które Claude ładuje na żądanie, w tym oficjalny skill Frontend Design od Anthropic dla wyczucia smaku."}, {"label": "Plan i podagenci", "body": "Może planować przed działaniem i powoływać podagentów pracujących równolegle nad różnymi częściami zadania, co utrzymuje spójność dużych refaktoryzacji UI."}]}, {"kind": "ul", "items": ["Dostawca: Anthropic", "Poświadczenie: klucz API Anthropic (BYOK, przez Console) lub subskrypcja Claude (Pro / Max)", "Powierzchnie: terminalowy CLI, rozszerzenia VS Code / Cursor / JetBrains, aplikacja desktopowa, web"]}]}, {"id": "why-design", "heading": "Dlaczego Claude Code jest dobry w projektowaniu", "blocks": [{"kind": "p", "text": "Wśród agentów kodujących Claude Code ma reputację narzędzia o wyczuciu smaku w pracy frontendowej. Wyjaśnia to kilka rzeczy."}, {"kind": "steps", "items": [{"label": "Konkretne, a nie mgliste decyzje", "body": "Claude Code zwykle zobowiązuje się do konkretnych wyborów — dokładnych wartości hex, skal odstępów, ramp typograficznych i hierarchii komponentów — zamiast machać ręką, a właśnie to odróżnia prawdziwy interfejs od atrapy."}, {"label": "Rozumowanie świadome bazy kodu", "body": "Dysponując dużym kontekstem roboczym, refaktoryzuje UI w wielu plikach naraz, ponownie wykorzystując twoje istniejące komponenty i tokens zamiast wymyślać jednorazowe style."}, {"label": "Oficjalny skill frontendowy", "body": "Anthropic dostarcza skill Frontend Design, który sprawia, że Claude najpierw spisuje kierunek projektowy i celowo odchodzi od generycznych czcionek systemowych i przewidywalnych fioletowych gradientów."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Diagram pokazujący, jak system projektowy, skill i obraz referencyjny zbiegają się w dobry wynik projektowy", "caption": "Wyczucie smaku bierze się z trzech wkładów, które dostarczasz: systemu projektowego, skilla i prawdziwych obrazów referencyjnych."}, {"kind": "p", "text": "Wniosek jest ten sam, który Anthropic formułuje o własnych modelach: Claude domyślnie nie ma wyczucia smaku — pozostawiony sam sobie zbiega ku statystycznemu środkowi projektowania webowego (Inter, fioletowe gradienty, miękkie cienie). Tworzy dobry projekt, gdy podasz mu ograniczenia. Open Design pakuje dokładnie te wkłady, dlatego te dwie rzeczy do siebie pasują (więcej poniżej)."}]}, {"id": "setup", "heading": "Skonfiguruj Claude Code do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto pełna ścieżka od czystej maszyny do Claude Code, który potrafi budować i weryfikować UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Pięciokrokowy proces konfiguracji: instalacja, uwierzytelnienie, konfiguracja CLAUDE.md, dodanie skilla, weryfikacja", "caption": "Sekwencja konfiguracji: instalacja → uwierzytelnienie → konfiguracja CLAUDE.md → dodanie skilla Frontend Design → włączenie weryfikacji w przeglądarce."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje reguły projektowe", "body": "Umieść swoje tokens, prymitywy i konwencje w CLAUDE.md i nakieruj na nie Claude'a, aby wynik pasował do marki, zamiast domyślać się generycznego wyglądu."}, {"label": "Dodaj weryfikację w przeglądarce", "body": "Podłącz MCP Playwright lub Chrome, aby Claude renderował w prawdziwej przeglądarce i sprawdzał swój wynik na różnych breakpointach, zamiast tylko potwierdzać, że build przechodzi."}]}]}, {"id": "skills-workflow", "heading": "Proces pracy z CLAUDE.md i Skills", "blocks": [{"kind": "p", "text": "Najbardziej dźwigniową pętlą projektową z Claude Code jest podawanie mu prawdziwych referencji wraz z twoim kontekstem projektowym, a następnie iterowanie, aż UI się zgodzi — przy czym CLAUDE.md i Skills niosą ograniczenia, więc nie musisz tłumaczyć ich od nowa przy każdym poleceniu."}, {"kind": "ol", "items": ["Zacznij od najczytelniejszych referencji wizualnych, jakie masz — i uwzględnij wiele stanów (desktop i mobile, hover, pusty, ładowanie), nie tylko jeden kadr bohaterski.", "Bądź konkretny w poleceniu; mgliste polecenia dają generyczne UI nawet przy silnym agencie.", "Trzymaj swój system projektowy i konwencje w CLAUDE.md i powiedz Claude'owi, gdzie znajdują się tokens i kanoniczne prymitywy.", "Dodaj skill Frontend Design, aby Claude zobowiązał się do prawdziwego kierunku estetycznego, zanim napisze kod.", "Podłącz weryfikację w przeglądarce, aby Claude renderował, zmieniał rozmiar do breakpointów i porównywał z referencjami — a nie tylko potwierdzał, że się buduje."]}, {"kind": "p", "text": "Wrzuć obraz referencyjny do sesji i daj polecenie z konkretnymi ograniczeniami:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Uruchom obok serwer deweloperski, trzymaj polecenia krótkie i skupione oraz commituj dobre iteracje / cofaj złe (mówiąc Claude'owi, kiedy cofasz), aby każde przejście budowało na czystej bazie. Używaj trybu planu do większych refaktoryzacji, abyś mógł przejrzeć podejście przed jakąkolwiek zmianą plików."}]}, {"id": "figma", "heading": "Claude Code + Figma: dwukierunkowy obieg projekt ↔ kod", "blocks": [{"kind": "p", "text": "W lutym 2026 Anthropic i Figma dostarczyły pierwszorzędną, dwukierunkową integrację za pośrednictwem serwera Figma MCP. Działa w obie strony."}, {"kind": "steps", "items": [{"label": "Projekt → Kod", "body": "Zaznacz ramkę w Figmie lub wklej link do Claude Code, pobierz kontekst projektowy i poproś go o implementację projektu z użyciem twojej istniejącej biblioteki komponentów. Code Connect utrzymuje wynik zgodny z twoimi rzeczywistymi komponentami."}, {"label": "Kod → Projekt", "body": "Zbuduj i podejrzyj funkcję w przeglądarce, a następnie powiedz „Send this to Figma”, aby uchwycić działające UI jako edytowalne warstwy Figmy — cały ekran lub wybrany element."}]}, {"kind": "p", "text": "Zainstaluj go raz poleceniem claude plugin install figma@claude-plugins-official (Dev Mode MCP wymaga płatnego planu Figma). Ten sam Figma MCP jest dostępny dla Claude Code, Codeksa, Cursora i VS Code — dokładnie ten rodzaj przenośnej, wieloagentowej możliwości, do orkiestracji której zbudowany jest Open Design."}]}, {"id": "vs", "heading": "Claude Code kontra Codex kontra Cursor w projektowaniu", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły zestawiają je ze sobą. Uczciwe podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Mocna strona projektowa", "Najlepszy do"], "rows": [["Claude Code", "Konkretne decyzje projektowe (hex, odstępy, typografia) i rozumowanie UX świadome bazy kodu", "Rozumowanie frontendowe i refaktoryzacje w dużym kontekście"], ["Codex", "Mocne dopracowanie wizualne i rozumienie obrazów; asynchroniczne buildy w sandboksie", "Delegowane asynchroniczne buildy i przenośne reguły AGENTS.md"], ["Cursor", "Wizualna pętla buduj-i-zobacz z podglądem na żywo i edycjami inline", "Ciasna praca nad UI w trybie iteruj-i-obserwuj wewnątrz IDE"]]}, {"kind": "p", "text": "Powracający werdykt społeczności jest taki, że wyczucie smaku pochodzi od ludzi: cała trójka domyślnie zbiega ku generycznej estetyce bez skills, referencji i ograniczeń. To jest prawdziwy problem do rozwiązania — i ma on kształt narzędzia projektowego, a nie modelu."}]}, {"id": "pitfalls", "heading": "Pułapki i jak unikać wyglądu „AI slop”", "blocks": [{"kind": "p", "text": "Nawet przy reputacji Claude Code za wyczucie smaku najczęstszą skargą na projekty generowane przez AI jest to, że wyglądają generycznie — czcionki Inter, fioletowe gradienty na bieli, miękkie cienie, przeskalowane zaokrąglone rogi, estetyka, która „krzyczy, że zrobiło to AI”. Sam Anthropic przypisuje to zbieżności rozkładowej: bezpieczne wybory dominują w danych treningowych z sieci. Inne zgłaszane problemy to popsute układy mobilne i przeciekanie instrukcji do treści UI."}, {"kind": "steps", "items": [{"label": "Zainstaluj skill Frontend Design", "body": "Zmusza Claude'a do zobowiązania się do prawdziwego kierunku i wyraźnie unika czcionek oraz gradientów nadużywanych przez AI."}, {"label": "Włącz weryfikację w przeglądarce", "body": "Spraw, aby Claude renderował i sam się sprawdzał na różnych breakpointach, tak by układy nie psuły się po cichu na mobile."}, {"label": "Dostarcz tokens i referencje", "body": "Prawdziwe design tokens i zrzuty ekranu referencji to pojedyncza największa dźwignia jakości wyniku."}, {"label": "Zakoduj reguły w CLAUDE.md", "body": "Umieść reguły w stylu „bez kart bohaterskich, najwyżej dwa kroje pisma, hierarchia stawiająca markę na pierwszym miejscu” tam, gdzie agent czyta je przy każdym uruchomieniu."}]}, {"kind": "p", "text": "Zauważ, że każde z tych zabezpieczeń polega na daniu agentowi wyselekcjonowanego kontekstu projektowego. Ręczne utrzymywanie tego kontekstu, projekt po projekcie, to mozół, który usuwa Open Design."}]}, {"id": "open-design", "heading": "Projektowanie z Claude Code wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to open-source'owa warstwa projektowa, o którą powyższy proces wciąż się dopomina. Traktuje Claude Code jako adapter pierwszej kategorii i otacza go wyselekcjonowaną biblioteką skills i systemów projektowych, ustrukturyzowanym potokiem renderowania oraz lokalnym desktopowym UI — więc kontekst projektowy, który czyni Claude Code dobrym, jest dostępny od pierwszego uruchomienia, a nie składany ręcznie za każdym razem."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz Claude Code jako swojego agenta.", "Uwierzytelnij się swoim kluczem API Anthropic (BYOK) lub subskrypcją Claude — poświadczenia pozostają na twojej maszynie i nigdy nie są przekierowywane przez nas.", "Wybierz system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym wyczuciem smaku.", "Każdy artefakt i plik DESIGN.md żyje w twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent Claude Code, ten sam klucz — plus prawdziwy, przenośny, open-source'owy proces projektowy wokół niego. Jest local-first i na licencji Apache-2.0, więc nic z twojej pracy ani twoich poświadczeń nie opuszcza twojej maszyny."}]}], "faqTitle": "Najczęściej zadawane pytania", "faq": [{"name": "Czy Claude Code nadaje się do pracy projektowej?", "text": "Tak — jest powszechnie uważany za agenta kodującego o najlepszym wyczuciu frontendu, podejmującego konkretne, świadome bazy kodu decyzje dotyczące wartości hex, odstępów i skal typograficznych. Mając w kontekście skill Frontend Design, system projektowy i prawdziwe obrazy referencyjne, tworzy responsywne UI o jakości produkcyjnej i potrafi je zweryfikować w przeglądarce. Bez tego kontekstu skłania się ku generycznemu wyglądowi, i to jest luka, którą wypełnia Open Design."}, {"name": "Czy potrzebuję subskrypcji Claude, aby projektować z Claude Code?", "text": "Możesz użyć albo klucza API Anthropic (BYOK, przez Console), albo subskrypcji Claude (Pro / Max). Tak czy inaczej Open Design nigdy nie przekierowuje twoich poświadczeń — są one używane bezpośrednio przez twojego agenta na twojej maszynie."}, {"name": "Claude Code czy Codex do projektowania frontendu?", "text": "Oba są mocne. Claude Code jest znany z konkretnych, świadomych bazy kodu decyzji projektowych i rozumowania frontendowego; Codex ma mocne dopracowanie wizualne i wyróżnia się w delegowanych buildach w sandboksie. Wiele zespołów używa obu — Open Design pozwala przełączać agentów bez zmiany twojego procesu projektowego."}, {"name": "Jak połączyć Claude Code z Figmą?", "text": "Zainstaluj oficjalny plugin Figma poleceniem claude plugin install figma@claude-plugins-official. Następnie możesz implementować ramki Figmy w kodzie z użyciem kontekstu projektowego oraz wypchnąć działające UI z powrotem do edytowalnych ramek Figmy za pomocą „Send this to Figma”. Dev Mode MCP wymaga płatnego planu Figma."}, {"name": "Czym są Skills i CLAUDE.md?", "text": "CLAUDE.md to plik markdown w korzeniu projektu, który Claude Code czyta na początku każdej sesji — miejsce na zakodowanie twoich konwencji projektowych. Skills pakują powtarzalne instrukcje i zasoby, które Claude ładuje na żądanie, w tym oficjalny skill Frontend Design od Anthropic. Open Design dostarcza wyselekcjonowaną bibliotekę obu, więc omijasz konfigurację dla każdego projektu z osobna."}, {"name": "Jak uniknąć generycznej estetyki „AI slop”?", "text": "Zainstaluj skill Frontend Design, dostarcz prawdziwe design tokens i zrzuty ekranu referencji, zakoduj reguły marki w CLAUDE.md oraz włącz weryfikację w przeglądarce. Open Design dostarcza je jako wyselekcjonowaną bibliotekę, więc omijasz konfigurację dla każdego projektu z osobna."}, {"name": "Czy Open Design jest powiązany z Anthropic?", "text": "Nie. Claude Code jest produktem Anthropic; Open Design to niezależny projekt open-source, który wspiera go jako adapter pierwszej kategorii. Claude i Claude Code są znakami towarowymi Anthropic."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design jest local-first i na licencji Apache-2.0. Twoje pliki, artefakty i DESIGN.md pozostają w twoim własnym repozytorium, a twoje poświadczenia Anthropic są używane bezpośrednio przez twojego agenta, nigdy nie są przekierowywane przez serwery Open Design."}], "ctaTitle": "Projektuj z Claude Code, w otwarty sposób.", "ctaBody": "Przynieś własny klucz Anthropic lub subskrypcję Claude, zachowaj każdy plik lokalnie i zyskaj wyselekcjonowaną bibliotekę projektową wokół agenta, którego już używasz.", "ctaActions": [{"label": "Użyj Claude Code w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Zostaw gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich obsługiwanych agentów"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex dla projektowania — Open Design",
        description: "Jak ludzie wykorzystują OpenAI Codex do projektowania UI i stron internetowych — plugin Product Design, integracja z Figmą, skills frontendowe — i jak Open Design zamienia Codeksa w local-first, open-source'owego agenta projektowego.",
        breadcrumb: "Codex",
        label: "Agent · Codex",
        heading: "Codex dla projektowania.",
        lead: "Codex to agent kodujący od OpenAI. Dzięki swojemu pluginowi Product Design i integracji z Figmą stał się poważnym narzędziem projektowym. Open Design wpina Codeksa w open-source'owy proces projektowy — twój klucz OpenAI lub subskrypcja ChatGPT, twoje pliki, local-first.",
        rich: {"heroCtaLead": "Open Design zamienia Codeksa w local-first, open-source'owego agenta projektowego — twój klucz OpenAI, twoje pliki, a wokół nich wyselekcjonowana biblioteka skills i systemów projektowych.", "heroCtaActions": [{"label": "Użyj Codeksa w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Zostaw gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex zaczynał jako generator kodu, ale w 2026 stał się wiarygodnym narzędziem do projektowania prawdziwych interfejsów — gdy tylko podasz mu właściwe referencje, skills i pętlę weryfikacji. To praktyczny, kompleksowy przewodnik po wykorzystaniu Codeksa do pracy nad UI, frontendem i systemami projektowymi oraz po wpięciu go w ustrukturyzowany proces projektowy z Open Design.", "Obejmuje on to, czym Codex jest dzisiaj, dlaczego nagle jest dobry we frontendzie, jak skonfigurować go od zera, pętlę zrzut-ekranu-do-UI, oficjalny dwukierunkowy obieg z Figmą, jak wypada na tle Cursora i Claude Code, pułapki, przez które wynik AI wygląda generycznie, oraz jak Open Design zasypuje tę lukę jako otwarta, local-first warstwa projektowa."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Pętla informacji zwrotnej w projektowaniu z Codeksem: terminalowy agent, przeglądarka renderująca UI oraz przestrzeń robocza, ze strzałką sprzężenia zwrotnego zawracającą do początku", "caption": "Główna pętla: Codex buduje UI w terminalu, renderuje je i weryfikuje w prawdziwej przeglądarce oraz iteruje względem twoich referencji."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-codex", "label": "Czym właściwie jest OpenAI Codex"}, {"id": "why-design", "label": "Dlaczego Codex jest teraz dobry w projektowaniu"}, {"id": "setup", "label": "Skonfiguruj Codeksa do projektowania (od zera)"}, {"id": "screenshot-workflow", "label": "Proces zrzut-ekranu-do-UI"}, {"id": "figma", "label": "Codex + dwukierunkowy obieg z Figmą"}, {"id": "vs", "label": "Codex kontra Cursor kontra Claude Code"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop”"}, {"id": "open-design", "label": "Projektowanie z Codeksem w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-codex", "heading": "Czym właściwie jest OpenAI Codex (a czym nie jest)", "blocks": [{"kind": "p", "text": "Najpierw rozróżnienie, które myli niemal każdego, kto szuka „Codeksa”. Pierwotny OpenAI Codex był modelem uzupełniania kodu z 2021 roku, który napędzał wczesny GitHub Copilot i został wycofany w 2023. Nie o tym jest ta strona. Dzisiejszy Codex to agentowe narzędzie do kodowania od OpenAI — planuje, pisze, uruchamia i weryfikuje kod na podstawie zadań w języku naturalnym."}, {"kind": "p", "text": "Nowoczesny Codex dostarczany jest na czterech powierzchniach: terminalowy CLI (przepisany w Rust, na licencji Apache-2.0), rozszerzenie IDE dla VS Code, Cursora i Windsurfa, doświadczenie chmurowe/webowe do delegowanych zadań asynchronicznych oraz aplikacja desktopowa z wbudowaną przeglądarką i Computer Use."}, {"kind": "steps", "items": [{"label": "Domyślny model", "body": "Od połowy 2026 zalecanym modelem jest gpt-5.5, przy czym gpt-5.4 to model, który OpenAI wprost wytrenowało pod frontend i computer use."}, {"label": "Plik instrukcji", "body": "Codex czyta plik AGENTS.md w twoim projekcie (standard międzynarzędziowy) w poszukiwaniu reguł projektu — naturalne miejsce, by zakodować twoje konwencje projektowe."}, {"label": "Sandbox", "body": "Działa w sandboksie na poziomie jądra (domyślnie workspace-write), więc agent edytujący twoje UI nie może wyjść poza projekt."}]}, {"kind": "ul", "items": ["Dostawca: OpenAI", "Poświadczenie: klucz API OpenAI (BYOK) lub subskrypcja ChatGPT (Free / Go / Plus / Pro / Business / Enterprise)", "Licencja CLI: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Dlaczego Codex jest teraz dobry w projektowaniu", "blocks": [{"kind": "p", "text": "Na początku 2026 zbiegły się trzy rzeczy, które uczyniły z Codeksa prawdziwe narzędzie projektowe, a nie generyczny generator kodu."}, {"kind": "steps", "items": [{"label": "Model wytrenowany pod frontend", "body": "OpenAI dostarczyło GPT-5.4, swój pierwszy główny model wytrenowany pod frontend i computer use, ze znacznie lepszym rozumieniem obrazów w całym procesie projektowym i silniejszą samoweryfikacją. Potrafi nawet generować mood boardy i opcje wizualne, zanim zobowiąże się do finalnych zasobów."}, {"label": "Oficjalny skill frontendowy", "body": "Katalog openai/skills dostarcza wyselekcjonowany skill frontendowy, który egzekwuje prawdziwe wyczucie smaku: układy bez kart, hero na całą szerokość, hierarchia stawiająca markę na pierwszym miejscu, powściągliwy ruch, najwyżej dwa kroje pisma i jeden kolor akcentu — i sprawia, że Codex spisuje tezę wizualną przed budowaniem."}, {"label": "Weryfikacja w przeglądarce", "body": "Dzięki skillowi Playwright Codex otwiera prawdziwą przeglądarkę, zmienia rozmiar do breakpointów i porównuje swój wynik z referencją, zamiast tylko sprawdzać, że build przechodzi."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Diagram pokazujący, jak system projektowy, skill i obraz referencyjny zbiegają się w dobry wynik projektowy", "caption": "Wyczucie smaku bierze się z trzech wkładów, które dostarczasz: systemu projektowego, skilla i prawdziwych obrazów referencyjnych."}, {"kind": "p", "text": "Wniosek za całą trójką: Codex domyślnie nie ma wyczucia smaku. Tworzy dobry projekt, gdy podasz mu ograniczenia — system projektowy, skill estetyczny i konkretne referencje. Open Design pakuje dokładnie te wkłady, dlatego te dwie rzeczy do siebie pasują (więcej poniżej)."}]}, {"id": "setup", "heading": "Skonfiguruj Codeksa do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto pełna ścieżka od czystej maszyny do Codeksa, który potrafi budować i weryfikować UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Pięciokrokowy proces konfiguracji: instalacja, uwierzytelnienie, konfiguracja, instalacja skilla, weryfikacja", "caption": "Sekwencja konfiguracji: instalacja → uwierzytelnienie → konfiguracja AGENTS.md → instalacja skilla frontendowego → włączenie weryfikacji w przeglądarce."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje reguły projektowe", "body": "Umieść swoje tokens, prymitywy i konwencje w AGENTS.md lub DESIGN.md i nakieruj na nie Codeksa, aby wynik pasował do marki, zamiast domyślać się generycznego wyglądu."}, {"label": "Wybierz właściwy poziom rozumowania", "body": "OpenAI zauważa, że niskie-do-średnich poziomy rozumowania często dają silniejsze rezultaty frontendowe niż ustawienie najwyższe."}]}]}, {"id": "screenshot-workflow", "heading": "Proces zrzut-ekranu-do-UI", "blocks": [{"kind": "p", "text": "Najbardziej dźwigniową pętlą projektową z Codeksem jest zamiana obrazu referencyjnego w działające, responsywne UI i iterowanie, aż się zgodzi. Własne wskazówki OpenAI sprowadzają się do pięciu kroków."}, {"kind": "ol", "items": ["Zacznij od najczytelniejszych referencji wizualnych, jakie masz — i uwzględnij wiele stanów (desktop i mobile, hover, pusty, ładowanie), nie tylko jeden kadr bohaterski.", "Bądź konkretny w poleceniu; mgliste polecenia dają generyczne UI.", "Przygotuj system projektowy i powiedz Codeksowi, gdzie znajdują się tokens i kanoniczne prymitywy.", "Włącz interaktywny skill Playwright, aby Codex renderował w prawdziwej przeglądarce i zmieniał rozmiar do breakpointów.", "Iteruj, każąc Codeksowi porównywać swoją implementację z powrotem ze zrzutami ekranu — a nie tylko potwierdzać, że się buduje."]}, {"kind": "p", "text": "Podaj obrazy, przeciągając zrzut ekranu do terminala lub używając flagi obrazu, a następnie daj polecenie z konkretnymi ograniczeniami:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Uruchom serwer deweloperski w drugim terminalu, trzymaj polecenia krótkie i skupione oraz commituj dobre iteracje / cofaj złe (mówiąc Codeksowi, kiedy cofasz), aby każde przejście budowało na czystej bazie."}]}, {"id": "figma", "heading": "Codex + Figma: dwukierunkowy obieg projekt ↔ kod", "blocks": [{"kind": "p", "text": "W lutym 2026 OpenAI i Figma ogłosiły oficjalne partnerstwo, zamieniając wcześniejszą betę Figma MCP w pierwszorzędną, dwukierunkową integrację. Działa w obie strony."}, {"kind": "steps", "items": [{"label": "Projekt → Kod", "body": "Skopiuj „link to selection” ramki w Figmie, wklej go do Codeksa z get_design_context i poproś o implementację projektu z użyciem twojej istniejącej biblioteki komponentów."}, {"label": "Kod → Projekt", "body": "Narzędzie generate_figma_design („Code to Canvas”) zamienia działające, uruchomione UI z powrotem w edytowalne ramki Figmy — cały ekran, wybrany element lub cały plik."}]}, {"kind": "p", "text": "Figma MCP działa jako serwer zdalny i jest zwolniony z limitów przepustowości. Dodaj go raz, a jest dostępny dla Codeksa, Claude Code, Cursora, VS Code i innych — dokładnie ten rodzaj przenośnej, wieloagentowej możliwości, do orkiestracji której zbudowany jest Open Design."}]}, {"id": "vs", "heading": "Codex kontra Cursor kontra Claude Code w projektowaniu", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły zestawiają je ze sobą. Uczciwe podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Mocna strona projektowa", "Najlepszy do"], "rows": [["Codex", "Mocne dopracowanie wizualne po GPT-5.4 + skill frontendowy; rozumienie obrazów", "Delegowane asynchroniczne buildy, uruchomienia w sandboksie, przenośne reguły AGENTS.md"], ["Cursor", "Wizualna pętla buduj-i-zobacz z podglądem na żywo i edycjami inline", "Ciasna praca nad UI w trybie iteruj-i-obserwuj wewnątrz IDE"], ["Claude Code", "Konkretne decyzje projektowe (hex, odstępy, typografia) i UX świadomy bazy kodu", "Rozumowanie frontendowe i refaktoryzacje w dużym kontekście"]]}, {"kind": "p", "text": "Powracający werdykt społeczności jest taki, że wyczucie smaku pochodzi od ludzi: cała trójka domyślnie zbiega ku generycznej estetyce bez skills, referencji i ograniczeń. To jest prawdziwy problem do rozwiązania — i ma on kształt narzędzia projektowego, a nie modelu."}]}, {"id": "pitfalls", "heading": "Pułapki i jak unikać wyglądu „AI slop”", "blocks": [{"kind": "p", "text": "Najczęstszą skargą na projekty generowane przez Codeksa jest to, że wyglądają generycznie — miękkie gradienty, unoszące się panele, przeskalowane zaokrąglone rogi, dramatyczne cienie, klimat Inter-i-fiolet, który „krzyczy, że zrobiło to AI”. Inne zgłaszane problemy to popsute układy mobilne, przeciekanie instrukcji do treści UI oraz szybkie osiąganie limitów użycia."}, {"kind": "steps", "items": [{"label": "Zainstaluj skill frontendowy", "body": "Wyselekcjonowany skill estetyczny zmusza Codeksa do zobowiązania się do prawdziwego kierunku zamiast domyślnego wyglądu."}, {"label": "Włącz weryfikację Playwright", "body": "Spraw, aby Codex renderował i sam się sprawdzał na różnych breakpointach, tak by układy nie psuły się po cichu na mobile."}, {"label": "Dostarcz tokens i referencje", "body": "Prawdziwe design tokens i zrzuty ekranu referencji to pojedyncza największa dźwignia jakości wyniku."}, {"label": "Zakoduj reguły w AGENTS.md", "body": "Umieść reguły w stylu „bez kart bohaterskich, najwyżej dwa kroje pisma, hierarchia stawiająca markę na pierwszym miejscu” tam, gdzie agent czyta je przy każdym uruchomieniu."}]}, {"kind": "p", "text": "Zauważ, że każde z tych zabezpieczeń polega na daniu agentowi wyselekcjonowanego kontekstu projektowego. Ręczne utrzymywanie tego kontekstu, projekt po projekcie, to mozół, który usuwa Open Design."}]}, {"id": "open-design", "heading": "Projektowanie z Codeksem wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to open-source'owa warstwa projektowa, o którą powyższy proces wciąż się dopomina. Traktuje Codeksa jako adapter pierwszej kategorii i otacza go wyselekcjonowaną biblioteką skills i systemów projektowych, ustrukturyzowanym potokiem renderowania oraz lokalnym desktopowym UI — więc kontekst projektowy, który czyni Codeksa dobrym, jest dostępny od pierwszego uruchomienia, a nie składany ręcznie za każdym razem."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz Codeksa jako swojego agenta.", "Uwierzytelnij się swoim kluczem API OpenAI (BYOK) lub subskrypcją ChatGPT — poświadczenia pozostają na twojej maszynie i nigdy nie są przekierowywane przez nas.", "Wybierz system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym wyczuciem smaku.", "Każdy artefakt i plik DESIGN.md żyje w twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent Codex, ten sam klucz — plus prawdziwy, przenośny, open-source'owy proces projektowy wokół niego. Jest local-first i na licencji Apache-2.0, więc nic z twojej pracy ani twoich poświadczeń nie opuszcza twojej maszyny."}]}], "faqTitle": "Najczęściej zadawane pytania", "faq": [{"name": "Czy OpenAI Codex naprawdę potrafi wykonywać pracę projektową?", "text": "Tak — mając w kontekście skill frontendowy, system projektowy i prawdziwe obrazy referencyjne, Codex (zwłaszcza na GPT-5.4) tworzy responsywne UI o jakości produkcyjnej i potrafi je zweryfikować w przeglądarce. Bez tego kontekstu skłania się ku generycznemu wyglądowi, i to jest luka, którą wypełnia Open Design."}, {"name": "Czy to plugin Product Design od OpenAI Codex?", "text": "Nie. Open Design to niezależny projekt open-source, który integruje Codeksa jako agenta. Uzupełnia własne narzędzia OpenAI o local-first, otwartą bibliotekę skills i systemów projektowych."}, {"name": "Czy potrzebuję subskrypcji ChatGPT, aby projektować z Codeksem?", "text": "Możesz użyć albo klucza API OpenAI (BYOK), albo swojej subskrypcji ChatGPT. Logowanie do ChatGPT zazwyczaj daje hojniejsze limity; Open Design tak czy inaczej nigdy nie przekierowuje twoich poświadczeń."}, {"name": "Codex czy Claude Code do projektowania frontendu?", "text": "Oba są mocne. Claude Code jest znany z konkretnych, świadomych bazy kodu decyzji projektowych; Codex ma mocne dopracowanie wizualne po GPT-5.4 i wyróżnia się w delegowanych buildach w sandboksie. Wiele zespołów używa obu — Open Design pozwala przełączać agentów bez zmiany twojego procesu projektowego."}, {"name": "Jak połączyć Codeksa z Figmą?", "text": "Dodaj oficjalny serwer Figma MCP (codex mcp add figma --url https://mcp.figma.com/mcp). Następnie możesz implementować ramki Figmy w kodzie za pomocą get_design_context oraz wypchnąć działające UI z powrotem do edytowalnych ramek Figmy za pomocą generate_figma_design."}, {"name": "Jak uniknąć generycznej estetyki „AI slop”?", "text": "Zainstaluj skill frontendowy, dostarcz prawdziwe design tokens i zrzuty ekranu referencji, zakoduj reguły marki w AGENTS.md oraz włącz weryfikację Playwright. Open Design dostarcza je jako wyselekcjonowaną bibliotekę, więc omijasz konfigurację dla każdego projektu z osobna."}, {"name": "Czy Open Design jest powiązany z OpenAI?", "text": "Nie. Codex jest produktem OpenAI; Open Design to niezależny projekt open-source, który wspiera go jako adapter pierwszej kategorii. OpenAI i Codex są znakami towarowymi OpenAI."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design jest local-first. Twoje pliki, artefakty i DESIGN.md pozostają w twoim własnym repozytorium, a twoje poświadczenia OpenAI są używane bezpośrednio przez twojego agenta, nigdy nie są przekierowywane przez serwery Open Design."}], "ctaTitle": "Projektuj z Codeksem, w otwarty sposób.", "ctaBody": "Przynieś własny klucz OpenAI, zachowaj każdy plik lokalnie i zyskaj wyselekcjonowaną bibliotekę projektową wokół agenta, którego już używasz.", "ctaActions": [{"label": "Użyj Codeksa w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Zostaw gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich obsługiwanych agentów"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor dla projektantów — Open Design",
        description: "Jak projektanci wykorzystują Cursora do projektowania UI i stron internetowych — Design Mode, Figma-do-kodu, Figma MCP — i jak Open Design zamienia Cursora w local-first, open-source'owego agenta projektowego.",
        breadcrumb: "Cursor",
        label: "Agent · Cursor",
        heading: "Cursor dla projektantów.",
        lead: "Cursor to edytor kodu oparty na AI, teraz z wizualnym Design Mode. Projektanci używają go do edycji UI poprzez wskazywanie i rysowanie oraz do zamiany Figmy w kod. Open Design wpina Cursor Agent w open-source'owy proces projektowy, który zachowuje twoje pliki lokalnie.",
        rich: {"heroCtaLead": "Open Design zamienia Cursora w local-first, open-source'owego agenta projektowego — twoje konto Cursor lub klucze modeli, twoje pliki, a wokół nich wyselekcjonowana biblioteka skills i systemów projektowych.", "heroCtaActions": [{"label": "Użyj Cursora w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Zostaw gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor to edytor kodu AI-first, który uczynił z „zbuduj i obserwuj, jak się renderuje” domyślny sposób dostarczania UI. Dzięki trybowi Agent, edycjom inline, podglądowi w edytorze i Figmie przez MCP stał się prawdziwym narzędziem projektowym — gdy tylko podasz mu właściwe referencje, reguły i pętlę weryfikacji. To praktyczny, kompleksowy przewodnik po wykorzystaniu Cursora do pracy nad UI, frontendem i systemami projektowymi oraz po wpięciu go w ustrukturyzowany proces projektowy z Open Design.", "Obejmuje on to, czym właściwie jest Cursor, dlaczego jego ciasna pętla iteruj-i-obserwuj jest dobra do projektowania, jak skonfigurować go od zera, pętlę zrzut-ekranu-i-podgląd-do-UI, dwukierunkowy obieg z Figmą przez MCP, jak wypada na tle Codeksa i Claude Code, pułapki, przez które wynik AI wygląda generycznie, oraz jak Open Design zasypuje tę lukę jako otwarta, local-first warstwa projektowa."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Zbieżność projektowa Cursora: edytor po lewej, wyselekcjonowane centrum skills i systemu projektowego pośrodku ze znakiem Cursora w środku oraz wyrenderowane UI po prawej", "caption": "Główna idea: Cursor edytuje i renderuje UI w edytorze, podczas gdy wyselekcjonowane centrum projektowe zasila go systemem, skills i referencjami, które sprawiają, że wynik wygląda celowo."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-cursor", "label": "Czym właściwie jest Cursor"}, {"id": "why-design", "label": "Dlaczego Cursor jest dobry w projektowaniu"}, {"id": "setup", "label": "Skonfiguruj Cursora do projektowania (od zera)"}, {"id": "preview-workflow", "label": "Proces podgląd-do-UI"}, {"id": "figma", "label": "Cursor + Figma przez MCP"}, {"id": "vs", "label": "Cursor kontra Codex kontra Claude Code"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop”"}, {"id": "open-design", "label": "Projektowanie z Cursorem w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-cursor", "heading": "Czym właściwie jest Cursor", "blocks": [{"kind": "p", "text": "Cursor to edytor kodu AI-first zbudowany przez Anysphere. To fork VS Code, więc zachowuje znajomy edytor, rozszerzenia i skróty klawiszowe, ale przebudowuje proces wokół agenta AI, który potrafi czytać cały twój projekt, edytować wiele plików, uruchamiać polecenia i iterować z tobą w pętli."}, {"kind": "p", "text": "Do pracy projektowej ważnymi powierzchniami są tryb Agent (opisujesz wynik, a Cursor planuje i edytuje w wielu plikach), edycje inline i uzupełnienia Tab do szybkich poprawek, podgląd / przeglądarka w edytorze, dzięki czemu widzisz działające UI bez opuszczania okna, oraz wsparcie MCP, które pozwala mu wciągać zewnętrzny kontekst, jak żywy plik Figmy."}, {"kind": "steps", "items": [{"label": "Reguły projektu", "body": "Cursor czyta pliki instrukcji projektu — wersjonowane reguły `.mdc` w `.cursor/rules` oraz zwykły `AGENTS.md` — więc możesz zakodować swoje konwencje projektowe tam, gdzie agent czyta je przy każdym uruchomieniu."}, {"label": "Modele", "body": "Cursor jest elastyczny pod względem modeli: dostarczany jest z czołowymi modelami przez twoją subskrypcję, a także obsługuje wnoszenie własnych kluczy modeli, więc wybierasz silnik stojący za tym samym procesem w edytorze."}, {"label": "MCP", "body": "Mówi w Model Context Protocol, więc zewnętrzne serwery — najistotniejszy serwer Figma MCP — stają się pierwszorzędnym kontekstem dla agenta."}]}, {"kind": "ul", "items": ["Dostawca: Anysphere", "Poświadczenie: konto / subskrypcja Cursor (Hobby / Pro / Business) lub własne klucze modeli (BYOK)", "Forma: edytor kodu AI-first (fork VS Code) z agentem i podglądem w edytorze"]}]}, {"id": "why-design", "heading": "Dlaczego Cursor jest dobry w projektowaniu", "blocks": [{"kind": "p", "text": "Przewaga projektowa Cursora to nie pojedyncza funkcja — to ciasność pętli buduj-i-zobacz. Trzy rzeczy sprawiają, że odczuwa się go jak narzędzie projektowe, a nie generyczny generator kodu."}, {"kind": "steps", "items": [{"label": "Ciasna pętla iteruj-i-obserwuj", "body": "Dajesz polecenie, Cursor edytuje w wielu plikach, a podgląd w edytorze natychmiast renderuje wynik — więc dostrajasz odstępy, hierarchię i ruch w sekundy, zamiast krążyć przez osobny terminal i przeglądarkę."}, {"label": "Bezpośrednia edycja wizualna", "body": "Poza czatem Cursor pozwala zaznaczać elementy w podglądzie i korygować style, więc drobne poprawki wizualne odczuwa się jak edycje projektowe, a nie archeologię kodu."}, {"label": "Reguły projektu i kontekst MCP", "body": "Dzięki `.cursor/rules` (lub `AGENTS.md`) i serwerowi Figma MCP agent pracuje względem twoich tokens, komponentów i prawdziwych specyfikacji projektowych zamiast zgadywać."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Diagram pokazujący, jak system projektowy, skill i obraz referencyjny zbiegają się w dobry wynik projektowy", "caption": "Wyczucie smaku bierze się z trzech wkładów, które dostarczasz: systemu projektowego, skilla i prawdziwych obrazów referencyjnych."}, {"kind": "p", "text": "Wniosek jest ten sam, którego uczy każdy agent: Cursor domyślnie nie ma wyczucia smaku. Tworzy dobry projekt, gdy podasz mu ograniczenia — system projektowy, skill estetyczny i konkretne referencje. Open Design pakuje dokładnie te wkłady, dlatego te dwie rzeczy do siebie pasują (więcej poniżej)."}]}, {"id": "setup", "heading": "Skonfiguruj Cursora do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto pełna ścieżka od czystej maszyny do Cursora, który potrafi budować, podglądać i weryfikować UI względem twojego systemu projektowego."}, {"kind": "ol", "items": ["Zainstaluj Cursora z cursor.com i zaloguj się swoim kontem Cursor lub skonfiguruj własne klucze modeli (BYOK) w Ustawieniach.", "Otwórz swój projekt i wybierz model w panelu czatu / Agent.", "Dodaj reguły projektu: utwórz `.cursor/rules/*.mdc` dla ustrukturyzowanych, ograniczonych globami konwencji lub zwykły `AGENTS.md` dla prostych, czytelnych instrukcji.", "Połącz serwer Figma MCP (opcjonalnie), aby agent mógł czytać żywy kontekst projektowy.", "Uruchom serwer deweloperski i używaj podglądu w edytorze, aby widzieć i weryfikować UI w trakcie iterowania."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Pięciokrokowy proces konfiguracji: instalacja, uwierzytelnienie, konfiguracja reguł, dodanie skilla, weryfikacja", "caption": "Sekwencja konfiguracji: instalacja → uwierzytelnienie → konfiguracja reguł projektu → dodanie skilla → włączenie weryfikacji w podglądzie."}, {"kind": "p", "text": "Minimalny plik reguł projektu sprawia, że agent projektuje pod markę zamiast domyślać się generycznego wyglądu. Umieść go tam, gdzie Cursor czyta go przy każdym uruchomieniu:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje reguły projektowe", "body": "Umieść swoje tokens, prymitywy i konwencje w `.cursor/rules` lub `AGENTS.md` i nakieruj na nie Cursora, aby wynik pasował do marki, zamiast domyślać się generycznego wyglądu."}, {"label": "Trzymaj polecenia krótkie", "body": "Ciasna pętla Cursora nagradza skupione prośby — iteruj po jednym komponencie lub stanie naraz i obserwuj podgląd między przejściami."}]}]}, {"id": "preview-workflow", "heading": "Proces podgląd-do-UI", "blocks": [{"kind": "p", "text": "Najbardziej dźwigniową pętlą projektową z Cursorem jest zamiana referencji w działające, responsywne UI i iterowanie w edytorze, aż się zgodzi — obserwując podgląd na żywo przez cały czas zamiast zgadywać."}, {"kind": "ol", "items": ["Zacznij od najczytelniejszych referencji wizualnych, jakie masz — i uwzględnij wiele stanów (desktop i mobile, hover, pusty, ładowanie), nie tylko jeden kadr bohaterski.", "Bądź konkretny w poleceniu; mgliste polecenia dają generyczne UI.", "Przygotuj system projektowy i powiedz Cursorowi, gdzie znajdują się tokens i kanoniczne prymitywy.", "Trzymaj podgląd w edytorze otwarty, a serwer deweloperski uruchomiony, aby każda edycja renderowała się natychmiast na breakpointach, na których ci zależy.", "Iteruj, porównując wyrenderowane UI z powrotem z referencjami — i używaj bezpośredniego zaznaczania elementów w podglądzie do drobnych poprawek wizualnych."]}, {"kind": "p", "text": "Podaj referencje, dołączając obraz do czatu, a następnie daj polecenie z konkretnymi ograniczeniami:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Commituj dobre iteracje i cofaj złe (mówiąc Cursorowi, kiedy cofasz), aby każde przejście budowało na czystej bazie — ta sama dyscyplina, która chroni każdą pętlę agenta przed dryfowaniem."}]}, {"id": "figma", "heading": "Cursor + Figma: projekt ↔ kod przez MCP", "blocks": [{"kind": "p", "text": "Cursor łączy się z Figmą przez oficjalny serwer Figma MCP, który daje agentowi ustrukturyzowany dostęp do żywego pliku Figmy zamiast płaskiego zrzutu ekranu. To usuwa zgadywanie z przekazania."}, {"kind": "steps", "items": [{"label": "Projekt → Kod", "body": "Skopiuj link ramki w Figmie, wklej go do Cursora i poproś o implementację projektu. Serwer MCP udostępnia prawdziwy kontekst projektowy — komponenty, zmienne, dane układu, tokens — więc wygenerowany kod pasuje do źródła zamiast je przybliżać."}, {"label": "Zachowaj zgodność", "body": "Przy spójnie używanych w Figmie design tokens, stylach i komponentach (oraz Code Connect tam, gdzie jest dostępny) wynik Cursora pozostaje zmapowany na twój prawdziwy system projektowy zamiast wymyślać prymitywy na nowo."}]}, {"kind": "p", "text": "Skonfiguruj zdalny serwer Figma MCP raz, a jest dostępny dla Cursora jako pierwszorzędny kontekst. Ponieważ MCP jest otwartym standardem, ten sam serwer można ponownie wykorzystać w Cursorze, Claude Code, Codeksie i VS Code — dokładnie ten rodzaj przenośnej, wieloagentowej możliwości, do orkiestracji której zbudowany jest Open Design."}]}, {"id": "vs", "heading": "Cursor kontra Codex kontra Claude Code w projektowaniu", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły zestawiają je ze sobą. Uczciwe podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Mocna strona projektowa", "Najlepszy do"], "rows": [["Cursor", "Wizualna pętla buduj-i-zobacz z podglądem na żywo w edytorze i bezpośrednią edycją elementów", "Ciasna praca nad UI w trybie iteruj-i-obserwuj wewnątrz IDE"], ["Codex", "Mocne dopracowanie wizualne ze skillem frontendowym; rozumienie obrazów i uruchomienia w sandboksie", "Delegowane asynchroniczne buildy i przenośne reguły AGENTS.md"], ["Claude Code", "Konkretne decyzje projektowe (hex, odstępy, typografia) i UX świadomy bazy kodu", "Rozumowanie frontendowe i refaktoryzacje w dużym kontekście"]]}, {"kind": "p", "text": "Powracający werdykt społeczności jest taki, że wyczucie smaku pochodzi od ludzi: cała trójka domyślnie zbiega ku generycznej estetyce bez skills, referencji i ograniczeń. To jest prawdziwy problem do rozwiązania — i ma on kształt narzędzia projektowego, a nie modelu."}]}, {"id": "pitfalls", "heading": "Pułapki i jak unikać wyglądu „AI slop”", "blocks": [{"kind": "p", "text": "Najczęstszą skargą na projekty generowane przez Cursora jest to, że wyglądają generycznie — miękkie gradienty, unoszące się panele, przeskalowane zaokrąglone rogi, dramatyczne cienie, klimat Inter-i-fiolet, który „krzyczy, że zrobiło to AI”. Inne zgłaszane problemy to układy psujące się na mobile oraz przeciekanie instrukcji do treści UI."}, {"kind": "steps", "items": [{"label": "Dodaj skill projektowy", "body": "Wyselekcjonowany skill estetyczny zmusza Cursora do zobowiązania się do prawdziwego kierunku zamiast domyślnego wyglądu."}, {"label": "Użyj podglądu do weryfikacji", "body": "Renderuj i sam się sprawdzaj na różnych breakpointach w podglądzie w edytorze, tak by układy nie psuły się po cichu na mobile."}, {"label": "Dostarcz tokens i referencje", "body": "Prawdziwe design tokens i zrzuty ekranu referencji to pojedyncza największa dźwignia jakości wyniku."}, {"label": "Zakoduj reguły w `.cursor/rules`", "body": "Umieść reguły w stylu „bez kart bohaterskich, najwyżej dwa kroje pisma, hierarchia stawiająca markę na pierwszym miejscu” tam, gdzie agent czyta je przy każdym uruchomieniu."}]}, {"kind": "p", "text": "Zauważ, że każde z tych zabezpieczeń polega na daniu agentowi wyselekcjonowanego kontekstu projektowego. Ręczne utrzymywanie tego kontekstu, projekt po projekcie, to mozół, który usuwa Open Design."}]}, {"id": "open-design", "heading": "Projektowanie z Cursorem wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to open-source'owa warstwa projektowa, o którą powyższy proces wciąż się dopomina. Traktuje Cursora jako adapter pierwszej kategorii i otacza go wyselekcjonowaną biblioteką skills i systemów projektowych, ustrukturyzowanym potokiem renderowania oraz lokalnym desktopowym UI — więc kontekst projektowy, który czyni Cursora dobrym, jest dostępny od pierwszego uruchomienia, a nie składany ręcznie za każdym razem."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz Cursora jako swojego agenta.", "Uwierzytelnij się swoim kontem Cursor lub własnymi kluczami modeli (BYOK) — poświadczenia pozostają na twojej maszynie i nigdy nie są przekierowywane przez nas.", "Wybierz system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym wyczuciem smaku.", "Każdy artefakt i plik DESIGN.md żyje w twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent Cursor, ten sam klucz — plus prawdziwy, przenośny, open-source'owy proces projektowy wokół niego. Jest local-first i na licencji Apache-2.0, więc nic z twojej pracy ani twoich poświadczeń nie opuszcza twojej maszyny."}]}], "faqTitle": "Najczęściej zadawane pytania", "faq": [{"name": "Czy Cursor naprawdę potrafi wykonywać pracę projektową?", "text": "Tak — mając w kontekście skill projektowy, system projektowy i prawdziwe obrazy referencyjne, Cursor tworzy responsywne UI o jakości produkcyjnej, a jego podgląd w edytorze pozwala je wizualnie zweryfikować i dopracować. Bez tego kontekstu skłania się ku generycznemu wyglądowi, i to jest luka, którą wypełnia Open Design."}, {"name": "Czy to oficjalny produkt Cursora?", "text": "Nie. Open Design to niezależny projekt open-source, który integruje Cursora jako agenta. Uzupełnia Cursora o local-first, otwartą bibliotekę skills i systemów projektowych."}, {"name": "Czy potrzebuję subskrypcji Cursor, aby projektować z Cursorem?", "text": "Możesz użyć konta / subskrypcji Cursor albo wnieść własne klucze modeli (BYOK). Open Design tak czy inaczej nigdy nie przekierowuje twoich poświadczeń — są one używane bezpośrednio przez twojego agenta."}, {"name": "Cursor czy Claude Code do projektowania frontendu?", "text": "Oba są mocne. Claude Code jest znany z konkretnych, świadomych bazy kodu decyzji projektowych; przewagą Cursora jest jego ciasna pętla buduj-i-zobacz z podglądem na żywo wewnątrz edytora. Wiele zespołów używa obu — Open Design pozwala przełączać agentów bez zmiany twojego procesu projektowego."}, {"name": "Jak połączyć Cursora z Figmą?", "text": "Dodaj oficjalny serwer Figma MCP w Cursorze, a następnie wklej link ramki Figmy do czatu i poproś Cursora o jej implementację. Serwer udostępnia prawdziwe komponenty, zmienne i dane układu, więc wygenerowany kod pasuje do źródłowego projektu."}, {"name": "Jak uniknąć generycznej estetyki „AI slop”?", "text": "Dodaj skill projektowy, dostarcz prawdziwe design tokens i zrzuty ekranu referencji, zakoduj reguły marki w `.cursor/rules` lub `AGENTS.md` oraz weryfikuj na różnych breakpointach w podglądzie. Open Design dostarcza je jako wyselekcjonowaną bibliotekę, więc omijasz konfigurację dla każdego projektu z osobna."}, {"name": "Czy Open Design jest powiązany z Cursorem lub Anysphere?", "text": "Nie. Cursor jest produktem Anysphere; Open Design to niezależny projekt open-source, który wspiera go jako adapter pierwszej kategorii. Cursor i Anysphere są znakami towarowymi Anysphere, Inc."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design jest local-first. Twoje pliki, artefakty i DESIGN.md pozostają w twoim własnym repozytorium, a twoje poświadczenia Cursora lub modeli są używane bezpośrednio przez twojego agenta, nigdy nie są przekierowywane przez serwery Open Design."}], "ctaTitle": "Projektuj z Cursorem, w otwarty sposób.", "ctaBody": "Przynieś własne konto Cursor lub klucze modeli, zachowaj każdy plik lokalnie i zyskaj wyselekcjonowaną bibliotekę projektową wokół agenta, którego już używasz.", "ctaActions": [{"label": "Użyj Cursora w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Zostaw gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich obsługiwanych agentów"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode dla projektowania — Open Design",
        description: "Jak ludzie wykorzystują OpenCode do projektowania UI i stron internetowych — pliki design.md, skills UI/UX, Figma MCP — i jak Open Design zamienia OpenCode w local-first, open-source'owego agenta projektowego.",
        breadcrumb: "OpenCode",
        label: "Agent · OpenCode",
        heading: "OpenCode dla projektowania.",
        lead: "OpenCode to open-source'owy, terminalowy agent kodujący AI. Projektanci dokręcają do niego skills projektowe i pliki DESIGN.md, aby generować prawdziwe UI. Open Design czyni z tego ustrukturyzowany, open-source'owy proces — przynieś swoje klucze dostawców i zachowaj wszystko lokalnie.",
        rich: {"heroCtaLead": "Open Design zamienia OpenCode w local-first, open-source'owego agenta projektowego — dowolny model, który wybierzesz, z własnym kluczem dostawcy, twoje pliki, a wokół nich wyselekcjonowana biblioteka skills i systemów projektowych.", "heroCtaActions": [{"label": "Użyj OpenCode w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Zostaw gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode to open-source'owy, terminalowy w pierwszej kolejności agent kodujący AI, który jest celowo niezależny od modelu: przynosisz własny klucz dostawcy i uruchamiasz dowolny model za tym samym procesem. Ta otwartość czyni go naturalną bazą do pracy projektowej — ale jak każdy agent, tworzy dobre UI tylko wtedy, gdy podasz mu właściwe referencje, skills i pętlę weryfikacji. To praktyczny, kompleksowy przewodnik po wykorzystaniu OpenCode do pracy nad UI, frontendem i systemami projektowymi oraz po wpięciu go w ustrukturyzowany proces projektowy z Open Design.", "Obejmuje on to, czym właściwie jest OpenCode, dlaczego niezależny od modelu otwarty agent jest dobrym wyborem do projektowania, jak skonfigurować go od zera, pętlę zrzut-ekranu-do-UI, jak AGENTS.md i MCP go rozszerzają, jak wypada na tle Codeksa, Claude Code i Cursora, pułapki, przez które wynik AI wygląda generycznie, oraz jak Open Design zasypuje tę lukę jako otwarta, local-first warstwa projektowa — naturalne połączenie, skoro oba projekty są open-source i działają na twojej własnej maszynie."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "Pętla informacji zwrotnej w projektowaniu z OpenCode: terminalowy agent TUI, przeglądarka renderująca UI oraz przestrzeń robocza, ze strzałką sprzężenia zwrotnego zawracającą do początku", "caption": "Główna pętla: OpenCode buduje UI w terminalu, renderuje je i weryfikuje w prawdziwej przeglądarce oraz iteruje względem twoich referencji — na dowolnym modelu, który wybierzesz."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-opencode", "label": "Czym właściwie jest OpenCode"}, {"id": "why-design", "label": "Dlaczego otwarty, dowolnomodelowy agent pasuje do projektowania"}, {"id": "setup", "label": "Skonfiguruj OpenCode do projektowania (od zera)"}, {"id": "screenshot-workflow", "label": "Proces zrzut-ekranu-do-UI"}, {"id": "extend", "label": "AGENTS.md, MCP i udostępnialne sesje"}, {"id": "vs", "label": "OpenCode kontra Codex kontra Claude Code kontra Cursor"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop”"}, {"id": "open-design", "label": "Projektowanie z OpenCode w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-opencode", "heading": "Czym właściwie jest OpenCode", "blocks": [{"kind": "p", "text": "OpenCode to open-source'owy agent kodujący AI zbudowany pod terminal, utrzymywany przez zespół stojący za SST (Anomaly Innovations). Czyta twoje repozytorium, uruchamia polecenia, edytuje pliki i rozmawia z dużym modelem językowym — ale w przeciwieństwie do agentów związanych z dostawcą nie dostarcza własnego modelu. Kierujesz go na dowolnego dostawcę i model, jaki chcesz, i przynosisz własny klucz."}, {"kind": "p", "text": "Działa jako terminalowy interfejs (TUI), z aplikacją desktopową i rozszerzeniami IDE nadbudowanymi na tym samym silniku. Pod maską używa architektury klient/serwer, więc agent wykonujący pracę jest odsprzężony od powierzchni, z której nim sterujesz. Dwaj wbudowani agenci — build i plan — przełączają się klawiszem Tab."}, {"kind": "steps", "items": [{"label": "Niezależny od modelu", "body": "Modele i dostawcy pochodzą z models.dev, otwartego katalogu. Konfigurujesz je w opencode.json łańcuchem provider/model-id i możesz wyłączać dostawców, których nie chcesz ładować — więc ten sam proces projektowy działa na Anthropic, OpenAI, Google, OpenRouter, modelach lokalnych i innych."}, {"label": "Plik instrukcji", "body": "OpenCode czyta plik AGENTS.md w twoim projekcie (standard międzynarzędziowy, zgodny także z CLAUDE.md) w poszukiwaniu reguł projektu — naturalne miejsce, by zakodować twoje konwencje projektowe. Uruchom /init, aby wygenerować jeden."}, {"label": "Rozszerzalny", "body": "Obsługuje integrację LSP, serwery MCP, motywy, skróty klawiszowe i niestandardowe polecenia, a także udostępnialne linki do sesji dla współpracy."}]}, {"kind": "ul", "items": ["Opiekun: SST / Anomaly Innovations (projekt open-source)", "Poświadczenie: twój własny klucz/klucze API dostawcy modeli — BYOK, bez uwiązania do dostawcy", "Licencja: MIT, open source"]}]}, {"id": "why-design", "heading": "Dlaczego otwarty, dowolnomodelowy agent pasuje do pracy projektowej", "blocks": [{"kind": "p", "text": "OpenCode nie ma jednego „modelu projektowego” tak jak agent związany z dostawcą — i o to właśnie chodzi. Ponieważ jest niezależny od modelu i otwarty, możesz uruchamiać ten sam proces projektowy na modelu, który aktualnie jest najlepszy we frontendzie, później go wymienić lub cofnąć się do modelu lokalnego, a wszystko to bez zmiany konfiguracji."}, {"kind": "p", "text": "Ale sam wybór modelu nie kupuje wyczucia smaku. Jak każdy agent kodujący, OpenCode tworzy generyczne UI, dopóki nie podasz mu ograniczeń. Dobry wynik projektowy bierze się z trzech wkładów, które dostarczasz."}, {"kind": "steps", "items": [{"label": "System projektowy", "body": "Prawdziwe tokens, prymitywy i konwencje, które agent ponownie wykorzystuje, aby wynik pasował do marki, zamiast domyślać się generycznego wyglądu."}, {"label": "Skill estetyczny", "body": "Wyselekcjonowany skill, który egzekwuje prawdziwe wyczucie smaku — powściągliwy ruch, hierarchia stawiająca markę na pierwszym miejscu, najwyżej dwa kroje pisma i jeden kolor akcentu — i sprawia, że agent zobowiązuje się do kierunku przed budowaniem."}, {"label": "Konkretne referencje", "body": "Faktyczne obrazy referencyjne i wiele stanów (desktop i mobile, hover, pusty, ładowanie), a nie pojedynczy kadr bohaterski."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Diagram pokazujący, jak system projektowy, skill i obraz referencyjny zbiegają się w dobry wynik projektowy", "caption": "Wyczucie smaku bierze się z trzech wkładów, które dostarczasz: systemu projektowego, skilla i prawdziwych obrazów referencyjnych — niezależnie od tego, który model uruchamiasz."}, {"kind": "p", "text": "Wniosek: OpenCode daje ci swobodę modelu, ale wyczucie smaku wciąż bierze się z wyselekcjonowanego kontekstu projektowego. Open Design pakuje dokładnie te wkłady, dlatego te dwie rzeczy do siebie pasują — oba są open-source i local-first (więcej poniżej)."}]}, {"id": "setup", "heading": "Skonfiguruj OpenCode do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto pełna ścieżka od czystej maszyny do OpenCode, który potrafi budować i weryfikować UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Pięciokrokowy proces konfiguracji: instalacja, uwierzytelnienie kluczem dostawcy, konfiguracja AGENTS.md, dodanie skilla, weryfikacja", "caption": "Sekwencja konfiguracji: instalacja → uwierzytelnienie (twój klucz dostawcy) → konfiguracja AGENTS.md → dodanie skilla → weryfikacja w prawdziwej przeglądarce."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje reguły projektowe", "body": "Umieść swoje tokens, prymitywy i konwencje w AGENTS.md (lub DESIGN.md przywoływanym z niego), aby wynik pasował do marki, zamiast domyślać się generycznego wyglądu. Opcja instructions w opencode.json może wskazywać na dodatkowe pliki reguł przez globy."}, {"label": "Wybierz zdolny model", "body": "Ponieważ OpenCode jest niezależny od modelu, wybierz dostawcę/model aktualnie najsilniejszy we frontendzie na przejście projektowe — i zostaw resztę swojego procesu bez zmian."}]}]}, {"id": "screenshot-workflow", "heading": "Proces zrzut-ekranu-do-UI", "blocks": [{"kind": "p", "text": "Najbardziej dźwigniową pętlą projektową z dowolnym agentem jest zamiana obrazu referencyjnego w działające, responsywne UI i iterowanie, aż się zgodzi. Ten sam pięciokrokowy kształt obowiązuje w OpenCode."}, {"kind": "ol", "items": ["Zacznij od najczytelniejszych referencji wizualnych, jakie masz — i uwzględnij wiele stanów (desktop i mobile, hover, pusty, ładowanie), nie tylko jeden kadr bohaterski.", "Bądź konkretny w poleceniu; mgliste polecenia dają generyczne UI.", "Przygotuj system projektowy i powiedz OpenCode, gdzie znajdują się tokens i kanoniczne prymitywy (w AGENTS.md).", "Uruchom serwer deweloperski i każ agentowi renderować w prawdziwej przeglądarce, zmieniając rozmiar do breakpointów, aby sprawdzić wynik.", "Iteruj, każąc OpenCode porównywać swoją implementację z powrotem ze zrzutami ekranu — a nie tylko potwierdzać, że się buduje."]}, {"kind": "p", "text": "Odwołuj się do plików za pomocą @ w TUI, aby uzyskać rozmyte wyszukiwanie w twoim katalogu roboczym, uruchamiaj polecenia powłoki inline z wiodącym !, a akcjami steruj poleceniami /. Następnie daj polecenie z konkretnymi ograniczeniami:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Trzymaj polecenia krótkie i skupione, commituj dobre iteracje i cofaj złe (mówiąc OpenCode, kiedy cofasz), aby każde przejście budowało na czystej bazie."}]}, {"id": "extend", "heading": "AGENTS.md, MCP i udostępnialne sesje", "blocks": [{"kind": "p", "text": "Trzy punkty rozszerzeń czynią OpenCode praktycznym do długotrwałej pracy projektowej, a wszystkie trzy czysto odwzorowują się na otwarty proces projektowy."}, {"kind": "steps", "items": [{"label": "Reguły AGENTS.md", "body": "Reguły projektu żyją w AGENTS.md w korzeniu repozytorium (lub reguły globalne w ~/.config/opencode/AGENTS.md). To trwały dom dla twoich konwencji projektowych, czytany przy każdym uruchomieniu, i jest zgodny z plikami CLAUDE.md, których używają inne agenty."}, {"label": "Serwery MCP", "body": "OpenCode obsługuje zarówno lokalne (command), jak i zdalne (URL) serwery MCP, konfigurowane pod kluczem mcp — przenośny sposób wnoszenia kontekstu projektowego i zewnętrznych narzędzi, które działają w wielu agentach, nie tylko w OpenCode."}, {"label": "Udostępnialne sesje", "body": "Polecenie /share tworzy publiczny link do rozmowy dla współpracy lub przeglądu, a /unshare go odwołuje — przydatne do uzyskania informacji zwrotnej na temat przejścia projektowego."}]}, {"kind": "p", "text": "To są przenośne, wieloagentowe możliwości — dokładnie to, do orkiestracji czego zbudowany jest Open Design, zamiast odtwarzać je dla każdego projektu z osobna."}]}, {"id": "vs", "heading": "OpenCode kontra Codex kontra Claude Code kontra Cursor w projektowaniu", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły zestawiają je ze sobą. Uczciwe podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Mocna strona projektowa", "Najlepszy do"], "rows": [["OpenCode", "Open-source i niezależny od modelu; uruchom dowolnego dostawcę za jednym terminalowym procesem", "Swoboda BYOK, przełączanie modeli, w pełni otwarte i local-first konfiguracje"], ["Codex", "Mocne dopracowanie wizualne ze skillem frontendowym; rozumienie obrazów", "Delegowane asynchroniczne, buildy w sandboksie, przenośne reguły AGENTS.md"], ["Claude Code", "Konkretne decyzje projektowe (hex, odstępy, typografia) i UX świadomy bazy kodu", "Rozumowanie frontendowe i refaktoryzacje w dużym kontekście"], ["Cursor", "Wizualna pętla buduj-i-zobacz z podglądem na żywo i edycjami inline", "Ciasna praca nad UI w trybie iteruj-i-obserwuj wewnątrz IDE"]]}, {"kind": "p", "text": "Powracający werdykt społeczności jest taki, że wyczucie smaku pochodzi od ludzi: wszystkie z nich domyślnie zbiegają ku generycznej estetyce bez skills, referencji i ograniczeń. To jest prawdziwy problem do rozwiązania — i ma on kształt narzędzia projektowego, a nie modelu, co jest dokładnie powodem, dla którego otwarty agent jak OpenCode tak dobrze łączy się z otwartą warstwą projektową."}]}, {"id": "pitfalls", "heading": "Pułapki i jak unikać wyglądu „AI slop”", "blocks": [{"kind": "p", "text": "Najczęstszą skargą na projekty generowane przez AI jest to, że wyglądają generycznie — miękkie gradienty, unoszące się panele, przeskalowane zaokrąglone rogi, dramatyczne cienie, klimat Inter-i-fiolet, który „krzyczy, że zrobiło to AI”. Inne zgłaszane problemy to popsute układy mobilne i przeciekanie instrukcji do treści UI. Żaden z nich nie jest charakterystyczny wyłącznie dla OpenCode; to się dzieje, gdy dowolny agent działa bez wyselekcjonowanego kontekstu projektowego."}, {"kind": "steps", "items": [{"label": "Dodaj skill estetyczny", "body": "Wyselekcjonowany skill projektowy zmusza agenta do zobowiązania się do prawdziwego kierunku zamiast domyślnego wyglądu."}, {"label": "Weryfikuj w prawdziwej przeglądarce", "body": "Renderuj i sam się sprawdzaj na różnych breakpointach, tak by układy nie psuły się po cichu na mobile."}, {"label": "Dostarcz tokens i referencje", "body": "Prawdziwe design tokens i zrzuty ekranu referencji to pojedyncza największa dźwignia jakości wyniku."}, {"label": "Zakoduj reguły w AGENTS.md", "body": "Umieść reguły w stylu „bez kart bohaterskich, najwyżej dwa kroje pisma, hierarchia stawiająca markę na pierwszym miejscu” tam, gdzie agent czyta je przy każdym uruchomieniu."}]}, {"kind": "p", "text": "Zauważ, że każde z tych zabezpieczeń polega na daniu agentowi wyselekcjonowanego kontekstu projektowego — niezależnie od tego, który model uruchamiasz. Ręczne utrzymywanie tego kontekstu, projekt po projekcie, to mozół, który usuwa Open Design."}]}, {"id": "open-design", "heading": "Projektowanie z OpenCode wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to open-source'owa warstwa projektowa, o którą powyższy proces wciąż się dopomina. Traktuje OpenCode jako adapter pierwszej kategorii i otacza go wyselekcjonowaną biblioteką skills i systemów projektowych, ustrukturyzowanym potokiem renderowania oraz lokalnym desktopowym UI — więc kontekst projektowy, który czyni dowolnego agenta dobrym, jest dostępny od pierwszego uruchomienia, a nie składany ręcznie za każdym razem. Oba projekty są open-source i local-first, co czyni to połączenie naturalnym dopasowaniem."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz OpenCode jako swojego agenta.", "Uwierzytelnij się własnym kluczem API dostawcy modeli (BYOK) — poświadczenia pozostają na twojej maszynie i nigdy nie są przekierowywane przez nas.", "Wybierz dowolnego dostawcę i model, a także system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym wyczuciem smaku.", "Każdy artefakt i plik DESIGN.md żyje w twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent OpenCode, ta sama swoboda modelu — plus prawdziwy, przenośny, open-source'owy proces projektowy wokół niego. Jest local-first i na licencji Apache-2.0, więc nic z twojej pracy ani twoich poświadczeń nie opuszcza twojej maszyny."}]}], "faqTitle": "Najczęściej zadawane pytania", "faq": [{"name": "Czy OpenCode naprawdę potrafi wykonywać pracę projektową?", "text": "Tak — mając w kontekście skill estetyczny, system projektowy i prawdziwe obrazy referencyjne, OpenCode tworzy responsywne UI o jakości produkcyjnej i potrafi je zweryfikować w przeglądarce. Ponieważ jest niezależny od modelu, uruchamiasz model aktualnie najlepszy we frontendzie. Bez tego wyselekcjonowanego kontekstu skłania się ku generycznemu wyglądowi, i to jest luka, którą wypełnia Open Design."}, {"name": "Którego modelu powinienem użyć z OpenCode do projektowania?", "text": "Dowolnego, jaki lubisz — OpenCode jest niezależny od dostawcy przez models.dev, więc możesz uruchamiać Anthropic, OpenAI, Google, OpenRouter lub modele lokalne za tym samym procesem i przełączać się w dowolnym momencie. Jakość wyniku projektowego zależy znacznie bardziej od twojego skilla, systemu projektowego i referencji niż od samego modelu."}, {"name": "Czy Open Design jest tworzony przez zespół OpenCode (SST)?", "text": "Nie. Open Design to niezależny projekt open-source, który integruje OpenCode jako agenta. Uzupełnia OpenCode o local-first, otwartą bibliotekę skills i systemów projektowych."}, {"name": "Czy potrzebuję specjalnej subskrypcji, aby projektować z OpenCode?", "text": "Nie — OpenCode jest BYOK. Przynosisz własny klucz API dostawcy modeli, a Open Design nigdy nie przekierowuje twoich poświadczeń. Nie ma uwiązania do dostawcy."}, {"name": "OpenCode, Codex czy Claude Code do projektowania frontendu?", "text": "Wszystkie są mocne, a wiele zespołów zestawia je ze sobą. Przewagą OpenCode jest bycie w pełni open-source i niezależnym od modelu; Codex wyróżnia się w delegowanych buildach w sandboksie; Claude Code jest znany z konkretnych, świadomych bazy kodu decyzji projektowych. Open Design pozwala przełączać agentów bez zmiany twojego procesu projektowego."}, {"name": "Jak rozszerzyć OpenCode o kontekst projektowy?", "text": "Zakoduj reguły w AGENTS.md, dodaj serwery MCP pod kluczem mcp dla przenośnych narzędzi i kontekstu projektowego oraz używaj udostępnialnych sesji do przeglądu. Open Design dostarcza wyselekcjonowaną bibliotekę skills i systemów projektowych, więc omijasz konfigurację dla każdego projektu z osobna."}, {"name": "Czy Open Design jest powiązany z OpenCode lub SST?", "text": "Nie. OpenCode to projekt open-source utrzymywany przez SST (Anomaly Innovations); Open Design to niezależny projekt open-source, który wspiera go jako adapter pierwszej kategorii."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design jest local-first. Twoje pliki, artefakty i DESIGN.md pozostają w twoim własnym repozytorium, a twoje poświadczenia dostawcy modeli są używane bezpośrednio przez twojego agenta, nigdy nie są przekierowywane przez serwery Open Design."}], "ctaTitle": "Projektuj z OpenCode, w otwarty sposób.", "ctaBody": "Przynieś własny klucz dostawcy modeli, zachowaj każdy plik lokalnie i zyskaj wyselekcjonowaną bibliotekę projektową wokół otwartego agenta, którego już używasz.", "ctaActions": [{"label": "Użyj OpenCode w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Zostaw gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich obsługiwanych agentów"},
      },
    },
    'id': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code untuk desain — Open Design",
        description: "Bagaimana desainer menggunakan Claude Code untuk desain UI dan web, dan bagaimana Open Design mengubahnya menjadi agen desain sungguhan — local-first, BYOK, dengan pustaka skill dan design system yang terkurasi.",
        breadcrumb: "Claude Code",
        label: "Agen · Claude Code",
        heading: "Claude Code untuk desain.",
        lead: "Claude Code adalah agen coding terminal dari Anthropic. Orang sudah menggunakannya untuk membangun UI, design system, dan landing page. Open Design menghubungkannya ke alur kerja desain sungguhan — bawa kunci Anthropic atau langganan Claude Anda, simpan setiap file secara lokal.",
        rich: {"heroCtaLead": "Open Design mengubah Claude Code menjadi agen desain open-source yang local-first — kunci Anthropic atau langganan Claude Anda, file Anda, dengan pustaka skill dan design system terkurasi di sekelilingnya.", "heroCtaActions": [{"label": "Gunakan Claude Code di dalam Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Beri bintang di GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Unduh aplikasi desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code secara luas dianggap sebagai agen coding dengan selera frontend terbaik — ia bernalar tentang antarmuka dengan kekhususan yang tidak biasa, menyebutkan nilai hex, spacing, dan type scale yang persis, serta merefaktor UI di seluruh codebase besar tanpa kehilangan alur pikir. Namun secara default, ia masih cenderung mengarah ke tampilan generik kecuali Anda memberikannya design system, skill, dan referensi nyata. Ini adalah panduan praktis end-to-end untuk menggunakan Claude Code dalam pekerjaan UI, frontend, dan design system, serta untuk merangkainya ke dalam alur kerja terstruktur dengan Open Design.", "Panduan ini membahas apa sebenarnya Claude Code itu, mengapa ia kuat di frontend, cara menyiapkannya dari nol, alur kerja CLAUDE.md dan Skills, round-trip Figma resmi, perbandingannya dengan Codex dan Cursor, jebakan yang membuat output AI terlihat generik, dan bagaimana Open Design menutup celah itu sebagai lapisan desain terbuka yang local-first."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Loop umpan balik desain Claude Code: agen terminal yang membuat keputusan desain spesifik, browser yang merender UI, dan workspace, dengan panah umpan balik yang berputar kembali", "caption": "Loop inti: Claude Code menalar keputusan UI yang spesifik di terminal, merender dan memverifikasinya di browser sungguhan, lalu mengonvergensikannya terhadap referensi Anda."}, "tocLabel": "Di halaman ini", "toc": [{"id": "what-is-claude-code", "label": "Apa sebenarnya Claude Code itu"}, {"id": "why-design", "label": "Mengapa Claude Code bagus untuk desain"}, {"id": "setup", "label": "Menyiapkan Claude Code untuk desain (dari nol)"}, {"id": "skills-workflow", "label": "Alur kerja CLAUDE.md dan Skills"}, {"id": "figma", "label": "Round-trip Claude Code + Figma"}, {"id": "vs", "label": "Claude Code vs Codex vs Cursor"}, {"id": "pitfalls", "label": "Jebakan dan tampilan “AI slop”"}, {"id": "open-design", "label": "Mendesain dengan Claude Code di Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-claude-code", "heading": "Apa sebenarnya Claude Code itu", "blocks": [{"kind": "p", "text": "Claude Code adalah alat coding agentic dari Anthropic. Ia membaca codebase Anda, menyunting file, menjalankan perintah, dan terintegrasi dengan alat pengembangan Anda — merencanakan, menulis, dan memverifikasi pekerjaan dari tugas berbahasa alami, bukan sekadar melengkapi baris secara otomatis."}, {"kind": "p", "text": "Ia hadir di beberapa permukaan yang semuanya berbagi mesin yang sama: CLI terminal, ekstensi IDE untuk VS Code, Cursor, dan JetBrains, aplikasi desktop dengan tinjauan diff visual, serta pengalaman web untuk tugas yang berjalan lama. File CLAUDE.md, pengaturan, dan server MCP Anda terbawa di semuanya."}, {"kind": "steps", "items": [{"label": "File instruksi", "body": "Claude Code membaca file CLAUDE.md di root proyek Anda pada awal setiap sesi — tempat alami untuk menuliskan konvensi desain, tokens, dan checklist tinjauan Anda."}, {"label": "Skills", "body": "Agent Skills mengemas instruksi, skrip, dan sumber daya yang dapat diulang yang dimuat Claude sesuai kebutuhan, termasuk skill Frontend Design resmi dari Anthropic untuk selera."}, {"label": "Plan dan subagent", "body": "Ia dapat merencanakan sebelum bertindak dan memunculkan subagent yang mengerjakan bagian-bagian berbeda dari suatu tugas secara paralel, yang menjaga refaktor UI besar tetap koheren."}]}, {"kind": "ul", "items": ["Vendor: Anthropic", "Kredensial: kunci API Anthropic (BYOK, melalui Console) atau langganan Claude (Pro / Max)", "Permukaan: CLI terminal, ekstensi VS Code / Cursor / JetBrains, aplikasi desktop, web"]}]}, {"id": "why-design", "heading": "Mengapa Claude Code bagus untuk desain", "blocks": [{"kind": "p", "text": "Di antara agen coding, Claude Code punya reputasi soal selera dalam pekerjaan frontend. Beberapa hal menjelaskannya."}, {"kind": "steps", "items": [{"label": "Keputusan spesifik, bukan samar", "body": "Claude Code cenderung berkomitmen pada pilihan konkret — nilai hex yang persis, spacing scale, type ramp, dan hierarki komponen — alih-alih mengambang, dan itulah yang membedakan antarmuka sungguhan dari placeholder."}, {"label": "Penalaran yang sadar codebase", "body": "Dengan konteks kerja yang besar, ia merefaktor UI di banyak file sekaligus, menggunakan kembali komponen dan tokens Anda yang ada, alih-alih menciptakan ulang gaya sekali pakai."}, {"label": "Skill frontend resmi", "body": "Anthropic menyediakan skill Frontend Design yang membuat Claude menulis arah desain lebih dulu dan secara sengaja menjauh dari font sistem generik dan gradien ungu yang bisa ditebak."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Diagram yang menunjukkan design system, skill, dan gambar referensi mengonvergensi menjadi output desain yang baik", "caption": "Selera datang dari tiga masukan yang Anda berikan: design system, skill, dan gambar referensi nyata."}, {"kind": "p", "text": "Pelajarannya sama dengan yang Anthropic katakan tentang modelnya sendiri: Claude tidak punya selera secara default — dibiarkan sendiri, ia mengonvergensi ke pusat statistik desain web (Inter, gradien ungu, soft shadow). Ia menghasilkan desain yang baik ketika Anda memberinya batasan. Open Design mengemas masukan-masukan itu secara persis, dan itulah mengapa keduanya cocok bersama (lebih lanjut di bawah)."}]}, {"id": "setup", "heading": "Menyiapkan Claude Code untuk pekerjaan desain, dari nol", "blocks": [{"kind": "p", "text": "Berikut jalur lengkap dari mesin yang bersih hingga Claude Code yang dapat membangun dan memverifikasi UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Alur penyiapan lima langkah: install, autentikasi, konfigurasi CLAUDE.md, tambah skill, verifikasi", "caption": "Urutan penyiapan: install → autentikasi → konfigurasi CLAUDE.md → tambahkan skill Frontend Design → aktifkan verifikasi browser."}, {"kind": "steps", "items": [{"label": "Tuliskan aturan desain Anda", "body": "Letakkan tokens, primitif, dan konvensi Anda di CLAUDE.md dan arahkan Claude ke sana, sehingga output sesuai dengan brand alih-alih jatuh ke tampilan generik."}, {"label": "Tambahkan verifikasi browser", "body": "Hubungkan Playwright atau Chrome MCP agar Claude merender di browser sungguhan dan memeriksa output-nya di berbagai breakpoint, bukan hanya memastikan build lolos."}]}]}, {"id": "skills-workflow", "heading": "Alur kerja CLAUDE.md dan Skills", "blocks": [{"kind": "p", "text": "Loop desain dengan daya ungkit tertinggi pada Claude Code adalah memberinya referensi nyata plus konteks desain Anda, lalu mengiterasi hingga UI cocok — dengan CLAUDE.md dan Skills membawa batasannya sehingga Anda tidak perlu menjelaskannya ulang di setiap prompt."}, {"kind": "ol", "items": ["Mulai dari referensi visual paling jelas yang Anda miliki — dan sertakan banyak state (desktop dan mobile, hover, kosong, loading), bukan hanya satu hero shot.", "Bersikaplah spesifik dalam prompt; prompt yang samar menghasilkan UI generik bahkan dengan agen yang kuat.", "Simpan design system dan konvensi Anda di CLAUDE.md, dan beri tahu Claude di mana tokens dan primitif kanonis berada.", "Tambahkan skill Frontend Design agar Claude berkomitmen pada arah estetik nyata sebelum menulis kode.", "Hubungkan verifikasi browser agar Claude merender, mengubah ukuran ke breakpoint, dan membandingkannya kembali ke referensi — bukan sekadar memastikan ia berhasil build."]}, {"kind": "p", "text": "Jatuhkan gambar referensi ke dalam sesi dan beri prompt dengan batasan konkret:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Jalankan dev server di sampingnya, jaga prompt tetap kecil dan terfokus, lalu commit iterasi yang baik / revert yang buruk (beri tahu Claude saat Anda revert) sehingga setiap putaran dibangun di atas dasar yang bersih. Gunakan plan mode untuk refaktor yang lebih besar agar Anda bisa meninjau pendekatannya sebelum ada perubahan file."}]}, {"id": "figma", "heading": "Claude Code + Figma: round-trip desain ↔ kode", "blocks": [{"kind": "p", "text": "Pada Februari 2026 Anthropic dan Figma merilis integrasi dwiarah kelas satu melalui server Figma MCP. Ia bekerja di kedua arah."}, {"kind": "steps", "items": [{"label": "Desain → Kode", "body": "Pilih sebuah frame di Figma atau tempelkan tautan ke Claude Code, tarik konteks desainnya, dan minta ia mengimplementasikan desain menggunakan pustaka komponen Anda yang ada. Code Connect menjaga output tetap selaras dengan komponen nyata Anda."}, {"label": "Kode → Desain", "body": "Bangun dan pratinjau sebuah fitur di browser, lalu katakan “Send this to Figma” untuk menangkap UI yang berjalan sebagai layer Figma yang dapat disunting — seluruh layar atau elemen terpilih."}]}, {"kind": "p", "text": "Install sekali dengan claude plugin install figma@claude-plugins-official (Dev Mode MCP memerlukan paket Figma berbayar). Figma MCP yang sama tersedia untuk Claude Code, Codex, Cursor, dan VS Code — persis jenis kemampuan portabel dan multi-agen yang dibuat untuk diorkestrasikan oleh Open Design."}]}, {"id": "vs", "heading": "Claude Code vs Codex vs Cursor untuk desain", "blocks": [{"kind": "p", "text": "Tidak ada pemenang tunggal untuk pekerjaan desain — setiap agen punya kekuatan berbeda, dan tim berpengalaman menumpuknya. Ringkasan yang adil:"}, {"kind": "table", "columns": ["Agen", "Kekuatan desain", "Paling cocok untuk"], "rows": [["Claude Code", "Keputusan desain spesifik (hex, spacing, type) dan penalaran UX yang sadar codebase", "Penalaran frontend dan refaktor konteks besar"], ["Codex", "Poles visual yang kuat dan pemahaman gambar; build asinkron tersandbox", "Build asinkron yang didelegasikan dan aturan AGENTS.md yang portabel"], ["Cursor", "Loop build-and-see visual dengan pratinjau langsung dan suntingan inline", "Pekerjaan UI iterate-and-watch yang rapat di dalam IDE"]]}, {"kind": "p", "text": "Putusan komunitas yang berulang adalah bahwa selera datang dari manusia: ketiganya jatuh ke estetika generik tanpa skill, referensi, dan batasan. Itulah masalah sebenarnya yang harus dipecahkan — dan bentuknya seperti alat desain, bukan seperti model."}]}, {"id": "pitfalls", "heading": "Jebakan, dan cara menghindari tampilan “AI slop”", "blocks": [{"kind": "p", "text": "Bahkan dengan reputasi selera Claude Code, keluhan paling umum tentang desain hasil AI adalah tampilannya yang generik — font Inter, gradien ungu di atas putih, soft shadow, sudut membulat berukuran berlebihan, estetika yang “berteriak ini buatan AI.” Anthropic sendiri mengaitkannya dengan konvergensi distribusional: pilihan aman mendominasi data pelatihan web. Masalah lain yang dilaporkan termasuk layout mobile yang rusak dan instruksi yang bocor ke teks UI."}, {"kind": "steps", "items": [{"label": "Install skill Frontend Design", "body": "Ia memaksa Claude berkomitmen pada arah nyata dan secara eksplisit menghindari font dan gradien yang terlalu sering dipakai oleh AI."}, {"label": "Aktifkan verifikasi browser", "body": "Buat Claude merender dan memeriksa diri sendiri di berbagai breakpoint sehingga layout tidak diam-diam rusak di mobile."}, {"label": "Sediakan tokens dan referensi", "body": "Design tokens nyata dan screenshot referensi adalah satu daya ungkit terbesar bagi kualitas output."}, {"label": "Tuliskan aturan di CLAUDE.md", "body": "Letakkan aturan bergaya “tanpa hero card, maksimal dua typeface, hierarki brand-first” di tempat yang dibaca agen pada setiap putaran."}]}, {"kind": "p", "text": "Perhatikan bahwa setiap mitigasi adalah soal memberi agen konteks desain yang terkurasi. Memelihara konteks itu secara manual, per proyek, adalah kerja melelahkan yang dihapus Open Design."}]}, {"id": "open-design", "heading": "Mendesain dengan Claude Code di dalam Open Design", "blocks": [{"kind": "p", "text": "Open Design adalah lapisan desain open-source yang terus diminta oleh alur kerja di atas. Ia memperlakukan Claude Code sebagai adaptor first-party dan membungkusnya dengan pustaka skill dan design system terkurasi, pipeline render terstruktur, dan UI desktop lokal — sehingga konteks desain yang membuat Claude Code bagus sudah ada sejak putaran pertama, bukan dirakit secara manual setiap kali."}, {"kind": "ol", "items": ["Install Open Design dan pilih Claude Code sebagai agen Anda.", "Autentikasi dengan kunci API Anthropic (BYOK) atau langganan Claude Anda — kredensial tetap di mesin Anda dan tidak pernah diproksi melalui kami.", "Pilih design system dan skill, lalu hasilkan deck, prototipe, dan landing page dengan selera yang konsisten.", "Setiap artefak dan file DESIGN.md hidup di repo Anda sendiri, bukan di cloud yang dihosting."]}, {"kind": "p", "text": "Agen Claude Code yang sama, kunci yang sama — ditambah alur kerja desain open-source yang nyata dan portabel di sekelilingnya. Ia local-first dan Apache-2.0, sehingga tidak ada bagian dari pekerjaan atau kredensial Anda yang meninggalkan mesin Anda."}]}], "faqTitle": "Pertanyaan yang sering diajukan", "faq": [{"name": "Apakah Claude Code bagus untuk pekerjaan desain?", "text": "Ya — ia secara luas dianggap sebagai agen coding dengan selera frontend terbaik, membuat keputusan spesifik dan sadar codebase tentang nilai hex, spacing, dan type scale. Dengan skill Frontend Design, design system, dan gambar referensi nyata dalam konteks, ia menghasilkan UI berkualitas produksi dan responsif serta dapat memverifikasinya di browser. Tanpa konteks itu, ia cenderung jatuh ke tampilan generik, dan itulah celah yang diisi Open Design."}, {"name": "Apakah saya butuh langganan Claude untuk mendesain dengan Claude Code?", "text": "Anda dapat menggunakan kunci API Anthropic (BYOK, melalui Console) atau langganan Claude (Pro / Max). Bagaimanapun, Open Design tidak pernah memproksi kredensial Anda — kredensial digunakan langsung oleh agen Anda di mesin Anda."}, {"name": "Claude Code atau Codex untuk desain frontend?", "text": "Keduanya kuat. Claude Code dikenal karena keputusan desain yang spesifik dan sadar codebase serta penalaran frontend; Codex punya poles visual yang kuat dan unggul dalam build yang didelegasikan dan tersandbox. Banyak tim memakai keduanya — Open Design memungkinkan Anda berganti agen tanpa mengubah alur kerja desain Anda."}, {"name": "Bagaimana cara menghubungkan Claude Code ke Figma?", "text": "Install plugin Figma resmi dengan claude plugin install figma@claude-plugins-official. Anda kemudian dapat mengimplementasikan frame Figma dalam kode menggunakan konteks desain, dan mendorong UI yang berjalan kembali ke frame Figma yang dapat disunting dengan “Send this to Figma.” Dev Mode MCP memerlukan paket Figma berbayar."}, {"name": "Apa itu Skills dan CLAUDE.md?", "text": "CLAUDE.md adalah file markdown di root proyek Anda yang dibaca Claude Code pada awal setiap sesi — tempat untuk menuliskan konvensi desain Anda. Skills mengemas instruksi dan sumber daya yang dapat diulang yang dimuat Claude sesuai kebutuhan, termasuk skill Frontend Design resmi dari Anthropic. Open Design menyediakan pustaka keduanya yang terkurasi sehingga Anda melewati penyiapan per proyek."}, {"name": "Bagaimana cara menghindari estetika “AI slop” yang generik?", "text": "Install skill Frontend Design, sediakan design tokens nyata dan screenshot referensi, tuliskan aturan brand di CLAUDE.md, dan aktifkan verifikasi browser. Open Design menyediakan ini sebagai pustaka terkurasi sehingga Anda melewati penyiapan per proyek."}, {"name": "Apakah Open Design berafiliasi dengan Anthropic?", "text": "Tidak. Claude Code adalah produk Anthropic; Open Design adalah proyek open-source independen yang mendukungnya sebagai adaptor first-party. Claude dan Claude Code adalah merek dagang Anthropic."}, {"name": "Apakah file dan kredensial saya aman?", "text": "Ya — Open Design bersifat local-first dan Apache-2.0. File, artefak, dan DESIGN.md Anda tetap di repo Anda sendiri, dan kredensial Anthropic Anda digunakan langsung oleh agen Anda, tidak pernah dirutekan melalui server Open Design."}], "ctaTitle": "Mendesain dengan Claude Code, dengan cara terbuka.", "ctaBody": "Bawa kunci Anthropic atau langganan Claude Anda sendiri, simpan setiap file secara lokal, dan dapatkan pustaka desain terkurasi di sekeliling agen yang sudah Anda gunakan.", "ctaActions": [{"label": "Gunakan Claude Code di dalam Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Beri bintang di GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Unduh aplikasi desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Lihat semua agen yang didukung"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex untuk desain — Open Design",
        description: "Bagaimana orang menggunakan OpenAI Codex untuk desain UI dan web — plugin Product Design, integrasi Figma, skill frontend — dan bagaimana Open Design mengubah Codex menjadi agen desain open-source yang local-first.",
        breadcrumb: "Codex",
        label: "Agen · Codex",
        heading: "Codex untuk desain.",
        lead: "Codex adalah agen coding dari OpenAI. Dengan plugin Product Design dan integrasi Figma-nya, ia telah menjadi alat desain yang serius. Open Design merangkai Codex ke alur kerja desain open-source — kunci OpenAI atau langganan ChatGPT Anda, file Anda, local-first.",
        rich: {"heroCtaLead": "Open Design mengubah Codex menjadi agen desain open-source yang local-first — kunci OpenAI Anda, file Anda, dengan pustaka skill dan design system terkurasi di sekelilingnya.", "heroCtaActions": [{"label": "Gunakan Codex di dalam Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Beri bintang di GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Unduh aplikasi desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex bermula sebagai generator kode, tetapi pada 2026 ia menjadi alat yang kredibel untuk mendesain antarmuka sungguhan — begitu Anda memberinya referensi, skill, dan loop verifikasi yang tepat. Ini adalah panduan praktis end-to-end untuk menggunakan Codex dalam pekerjaan UI, frontend, dan design system, serta untuk merangkainya ke alur kerja desain terstruktur dengan Open Design.", "Panduan ini membahas apa itu Codex sekarang, mengapa ia tiba-tiba bagus di frontend, cara menyiapkannya dari nol, loop screenshot-to-UI, round-trip Figma resmi, perbandingannya dengan Cursor dan Claude Code, jebakan yang membuat output AI terlihat generik, dan bagaimana Open Design menutup celah itu sebagai lapisan desain terbuka yang local-first."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Loop umpan balik desain Codex: agen terminal, browser yang merender UI, dan workspace, dengan panah umpan balik yang berputar kembali", "caption": "Loop inti: Codex membangun UI di terminal, merender dan memverifikasinya di browser sungguhan, lalu mengiterasinya terhadap referensi Anda."}, "tocLabel": "Di halaman ini", "toc": [{"id": "what-is-codex", "label": "Apa sebenarnya OpenAI Codex itu"}, {"id": "why-design", "label": "Mengapa Codex sekarang bagus untuk desain"}, {"id": "setup", "label": "Menyiapkan Codex untuk desain (dari nol)"}, {"id": "screenshot-workflow", "label": "Alur kerja screenshot-to-UI"}, {"id": "figma", "label": "Round-trip Codex + Figma"}, {"id": "vs", "label": "Codex vs Cursor vs Claude Code"}, {"id": "pitfalls", "label": "Jebakan dan tampilan “AI slop”"}, {"id": "open-design", "label": "Mendesain dengan Codex di Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-codex", "heading": "Apa sebenarnya OpenAI Codex itu (dan apa yang bukan)", "blocks": [{"kind": "p", "text": "Pertama, sebuah penjelasan yang membingungkan hampir semua orang yang mencari “Codex.” OpenAI Codex yang asli adalah model penyelesaian kode tahun 2021 yang menggerakkan GitHub Copilot awal dan dihentikan pada 2023. Itu bukan yang dibahas halaman ini. Codex masa kini adalah alat coding agentic dari OpenAI — ia merencanakan, menulis, menjalankan, dan memverifikasi kode dari tugas berbahasa alami."}, {"kind": "p", "text": "Codex modern hadir di empat permukaan: CLI terminal (ditulis ulang dalam Rust, berlisensi Apache-2.0), ekstensi IDE untuk VS Code, Cursor, dan Windsurf, pengalaman cloud/web untuk tugas asinkron yang didelegasikan, dan aplikasi desktop dengan browser internal dan Computer Use."}, {"kind": "steps", "items": [{"label": "Model default", "body": "Per pertengahan 2026, model yang direkomendasikan adalah gpt-5.5, dengan gpt-5.4 sebagai model yang secara eksplisit dilatih OpenAI untuk frontend dan computer use."}, {"label": "File instruksi", "body": "Codex membaca file AGENTS.md di proyek Anda (standar lintas alat) untuk aturan proyek — tempat alami untuk menuliskan konvensi desain Anda."}, {"label": "Sandbox", "body": "Ia berjalan dalam sandbox tingkat kernel (workspace-write secara default), sehingga agen yang menyunting UI Anda tidak dapat berkelana ke luar proyek."}]}, {"kind": "ul", "items": ["Vendor: OpenAI", "Kredensial: kunci API OpenAI (BYOK) atau langganan ChatGPT (Free / Go / Plus / Pro / Business / Enterprise)", "Lisensi CLI: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Mengapa Codex sekarang bagus untuk desain", "blocks": [{"kind": "p", "text": "Tiga hal berkonvergensi pada awal 2026 untuk menjadikan Codex alat desain sungguhan, bukan sekadar generator kode generik."}, {"kind": "steps", "items": [{"label": "Model yang dilatih untuk frontend", "body": "OpenAI merilis GPT-5.4, model mainline pertamanya yang dilatih untuk frontend dan computer use, dengan pemahaman gambar yang jauh lebih baik di seluruh alur kerja desain dan verifikasi diri yang lebih kuat. Ia bahkan dapat menghasilkan mood board dan opsi visual sebelum berkomitmen pada aset final."}, {"label": "Skill frontend resmi", "body": "Katalog openai/skills menyediakan frontend-skill terkurasi yang menegakkan selera nyata: layout tanpa card, hero full-bleed, hierarki brand-first, gerak yang terkendali, paling banyak dua typeface dan satu accent color — dan membuat Codex menulis tesis visual sebelum membangun."}, {"label": "Verifikasi browser", "body": "Dengan skill Playwright, Codex membuka browser sungguhan, mengubah ukuran ke breakpoint, dan membandingkan output-nya kembali ke referensi alih-alih hanya memeriksa bahwa build lolos."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Diagram yang menunjukkan design system, skill, dan gambar referensi mengonvergensi menjadi output desain yang baik", "caption": "Selera datang dari tiga masukan yang Anda berikan: design system, skill, dan gambar referensi nyata."}, {"kind": "p", "text": "Pelajaran di balik ketiganya: Codex tidak punya selera secara default. Ia menghasilkan desain yang baik ketika Anda memberinya batasan — design system, skill estetik, dan referensi konkret. Open Design mengemas masukan-masukan itu secara persis, dan itulah mengapa keduanya cocok bersama (lebih lanjut di bawah)."}]}, {"id": "setup", "heading": "Menyiapkan Codex untuk pekerjaan desain, dari nol", "blocks": [{"kind": "p", "text": "Berikut jalur lengkap dari mesin yang bersih hingga Codex yang dapat membangun dan memverifikasi UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Alur penyiapan lima langkah: install, autentikasi, konfigurasi, install skill, verifikasi", "caption": "Urutan penyiapan: install → autentikasi → konfigurasi AGENTS.md → install skill frontend → aktifkan verifikasi browser."}, {"kind": "steps", "items": [{"label": "Tuliskan aturan desain Anda", "body": "Letakkan tokens, primitif, dan konvensi Anda di AGENTS.md atau DESIGN.md dan arahkan Codex ke sana, sehingga output sesuai dengan brand alih-alih jatuh ke tampilan generik."}, {"label": "Pilih tingkat reasoning yang tepat", "body": "OpenAI mencatat bahwa tingkat reasoning rendah hingga sedang sering menghasilkan hasil frontend yang lebih kuat daripada pengaturan tertinggi."}]}]}, {"id": "screenshot-workflow", "heading": "Alur kerja screenshot-to-UI", "blocks": [{"kind": "p", "text": "Loop desain dengan daya ungkit tertinggi pada Codex adalah mengubah gambar referensi menjadi UI yang berfungsi dan responsif, lalu mengiterasinya hingga cocok. Panduan OpenAI sendiri menyaringnya menjadi lima langkah."}, {"kind": "ol", "items": ["Mulai dari referensi visual paling jelas yang Anda miliki — dan sertakan banyak state (desktop dan mobile, hover, kosong, loading), bukan hanya satu hero shot.", "Bersikaplah spesifik dalam prompt; prompt yang samar menghasilkan UI generik.", "Siapkan design system dan beri tahu Codex di mana tokens dan primitif kanonis berada.", "Aktifkan skill interaktif Playwright agar Codex merender di browser sungguhan dan mengubah ukuran ke breakpoint.", "Iterasi dengan meminta Codex membandingkan implementasinya kembali ke screenshot — bukan sekadar memastikan ia berhasil build."]}, {"kind": "p", "text": "Beri gambar dengan menyeret screenshot ke dalam terminal atau dengan flag image, lalu beri prompt dengan batasan konkret:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Jalankan dev server di terminal kedua, jaga prompt tetap kecil dan terfokus, lalu commit iterasi yang baik / revert yang buruk (beri tahu Codex saat Anda revert) sehingga setiap putaran dibangun di atas dasar yang bersih."}]}, {"id": "figma", "heading": "Codex + Figma: round-trip desain ↔ kode", "blocks": [{"kind": "p", "text": "Pada Februari 2026 OpenAI dan Figma mengumumkan kemitraan resmi, mengubah beta Figma MCP sebelumnya menjadi integrasi dwiarah kelas satu. Ia bekerja di kedua arah."}, {"kind": "steps", "items": [{"label": "Desain → Kode", "body": "Salin “link to selection” sebuah frame di Figma, tempelkan ke Codex dengan get_design_context, dan minta ia mengimplementasikan desain menggunakan pustaka komponen Anda yang ada."}, {"label": "Kode → Desain", "body": "Alat generate_figma_design (“Code to Canvas”) mengubah UI yang hidup dan berjalan kembali menjadi frame Figma yang dapat disunting — seluruh layar, elemen terpilih, atau seluruh file."}]}, {"kind": "p", "text": "Figma MCP berjalan sebagai server remote dan dikecualikan dari rate limit. Tambahkan sekali dan ia tersedia untuk Codex, Claude Code, Cursor, VS Code, dan lainnya — persis jenis kemampuan portabel dan multi-agen yang dibuat untuk diorkestrasikan oleh Open Design."}]}, {"id": "vs", "heading": "Codex vs Cursor vs Claude Code untuk desain", "blocks": [{"kind": "p", "text": "Tidak ada pemenang tunggal untuk pekerjaan desain — setiap agen punya kekuatan berbeda, dan tim berpengalaman menumpuknya. Ringkasan yang adil:"}, {"kind": "table", "columns": ["Agen", "Kekuatan desain", "Paling cocok untuk"], "rows": [["Codex", "Poles visual yang kuat setelah GPT-5.4 + frontend-skill; pemahaman gambar", "Build asinkron yang didelegasikan, jalankan tersandbox, aturan AGENTS.md yang portabel"], ["Cursor", "Loop build-and-see visual dengan pratinjau langsung dan suntingan inline", "Pekerjaan UI iterate-and-watch yang rapat di dalam IDE"], ["Claude Code", "Keputusan desain spesifik (hex, spacing, type) dan UX yang sadar codebase", "Penalaran frontend dan refaktor konteks besar"]]}, {"kind": "p", "text": "Putusan komunitas yang berulang adalah bahwa selera datang dari manusia: ketiganya jatuh ke estetika generik tanpa skill, referensi, dan batasan. Itulah masalah sebenarnya yang harus dipecahkan — dan bentuknya seperti alat desain, bukan seperti model."}]}, {"id": "pitfalls", "heading": "Jebakan, dan cara menghindari tampilan “AI slop”", "blocks": [{"kind": "p", "text": "Keluhan paling umum tentang desain hasil Codex adalah tampilannya yang generik — gradien lembut, panel mengambang, sudut membulat berukuran berlebihan, bayangan dramatis, nuansa Inter-dan-ungu yang “berteriak ini buatan AI.” Masalah lain yang dilaporkan termasuk layout mobile yang rusak, instruksi yang bocor ke teks UI, dan cepat mencapai batas penggunaan."}, {"kind": "steps", "items": [{"label": "Install sebuah skill frontend", "body": "Skill estetik terkurasi memaksa Codex berkomitmen pada arah nyata alih-alih tampilan default."}, {"label": "Aktifkan verifikasi Playwright", "body": "Buat Codex merender dan memeriksa diri sendiri di berbagai breakpoint sehingga layout tidak diam-diam rusak di mobile."}, {"label": "Sediakan tokens dan referensi", "body": "Design tokens nyata dan screenshot referensi adalah satu daya ungkit terbesar bagi kualitas output."}, {"label": "Tuliskan aturan di AGENTS.md", "body": "Letakkan aturan bergaya “tanpa hero card, maksimal dua typeface, hierarki brand-first” di tempat yang dibaca agen pada setiap putaran."}]}, {"kind": "p", "text": "Perhatikan bahwa setiap mitigasi adalah soal memberi agen konteks desain yang terkurasi. Memelihara konteks itu secara manual, per proyek, adalah kerja melelahkan yang dihapus Open Design."}]}, {"id": "open-design", "heading": "Mendesain dengan Codex di dalam Open Design", "blocks": [{"kind": "p", "text": "Open Design adalah lapisan desain open-source yang terus diminta oleh alur kerja di atas. Ia memperlakukan Codex sebagai adaptor first-party dan membungkusnya dengan pustaka skill dan design system terkurasi, pipeline render terstruktur, dan UI desktop lokal — sehingga konteks desain yang membuat Codex bagus sudah ada sejak putaran pertama, bukan dirakit secara manual setiap kali."}, {"kind": "ol", "items": ["Install Open Design dan pilih Codex sebagai agen Anda.", "Autentikasi dengan kunci API OpenAI (BYOK) atau langganan ChatGPT Anda — kredensial tetap di mesin Anda dan tidak pernah diproksi melalui kami.", "Pilih design system dan skill, lalu hasilkan deck, prototipe, dan landing page dengan selera yang konsisten.", "Setiap artefak dan file DESIGN.md hidup di repo Anda sendiri, bukan di cloud yang dihosting."]}, {"kind": "p", "text": "Agen Codex yang sama, kunci yang sama — ditambah alur kerja desain open-source yang nyata dan portabel di sekelilingnya. Ia local-first dan Apache-2.0, sehingga tidak ada bagian dari pekerjaan atau kredensial Anda yang meninggalkan mesin Anda."}]}], "faqTitle": "Pertanyaan yang sering diajukan", "faq": [{"name": "Apakah OpenAI Codex benar-benar bisa melakukan pekerjaan desain?", "text": "Ya — dengan skill frontend, design system, dan gambar referensi nyata dalam konteks, Codex (terutama pada GPT-5.4) menghasilkan UI berkualitas produksi dan responsif serta dapat memverifikasinya di browser. Tanpa konteks itu, ia cenderung jatuh ke tampilan generik, dan itulah celah yang diisi Open Design."}, {"name": "Apakah ini plugin Product Design OpenAI Codex?", "text": "Bukan. Open Design adalah proyek open-source independen yang mengintegrasikan Codex sebagai agen. Ia melengkapi tooling OpenAI sendiri dengan pustaka skill dan design system yang terbuka dan local-first."}, {"name": "Apakah saya butuh langganan ChatGPT untuk mendesain dengan Codex?", "text": "Anda dapat menggunakan kunci API OpenAI (BYOK) atau langganan ChatGPT Anda. Masuk dengan ChatGPT umumnya memberi batas yang lebih murah hati; Open Design tidak pernah memproksi kredensial Anda dengan cara apa pun."}, {"name": "Codex atau Claude Code untuk desain frontend?", "text": "Keduanya kuat. Claude Code dikenal karena keputusan desain yang spesifik dan sadar codebase; Codex punya poles visual yang kuat setelah GPT-5.4 dan unggul dalam build yang didelegasikan dan tersandbox. Banyak tim memakai keduanya — Open Design memungkinkan Anda berganti agen tanpa mengubah alur kerja desain Anda."}, {"name": "Bagaimana cara menghubungkan Codex ke Figma?", "text": "Tambahkan server Figma MCP resmi (codex mcp add figma --url https://mcp.figma.com/mcp). Anda kemudian dapat mengimplementasikan frame Figma dalam kode dengan get_design_context dan mendorong UI yang berjalan kembali ke frame Figma yang dapat disunting dengan generate_figma_design."}, {"name": "Bagaimana cara menghindari estetika “AI slop” yang generik?", "text": "Install skill frontend, sediakan design tokens nyata dan screenshot referensi, tuliskan aturan brand di AGENTS.md, dan aktifkan verifikasi Playwright. Open Design menyediakan ini sebagai pustaka terkurasi sehingga Anda melewati penyiapan per proyek."}, {"name": "Apakah Open Design berafiliasi dengan OpenAI?", "text": "Tidak. Codex adalah produk OpenAI; Open Design adalah proyek open-source independen yang mendukungnya sebagai adaptor first-party. OpenAI dan Codex adalah merek dagang OpenAI."}, {"name": "Apakah file dan kredensial saya aman?", "text": "Ya — Open Design bersifat local-first. File, artefak, dan DESIGN.md Anda tetap di repo Anda sendiri, dan kredensial OpenAI Anda digunakan langsung oleh agen Anda, tidak pernah dirutekan melalui server Open Design."}], "ctaTitle": "Mendesain dengan Codex, dengan cara terbuka.", "ctaBody": "Bawa kunci OpenAI Anda sendiri, simpan setiap file secara lokal, dan dapatkan pustaka desain terkurasi di sekeliling agen yang sudah Anda gunakan.", "ctaActions": [{"label": "Gunakan Codex di dalam Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Beri bintang di GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Unduh aplikasi desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Lihat semua agen yang didukung"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor untuk desainer — Open Design",
        description: "Bagaimana desainer menggunakan Cursor untuk desain UI dan web — Design Mode, Figma-to-code, Figma MCP — dan bagaimana Open Design mengubah Cursor menjadi agen desain open-source yang local-first.",
        breadcrumb: "Cursor",
        label: "Agen · Cursor",
        heading: "Cursor untuk desainer.",
        lead: "Cursor adalah editor kode AI, kini dengan Design Mode visual. Desainer menggunakannya untuk menyunting UI dengan menunjuk dan menggambar, serta untuk mengubah Figma menjadi kode. Open Design menghubungkan Cursor Agent ke alur kerja desain open-source yang menjaga file Anda tetap lokal.",
        rich: {"heroCtaLead": "Open Design mengubah Cursor menjadi agen desain open-source yang local-first — akun Cursor atau kunci model Anda, file Anda, dengan pustaka skill dan design system terkurasi di sekelilingnya.", "heroCtaActions": [{"label": "Gunakan Cursor di dalam Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Beri bintang di GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Unduh aplikasi desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor adalah editor kode AI-first yang menjadikan “bangun lalu lihat ia merender” sebagai cara default untuk mengirimkan UI. Dengan mode Agent, suntingan inline, pratinjau di dalam editor, dan Figma lewat MCP, ia telah menjadi alat desain yang sungguhan — begitu Anda memberinya referensi, aturan, dan loop verifikasi yang tepat. Ini adalah panduan praktis end-to-end untuk menggunakan Cursor dalam pekerjaan UI, frontend, dan design system, serta untuk merangkainya ke alur kerja desain terstruktur dengan Open Design.", "Panduan ini membahas apa sebenarnya Cursor itu, mengapa loop iterate-and-watch-nya yang rapat bagus untuk desain, cara menyiapkannya dari nol, loop screenshot-dan-pratinjau-to-UI, round-trip Figma lewat MCP, perbandingannya dengan Codex dan Claude Code, jebakan yang membuat output AI terlihat generik, dan bagaimana Open Design menutup celah itu sebagai lapisan desain terbuka yang local-first."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Konvergensi desain Cursor: editor di kiri, hub skill dan design system terkurasi di tengah dengan mark Cursor di pusat, dan UI yang dirender di kanan", "caption": "Ide intinya: Cursor menyunting dan merender UI di dalam editor, sementara hub desain terkurasi memberinya system, skill, dan referensi yang membuat output terlihat disengaja."}, "tocLabel": "Di halaman ini", "toc": [{"id": "what-is-cursor", "label": "Apa sebenarnya Cursor itu"}, {"id": "why-design", "label": "Mengapa Cursor bagus untuk desain"}, {"id": "setup", "label": "Menyiapkan Cursor untuk desain (dari nol)"}, {"id": "preview-workflow", "label": "Alur kerja preview-to-UI"}, {"id": "figma", "label": "Cursor + Figma lewat MCP"}, {"id": "vs", "label": "Cursor vs Codex vs Claude Code"}, {"id": "pitfalls", "label": "Jebakan dan tampilan “AI slop”"}, {"id": "open-design", "label": "Mendesain dengan Cursor di Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-cursor", "heading": "Apa sebenarnya Cursor itu", "blocks": [{"kind": "p", "text": "Cursor adalah editor kode AI-first yang dibangun oleh Anysphere. Ia adalah fork dari VS Code, sehingga tetap mempertahankan editor, ekstensi, dan keybinding yang familier, tetapi membangun ulang alur kerja di seputar agen AI yang dapat membaca seluruh proyek Anda, menyunting banyak file, menjalankan perintah, dan mengiterasi bersama Anda dalam loop."}, {"kind": "p", "text": "Untuk pekerjaan desain, permukaan yang penting adalah mode Agent (Anda mendeskripsikan hasil dan Cursor merencanakan serta menyunting di banyak file), suntingan inline dan penyelesaian Tab untuk perubahan cepat, pratinjau / browser di dalam editor agar Anda bisa melihat UI yang berjalan tanpa meninggalkan jendela, serta dukungan MCP yang membuatnya dapat menarik konteks eksternal seperti file Figma yang hidup."}, {"kind": "steps", "items": [{"label": "Aturan proyek", "body": "Cursor membaca file instruksi proyek — aturan `.mdc` yang berversi di bawah `.cursor/rules`, dan `AGENTS.md` biasa — sehingga Anda dapat menuliskan konvensi desain di tempat yang dibaca agen pada setiap putaran."}, {"label": "Model", "body": "Cursor fleksibel soal model: ia hadir dengan model-model terdepan melalui langganan Anda dan juga mendukung membawa kunci model Anda sendiri, sehingga Anda memilih mesin di balik alur kerja editor yang sama."}, {"label": "MCP", "body": "Ia berbicara Model Context Protocol, sehingga server eksternal — yang paling relevan server Figma MCP — menjadi konteks kelas satu bagi agen."}]}, {"kind": "ul", "items": ["Vendor: Anysphere", "Kredensial: akun / langganan Cursor (Hobby / Pro / Business) atau kunci model Anda sendiri (BYOK)", "Bentuk: editor kode AI-first (fork VS Code) dengan agen dan pratinjau di dalam editor"]}]}, {"id": "why-design", "heading": "Mengapa Cursor bagus untuk desain", "blocks": [{"kind": "p", "text": "Keunggulan desain Cursor bukan satu fitur tunggal — melainkan kerapatan loop build-and-see. Tiga hal membuatnya terasa seperti alat desain alih-alih generator kode generik."}, {"kind": "steps", "items": [{"label": "Loop iterate-and-watch yang rapat", "body": "Anda memberi prompt, Cursor menyunting di banyak file, dan pratinjau di dalam editor merender hasilnya seketika — sehingga Anda menyesuaikan spacing, hierarki, dan gerak dalam hitungan detik alih-alih bolak-balik melalui terminal dan browser terpisah."}, {"label": "Penyuntingan visual langsung", "body": "Selain chat, Cursor memungkinkan Anda memilih elemen di pratinjau dan menyetel gaya, sehingga koreksi visual kecil terasa seperti suntingan desain alih-alih arkeologi kode."}, {"label": "Aturan proyek dan konteks MCP", "body": "Dengan `.cursor/rules` (atau `AGENTS.md`) dan server Figma MCP, agen bekerja terhadap tokens, komponen, dan spesifikasi desain nyata Anda alih-alih menebak."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Diagram yang menunjukkan design system, skill, dan gambar referensi mengonvergensi menjadi output desain yang baik", "caption": "Selera datang dari tiga masukan yang Anda berikan: design system, skill, dan gambar referensi nyata."}, {"kind": "p", "text": "Pelajarannya sama dengan yang diajarkan setiap agen: Cursor tidak punya selera secara default. Ia menghasilkan desain yang baik ketika Anda memberinya batasan — design system, skill estetik, dan referensi konkret. Open Design mengemas masukan-masukan itu secara persis, dan itulah mengapa keduanya cocok bersama (lebih lanjut di bawah)."}]}, {"id": "setup", "heading": "Menyiapkan Cursor untuk pekerjaan desain, dari nol", "blocks": [{"kind": "p", "text": "Berikut jalur lengkap dari mesin yang bersih hingga Cursor yang dapat membangun, mempratinjau, dan memverifikasi UI terhadap design system Anda."}, {"kind": "ol", "items": ["Install Cursor dari cursor.com dan masuk dengan akun Cursor Anda, atau konfigurasikan kunci model Anda sendiri (BYOK) di Settings.", "Buka proyek Anda dan pilih model di panel chat / Agent.", "Tambahkan aturan proyek: buat `.cursor/rules/*.mdc` untuk konvensi terstruktur yang bercakupan glob, atau `AGENTS.md` biasa untuk instruksi yang sederhana dan mudah dibaca.", "Hubungkan server Figma MCP (opsional) agar agen dapat membaca konteks desain yang hidup.", "Jalankan dev server Anda dan gunakan pratinjau di dalam editor untuk melihat dan memverifikasi UI saat Anda mengiterasi."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Alur penyiapan lima langkah: install, autentikasi, konfigurasi aturan, tambah skill, verifikasi", "caption": "Urutan penyiapan: install → autentikasi → konfigurasi aturan proyek → tambahkan skill → aktifkan verifikasi pratinjau."}, {"kind": "p", "text": "File aturan-proyek minimal membuat agen mendesain ke sebuah brand alih-alih jatuh ke tampilan generik. Letakkan di tempat yang dibaca Cursor pada setiap putaran:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Tuliskan aturan desain Anda", "body": "Letakkan tokens, primitif, dan konvensi Anda di `.cursor/rules` atau `AGENTS.md` dan arahkan Cursor ke sana, sehingga output sesuai dengan brand alih-alih jatuh ke tampilan generik."}, {"label": "Jaga prompt tetap kecil", "body": "Loop Cursor yang rapat memberi imbalan pada permintaan yang terfokus — iterasi satu komponen atau state pada satu waktu dan amati pratinjau di antara putaran."}]}]}, {"id": "preview-workflow", "heading": "Alur kerja preview-to-UI", "blocks": [{"kind": "p", "text": "Loop desain dengan daya ungkit tertinggi pada Cursor adalah mengubah referensi menjadi UI yang berfungsi dan responsif, lalu mengiterasinya di dalam editor hingga cocok — mengamati pratinjau langsung sepanjang waktu alih-alih menebak."}, {"kind": "ol", "items": ["Mulai dari referensi visual paling jelas yang Anda miliki — dan sertakan banyak state (desktop dan mobile, hover, kosong, loading), bukan hanya satu hero shot.", "Bersikaplah spesifik dalam prompt; prompt yang samar menghasilkan UI generik.", "Siapkan design system dan beri tahu Cursor di mana tokens dan primitif kanonis berada.", "Jaga pratinjau di dalam editor tetap terbuka dan dev server Anda tetap berjalan agar setiap suntingan dirender seketika pada breakpoint yang Anda pedulikan.", "Iterasi dengan membandingkan UI yang dirender kembali ke referensi — dan gunakan pemilihan elemen langsung di pratinjau untuk koreksi visual kecil."]}, {"kind": "p", "text": "Beri referensi dengan melampirkan gambar ke chat, lalu beri prompt dengan batasan konkret:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Commit iterasi yang baik dan revert yang buruk (beri tahu Cursor saat Anda revert) sehingga setiap putaran dibangun di atas dasar yang bersih — disiplin yang sama yang menjaga loop agen mana pun agar tidak menyimpang."}]}, {"id": "figma", "heading": "Cursor + Figma: desain ↔ kode lewat MCP", "blocks": [{"kind": "p", "text": "Cursor terhubung ke Figma melalui server Figma MCP resmi, yang memberi agen akses terstruktur ke file Figma yang hidup alih-alih screenshot datar. Itu menghilangkan tebak-tebakan dari handoff."}, {"kind": "steps", "items": [{"label": "Desain → Kode", "body": "Salin tautan sebuah frame di Figma, tempelkan ke Cursor, dan minta ia mengimplementasikan desain. Server MCP mengekspos konteks desain nyata — komponen, variabel, data layout, tokens — sehingga kode yang dihasilkan cocok dengan sumber alih-alih mendekatinya."}, {"label": "Tetap selaras", "body": "Dengan design tokens, gaya, dan komponen yang digunakan secara konsisten di Figma (dan Code Connect bila tersedia), output Cursor tetap terpetakan ke design system nyata Anda alih-alih menciptakan ulang primitif."}]}, {"kind": "p", "text": "Siapkan server Figma MCP remote sekali dan ia tersedia bagi Cursor sebagai konteks kelas satu. Karena MCP adalah standar terbuka, server yang sama dapat dipakai ulang di Cursor, Claude Code, Codex, dan VS Code — persis jenis kemampuan portabel dan multi-agen yang dibuat untuk diorkestrasikan oleh Open Design."}]}, {"id": "vs", "heading": "Cursor vs Codex vs Claude Code untuk desain", "blocks": [{"kind": "p", "text": "Tidak ada pemenang tunggal untuk pekerjaan desain — setiap agen punya kekuatan berbeda, dan tim berpengalaman menumpuknya. Ringkasan yang adil:"}, {"kind": "table", "columns": ["Agen", "Kekuatan desain", "Paling cocok untuk"], "rows": [["Cursor", "Loop build-and-see visual dengan pratinjau langsung di dalam editor dan penyuntingan elemen langsung", "Pekerjaan UI iterate-and-watch yang rapat di dalam IDE"], ["Codex", "Poles visual yang kuat dengan skill frontend; pemahaman gambar dan jalankan tersandbox", "Build asinkron yang didelegasikan dan aturan AGENTS.md yang portabel"], ["Claude Code", "Keputusan desain spesifik (hex, spacing, type) dan UX yang sadar codebase", "Penalaran frontend dan refaktor konteks besar"]]}, {"kind": "p", "text": "Putusan komunitas yang berulang adalah bahwa selera datang dari manusia: ketiganya jatuh ke estetika generik tanpa skill, referensi, dan batasan. Itulah masalah sebenarnya yang harus dipecahkan — dan bentuknya seperti alat desain, bukan seperti model."}]}, {"id": "pitfalls", "heading": "Jebakan, dan cara menghindari tampilan “AI slop”", "blocks": [{"kind": "p", "text": "Keluhan paling umum tentang desain hasil Cursor adalah tampilannya yang generik — gradien lembut, panel mengambang, sudut membulat berukuran berlebihan, bayangan dramatis, nuansa Inter-dan-ungu yang “berteriak ini buatan AI.” Masalah lain yang dilaporkan termasuk layout yang rusak di mobile dan instruksi yang bocor ke teks UI."}, {"kind": "steps", "items": [{"label": "Tambahkan sebuah skill desain", "body": "Skill estetik terkurasi memaksa Cursor berkomitmen pada arah nyata alih-alih tampilan default."}, {"label": "Gunakan pratinjau untuk verifikasi", "body": "Render dan periksa diri sendiri di berbagai breakpoint di pratinjau dalam editor sehingga layout tidak diam-diam rusak di mobile."}, {"label": "Sediakan tokens dan referensi", "body": "Design tokens nyata dan screenshot referensi adalah satu daya ungkit terbesar bagi kualitas output."}, {"label": "Tuliskan aturan di `.cursor/rules`", "body": "Letakkan aturan bergaya “tanpa hero card, maksimal dua typeface, hierarki brand-first” di tempat yang dibaca agen pada setiap putaran."}]}, {"kind": "p", "text": "Perhatikan bahwa setiap mitigasi adalah soal memberi agen konteks desain yang terkurasi. Memelihara konteks itu secara manual, per proyek, adalah kerja melelahkan yang dihapus Open Design."}]}, {"id": "open-design", "heading": "Mendesain dengan Cursor di dalam Open Design", "blocks": [{"kind": "p", "text": "Open Design adalah lapisan desain open-source yang terus diminta oleh alur kerja di atas. Ia memperlakukan Cursor sebagai adaptor first-party dan membungkusnya dengan pustaka skill dan design system terkurasi, pipeline render terstruktur, dan UI desktop lokal — sehingga konteks desain yang membuat Cursor bagus sudah ada sejak putaran pertama, bukan dirakit secara manual setiap kali."}, {"kind": "ol", "items": ["Install Open Design dan pilih Cursor sebagai agen Anda.", "Autentikasi dengan akun Cursor Anda atau kunci model Anda sendiri (BYOK) — kredensial tetap di mesin Anda dan tidak pernah diproksi melalui kami.", "Pilih design system dan skill, lalu hasilkan deck, prototipe, dan landing page dengan selera yang konsisten.", "Setiap artefak dan file DESIGN.md hidup di repo Anda sendiri, bukan di cloud yang dihosting."]}, {"kind": "p", "text": "Agen Cursor yang sama, kunci yang sama — ditambah alur kerja desain open-source yang nyata dan portabel di sekelilingnya. Ia local-first dan Apache-2.0, sehingga tidak ada bagian dari pekerjaan atau kredensial Anda yang meninggalkan mesin Anda."}]}], "faqTitle": "Pertanyaan yang sering diajukan", "faq": [{"name": "Apakah Cursor benar-benar bisa melakukan pekerjaan desain?", "text": "Ya — dengan skill desain, design system, dan gambar referensi nyata dalam konteks, Cursor menghasilkan UI berkualitas produksi dan responsif, dan pratinjau di dalam editornya memungkinkan Anda memverifikasi serta menyempurnakannya secara visual. Tanpa konteks itu, ia cenderung jatuh ke tampilan generik, dan itulah celah yang diisi Open Design."}, {"name": "Apakah ini produk Cursor resmi?", "text": "Bukan. Open Design adalah proyek open-source independen yang mengintegrasikan Cursor sebagai agen. Ia melengkapi Cursor dengan pustaka skill dan design system yang terbuka dan local-first."}, {"name": "Apakah saya butuh langganan Cursor untuk mendesain dengan Cursor?", "text": "Anda dapat menggunakan akun / langganan Cursor atau membawa kunci model Anda sendiri (BYOK). Open Design tidak pernah memproksi kredensial Anda dengan cara apa pun — kredensial digunakan langsung oleh agen Anda."}, {"name": "Cursor atau Claude Code untuk desain frontend?", "text": "Keduanya kuat. Claude Code dikenal karena keputusan desain yang spesifik dan sadar codebase; keunggulan Cursor adalah loop build-and-see-nya yang rapat dengan pratinjau langsung di dalam editor. Banyak tim memakai keduanya — Open Design memungkinkan Anda berganti agen tanpa mengubah alur kerja desain Anda."}, {"name": "Bagaimana cara menghubungkan Cursor ke Figma?", "text": "Tambahkan server Figma MCP resmi di Cursor, lalu tempelkan tautan frame Figma ke chat dan minta Cursor mengimplementasikannya. Server mengekspos komponen, variabel, dan data layout nyata sehingga kode yang dihasilkan cocok dengan desain sumber."}, {"name": "Bagaimana cara menghindari estetika “AI slop” yang generik?", "text": "Tambahkan skill desain, sediakan design tokens nyata dan screenshot referensi, tuliskan aturan brand di `.cursor/rules` atau `AGENTS.md`, dan verifikasi di berbagai breakpoint di pratinjau. Open Design menyediakan ini sebagai pustaka terkurasi sehingga Anda melewati penyiapan per proyek."}, {"name": "Apakah Open Design berafiliasi dengan Cursor atau Anysphere?", "text": "Tidak. Cursor adalah produk Anysphere; Open Design adalah proyek open-source independen yang mendukungnya sebagai adaptor first-party. Cursor dan Anysphere adalah merek dagang Anysphere, Inc."}, {"name": "Apakah file dan kredensial saya aman?", "text": "Ya — Open Design bersifat local-first. File, artefak, dan DESIGN.md Anda tetap di repo Anda sendiri, dan kredensial Cursor atau model Anda digunakan langsung oleh agen Anda, tidak pernah dirutekan melalui server Open Design."}], "ctaTitle": "Mendesain dengan Cursor, dengan cara terbuka.", "ctaBody": "Bawa akun Cursor atau kunci model Anda sendiri, simpan setiap file secara lokal, dan dapatkan pustaka desain terkurasi di sekeliling agen yang sudah Anda gunakan.", "ctaActions": [{"label": "Gunakan Cursor di dalam Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Beri bintang di GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Unduh aplikasi desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Lihat semua agen yang didukung"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode untuk desain — Open Design",
        description: "Bagaimana orang menggunakan OpenCode untuk desain UI dan web — file design.md, skill UI/UX, Figma MCP — dan bagaimana Open Design mengubah OpenCode menjadi agen desain open-source yang local-first.",
        breadcrumb: "OpenCode",
        label: "Agen · OpenCode",
        heading: "OpenCode untuk desain.",
        lead: "OpenCode adalah agen coding AI terminal yang open-source. Desainer memasangkan skill desain dan file DESIGN.md padanya untuk menghasilkan UI sungguhan. Open Design menjadikannya alur kerja open-source yang terstruktur — bawa kunci provider Anda, simpan semuanya secara lokal.",
        rich: {"heroCtaLead": "Open Design mengubah OpenCode menjadi agen desain open-source yang local-first — model apa pun yang Anda pilih dengan kunci provider Anda sendiri, file Anda, dengan pustaka skill dan design system terkurasi di sekelilingnya.", "heroCtaActions": [{"label": "Gunakan OpenCode di dalam Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Beri bintang di GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Unduh aplikasi desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode adalah agen coding AI yang open-source dan mengutamakan terminal, yang sengaja dibuat model-agnostic: Anda membawa kunci provider Anda sendiri dan menjalankan model apa pun yang Anda inginkan di balik alur kerja yang sama. Keterbukaan itu menjadikannya basis alami untuk pekerjaan desain — tetapi seperti setiap agen, ia hanya menghasilkan UI yang baik ketika Anda memberinya referensi, skill, dan loop verifikasi yang tepat. Ini adalah panduan praktis end-to-end untuk menggunakan OpenCode dalam pekerjaan UI, frontend, dan design system, serta untuk merangkainya ke alur kerja desain terstruktur dengan Open Design.", "Panduan ini membahas apa sebenarnya OpenCode itu, mengapa agen terbuka yang model-agnostic cocok untuk desain, cara menyiapkannya dari nol, loop screenshot-to-UI, bagaimana AGENTS.md dan MCP memperluasnya, perbandingannya dengan Codex, Claude Code, dan Cursor, jebakan yang membuat output AI terlihat generik, dan bagaimana Open Design menutup celah itu sebagai lapisan desain terbuka yang local-first — sebuah pasangan alami, karena kedua proyek bersifat open-source dan berjalan di mesin Anda sendiri."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "Loop umpan balik desain OpenCode: agen TUI terminal, browser yang merender UI, dan workspace, dengan panah umpan balik yang berputar kembali", "caption": "Loop inti: OpenCode membangun UI di terminal, merender dan memverifikasinya di browser sungguhan, lalu mengiterasinya terhadap referensi Anda — pada model apa pun yang Anda pilih."}, "tocLabel": "Di halaman ini", "toc": [{"id": "what-is-opencode", "label": "Apa sebenarnya OpenCode itu"}, {"id": "why-design", "label": "Mengapa agen terbuka apa-pun-modelnya cocok untuk desain"}, {"id": "setup", "label": "Menyiapkan OpenCode untuk desain (dari nol)"}, {"id": "screenshot-workflow", "label": "Alur kerja screenshot-to-UI"}, {"id": "extend", "label": "AGENTS.md, MCP, dan sesi yang dapat dibagikan"}, {"id": "vs", "label": "OpenCode vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "Jebakan dan tampilan “AI slop”"}, {"id": "open-design", "label": "Mendesain dengan OpenCode di Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-opencode", "heading": "Apa sebenarnya OpenCode itu", "blocks": [{"kind": "p", "text": "OpenCode adalah agen coding AI open-source yang dibangun untuk terminal, dipelihara oleh tim di balik SST (Anomaly Innovations). Ia membaca repositori Anda, menjalankan perintah, menyunting file, dan berbicara dengan model bahasa besar — tetapi tidak seperti agen yang terikat vendor, ia tidak menyertakan modelnya sendiri. Anda mengarahkannya ke provider dan model apa pun yang Anda inginkan dan membawa kunci Anda sendiri."}, {"kind": "p", "text": "Ia berjalan sebagai terminal UI (TUI), dengan aplikasi desktop dan ekstensi IDE di atas mesin yang sama. Di balik layar, ia menggunakan arsitektur client/server, sehingga agen yang melakukan pekerjaan terpisah dari permukaan tempat Anda mengendalikannya. Dua agen bawaan — build dan plan — berganti dengan tombol Tab."}, {"kind": "steps", "items": [{"label": "Model-agnostic", "body": "Model dan provider berasal dari models.dev, sebuah katalog terbuka. Anda mengonfigurasikannya di opencode.json dengan string provider/model-id dan dapat menonaktifkan provider yang tidak ingin dimuat — sehingga alur kerja desain yang sama berjalan di Anthropic, OpenAI, Google, OpenRouter, model lokal, dan lainnya."}, {"label": "File instruksi", "body": "OpenCode membaca file AGENTS.md di proyek Anda (standar lintas alat, juga kompatibel dengan CLAUDE.md) untuk aturan proyek — tempat alami untuk menuliskan konvensi desain Anda. Jalankan /init untuk menghasilkannya."}, {"label": "Dapat diperluas", "body": "Ia mendukung integrasi LSP, server MCP, tema, keybind, dan perintah kustom, ditambah tautan sesi yang dapat dibagikan untuk kolaborasi."}]}, {"kind": "ul", "items": ["Pemelihara: SST / Anomaly Innovations (proyek open-source)", "Kredensial: kunci API provider model Anda sendiri — BYOK, tanpa vendor lock-in", "Lisensi: MIT, open source"]}]}, {"id": "why-design", "heading": "Mengapa agen terbuka apa-pun-modelnya cocok untuk pekerjaan desain", "blocks": [{"kind": "p", "text": "OpenCode tidak punya satu “model desain” seperti agen vendor — dan itulah intinya. Karena ia model-agnostic dan terbuka, Anda dapat menjalankan alur kerja desain yang sama pada model mana pun yang saat ini terbaik di frontend, menukarnya nanti, atau beralih ke model lokal, semua tanpa mengubah penyiapan Anda."}, {"kind": "p", "text": "Tetapi pilihan model saja tidak membeli selera. Seperti setiap agen coding, OpenCode menghasilkan UI generik kecuali Anda memberinya batasan. Output desain yang baik datang dari tiga masukan yang Anda berikan."}, {"kind": "steps", "items": [{"label": "Sebuah design system", "body": "Tokens, primitif, dan konvensi nyata yang digunakan kembali oleh agen, sehingga output sesuai dengan brand alih-alih jatuh ke tampilan generik."}, {"label": "Sebuah skill estetik", "body": "Skill terkurasi yang menegakkan selera nyata — gerak yang terkendali, hierarki brand-first, paling banyak dua typeface dan satu accent color — dan membuat agen berkomitmen pada arah sebelum membangun."}, {"label": "Referensi konkret", "body": "Gambar referensi nyata dan banyak state (desktop dan mobile, hover, kosong, loading), bukan satu hero shot."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Diagram yang menunjukkan design system, skill, dan gambar referensi mengonvergensi menjadi output desain yang baik", "caption": "Selera datang dari tiga masukan yang Anda berikan: design system, skill, dan gambar referensi nyata — terlepas dari model mana yang Anda jalankan."}, {"kind": "p", "text": "Pelajarannya: OpenCode memberi Anda kebebasan model, tetapi selera tetap datang dari konteks desain yang terkurasi. Open Design mengemas masukan-masukan itu secara persis, dan itulah mengapa keduanya cocok bersama — keduanya open-source dan local-first (lebih lanjut di bawah)."}]}, {"id": "setup", "heading": "Menyiapkan OpenCode untuk pekerjaan desain, dari nol", "blocks": [{"kind": "p", "text": "Berikut jalur lengkap dari mesin yang bersih hingga OpenCode yang dapat membangun dan memverifikasi UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Alur penyiapan lima langkah: install, autentikasi dengan kunci provider Anda, konfigurasi AGENTS.md, tambah skill, verifikasi", "caption": "Urutan penyiapan: install → autentikasi (kunci provider Anda) → konfigurasi AGENTS.md → tambahkan skill → verifikasi di browser sungguhan."}, {"kind": "steps", "items": [{"label": "Tuliskan aturan desain Anda", "body": "Letakkan tokens, primitif, dan konvensi Anda di AGENTS.md (atau DESIGN.md yang dirujuk darinya) sehingga output sesuai dengan brand alih-alih jatuh ke tampilan generik. Opsi instructions di opencode.json dapat mengarah ke file aturan tambahan via glob."}, {"label": "Pilih model yang mumpuni", "body": "Karena OpenCode model-agnostic, pilih provider/model mana pun yang saat ini paling kuat di frontend untuk putaran desain — dan biarkan sisa alur kerja Anda tetap tidak berubah."}]}]}, {"id": "screenshot-workflow", "heading": "Alur kerja screenshot-to-UI", "blocks": [{"kind": "p", "text": "Loop desain dengan daya ungkit tertinggi pada agen mana pun adalah mengubah gambar referensi menjadi UI yang berfungsi dan responsif, lalu mengiterasinya hingga cocok. Bentuk lima langkah yang sama berlaku di OpenCode."}, {"kind": "ol", "items": ["Mulai dari referensi visual paling jelas yang Anda miliki — dan sertakan banyak state (desktop dan mobile, hover, kosong, loading), bukan hanya satu hero shot.", "Bersikaplah spesifik dalam prompt; prompt yang samar menghasilkan UI generik.", "Siapkan design system dan beri tahu OpenCode di mana tokens dan primitif kanonis berada (di AGENTS.md).", "Jalankan dev server dan minta agen merender di browser sungguhan, mengubah ukuran ke breakpoint untuk memeriksa hasilnya.", "Iterasi dengan meminta OpenCode membandingkan implementasinya kembali ke screenshot — bukan sekadar memastikan ia berhasil build."]}, {"kind": "p", "text": "Rujuk file dengan @ di TUI untuk pencarian fuzzy direktori kerja Anda, jalankan perintah shell secara inline dengan awalan !, dan kendalikan tindakan dengan perintah /. Lalu beri prompt dengan batasan konkret:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Jaga prompt tetap kecil dan terfokus, commit iterasi yang baik dan revert yang buruk (beri tahu OpenCode saat Anda revert), sehingga setiap putaran dibangun di atas dasar yang bersih."}]}, {"id": "extend", "heading": "AGENTS.md, MCP, dan sesi yang dapat dibagikan", "blocks": [{"kind": "p", "text": "Tiga titik ekstensi membuat OpenCode praktis untuk pekerjaan desain yang berkelanjutan, dan ketiganya terpetakan rapi ke alur kerja desain terbuka."}, {"kind": "steps", "items": [{"label": "Aturan AGENTS.md", "body": "Aturan proyek tinggal di sebuah AGENTS.md di root repo (atau aturan global di ~/.config/opencode/AGENTS.md). Ia adalah rumah yang tahan lama bagi konvensi desain Anda, dibaca pada setiap putaran, dan kompatibel dengan file CLAUDE.md yang dipakai agen lain."}, {"label": "Server MCP", "body": "OpenCode mendukung server MCP lokal (command) maupun remote (URL), dikonfigurasikan di bawah kunci mcp — cara portabel untuk membawa konteks desain dan alat eksternal yang bekerja lintas agen, bukan hanya OpenCode."}, {"label": "Sesi yang dapat dibagikan", "body": "Perintah /share membuat tautan publik ke sebuah percakapan untuk kolaborasi atau tinjauan, dan /unshare mencabutnya — berguna untuk mendapatkan umpan balik atas sebuah putaran desain."}]}, {"kind": "p", "text": "Ini adalah kemampuan portabel dan multi-agen — persis jenis hal yang dibuat untuk diorkestrasikan oleh Open Design, alih-alih dibuat ulang per proyek."}]}, {"id": "vs", "heading": "OpenCode vs Codex vs Claude Code vs Cursor untuk desain", "blocks": [{"kind": "p", "text": "Tidak ada pemenang tunggal untuk pekerjaan desain — setiap agen punya kekuatan berbeda, dan tim berpengalaman menumpuknya. Ringkasan yang adil:"}, {"kind": "table", "columns": ["Agen", "Kekuatan desain", "Paling cocok untuk"], "rows": [["OpenCode", "Open-source dan model-agnostic; jalankan provider apa pun di balik satu alur kerja terminal", "Kebebasan BYOK, pergantian model, penyiapan yang sepenuhnya terbuka dan local-first"], ["Codex", "Poles visual yang kuat dengan skill frontend; pemahaman gambar", "Asinkron yang didelegasikan, build tersandbox, aturan AGENTS.md yang portabel"], ["Claude Code", "Keputusan desain spesifik (hex, spacing, type) dan UX yang sadar codebase", "Penalaran frontend dan refaktor konteks besar"], ["Cursor", "Loop build-and-see visual dengan pratinjau langsung dan suntingan inline", "Pekerjaan UI iterate-and-watch yang rapat di dalam IDE"]]}, {"kind": "p", "text": "Putusan komunitas yang berulang adalah bahwa selera datang dari manusia: semuanya jatuh ke estetika generik tanpa skill, referensi, dan batasan. Itulah masalah sebenarnya yang harus dipecahkan — dan bentuknya seperti alat desain, bukan seperti model, yang justru menjadi alasan mengapa agen terbuka seperti OpenCode berpasangan begitu baik dengan lapisan desain terbuka."}]}, {"id": "pitfalls", "heading": "Jebakan, dan cara menghindari tampilan “AI slop”", "blocks": [{"kind": "p", "text": "Keluhan paling umum tentang desain hasil AI adalah tampilannya yang generik — gradien lembut, panel mengambang, sudut membulat berukuran berlebihan, bayangan dramatis, nuansa Inter-dan-ungu yang “berteriak ini buatan AI.” Masalah lain yang dilaporkan termasuk layout mobile yang rusak dan instruksi yang bocor ke teks UI. Tak satu pun dari ini unik bagi OpenCode; semuanya terjadi ketika agen mana pun berjalan tanpa konteks desain yang terkurasi."}, {"kind": "steps", "items": [{"label": "Tambahkan sebuah skill estetik", "body": "Skill desain terkurasi memaksa agen berkomitmen pada arah nyata alih-alih tampilan default."}, {"label": "Verifikasi di browser sungguhan", "body": "Render dan periksa diri sendiri di berbagai breakpoint sehingga layout tidak diam-diam rusak di mobile."}, {"label": "Sediakan tokens dan referensi", "body": "Design tokens nyata dan screenshot referensi adalah satu daya ungkit terbesar bagi kualitas output."}, {"label": "Tuliskan aturan di AGENTS.md", "body": "Letakkan aturan bergaya “tanpa hero card, maksimal dua typeface, hierarki brand-first” di tempat yang dibaca agen pada setiap putaran."}]}, {"kind": "p", "text": "Perhatikan bahwa setiap mitigasi adalah soal memberi agen konteks desain yang terkurasi — terlepas dari model mana yang Anda jalankan. Memelihara konteks itu secara manual, per proyek, adalah kerja melelahkan yang dihapus Open Design."}]}, {"id": "open-design", "heading": "Mendesain dengan OpenCode di dalam Open Design", "blocks": [{"kind": "p", "text": "Open Design adalah lapisan desain open-source yang terus diminta oleh alur kerja di atas. Ia memperlakukan OpenCode sebagai adaptor first-party dan membungkusnya dengan pustaka skill dan design system terkurasi, pipeline render terstruktur, dan UI desktop lokal — sehingga konteks desain yang membuat agen mana pun bagus sudah ada sejak putaran pertama, bukan dirakit secara manual setiap kali. Kedua proyek bersifat open-source dan local-first, yang menjadikan pasangan ini cocok secara alami."}, {"kind": "ol", "items": ["Install Open Design dan pilih OpenCode sebagai agen Anda.", "Autentikasi dengan kunci API provider model Anda sendiri (BYOK) — kredensial tetap di mesin Anda dan tidak pernah diproksi melalui kami.", "Pilih provider dan model apa pun, plus design system dan skill, lalu hasilkan deck, prototipe, dan landing page dengan selera yang konsisten.", "Setiap artefak dan file DESIGN.md hidup di repo Anda sendiri, bukan di cloud yang dihosting."]}, {"kind": "p", "text": "Agen OpenCode yang sama, kebebasan model yang sama — ditambah alur kerja desain open-source yang nyata dan portabel di sekelilingnya. Ia local-first dan Apache-2.0, sehingga tidak ada bagian dari pekerjaan atau kredensial Anda yang meninggalkan mesin Anda."}]}], "faqTitle": "Pertanyaan yang sering diajukan", "faq": [{"name": "Apakah OpenCode benar-benar bisa melakukan pekerjaan desain?", "text": "Ya — dengan skill estetik, design system, dan gambar referensi nyata dalam konteks, OpenCode menghasilkan UI berkualitas produksi dan responsif serta dapat memverifikasinya di browser. Karena ia model-agnostic, Anda menjalankan model mana pun yang saat ini terbaik di frontend. Tanpa konteks terkurasi itu, ia cenderung jatuh ke tampilan generik, dan itulah celah yang diisi Open Design."}, {"name": "Model mana yang sebaiknya saya gunakan dengan OpenCode untuk desain?", "text": "Mana pun yang Anda suka — OpenCode bersifat provider-agnostic via models.dev, sehingga Anda dapat menjalankan Anthropic, OpenAI, Google, OpenRouter, atau model lokal di balik alur kerja yang sama dan beralih kapan saja. Kualitas output desain jauh lebih bergantung pada skill, design system, dan referensi Anda daripada pada modelnya saja."}, {"name": "Apakah Open Design dibuat oleh tim OpenCode (SST)?", "text": "Bukan. Open Design adalah proyek open-source independen yang mengintegrasikan OpenCode sebagai agen. Ia melengkapi OpenCode dengan pustaka skill dan design system yang terbuka dan local-first."}, {"name": "Apakah saya butuh langganan khusus untuk mendesain dengan OpenCode?", "text": "Tidak — OpenCode bersifat BYOK. Anda membawa kunci API provider model Anda sendiri, dan Open Design tidak pernah memproksi kredensial Anda. Tidak ada vendor lock-in."}, {"name": "OpenCode atau Codex atau Claude Code untuk desain frontend?", "text": "Semuanya kuat, dan banyak tim menumpuknya. Keunggulan OpenCode adalah sepenuhnya open-source dan model-agnostic; Codex unggul dalam build yang didelegasikan dan tersandbox; Claude Code dikenal karena keputusan desain yang spesifik dan sadar codebase. Open Design memungkinkan Anda berganti agen tanpa mengubah alur kerja desain Anda."}, {"name": "Bagaimana cara memperluas OpenCode untuk konteks desain?", "text": "Tuliskan aturan di AGENTS.md, tambahkan server MCP di bawah kunci mcp untuk alat portabel dan konteks desain, serta gunakan sesi yang dapat dibagikan untuk tinjauan. Open Design menyediakan pustaka skill dan design system terkurasi sehingga Anda melewati penyiapan per proyek."}, {"name": "Apakah Open Design berafiliasi dengan OpenCode atau SST?", "text": "Tidak. OpenCode adalah proyek open-source yang dipelihara oleh SST (Anomaly Innovations); Open Design adalah proyek open-source independen yang mendukungnya sebagai adaptor first-party."}, {"name": "Apakah file dan kredensial saya aman?", "text": "Ya — Open Design bersifat local-first. File, artefak, dan DESIGN.md Anda tetap di repo Anda sendiri, dan kredensial provider model Anda digunakan langsung oleh agen Anda, tidak pernah dirutekan melalui server Open Design."}], "ctaTitle": "Mendesain dengan OpenCode, dengan cara terbuka.", "ctaBody": "Bawa kunci provider model Anda sendiri, simpan setiap file secara lokal, dan dapatkan pustaka desain terkurasi di sekeliling agen terbuka yang sudah Anda gunakan.", "ctaActions": [{"label": "Gunakan OpenCode di dalam Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Beri bintang di GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Unduh aplikasi desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Lihat semua agen yang didukung"},
      },
    },
  };
}
